type nonrec resource_spec = {
  training_plan_arn : studio_resource_spec_training_plan_arn option;
      [@ocaml.doc
        "The ARN of the SageMaker AI Training Plan to use for this app. When you specify a \
         training plan, the app launches on reserved GPU capacity. This field is supported for \
         JupyterLab and CodeEditor app types.\n\n\
        \ For more information about how to reserve GPU capacity with SageMaker AI Training Plans, \
         see \
         {{:https://docs.aws.amazon.com/sagemaker/latest/dg/training-plan-utilization-for-studio-apps.html}Using \
         training plans in Studio applications}.\n\
        \ "]
  lifecycle_config_arn : studio_lifecycle_config_arn option;
      [@ocaml.doc
        " The Amazon Resource Name (ARN) of the Lifecycle Configuration attached to the Resource.\n"]
  instance_type : app_instance_type option;
      [@ocaml.doc
        "The instance type that the image version runs on.\n\n\
        \   {b JupyterServer apps} only support the [system] value.\n\
        \  \n\
        \   For {b KernelGateway apps}, the [system] value is translated to [ml.t3.medium]. \
         KernelGateway apps also support all other values for available instance types.\n\
        \   \n\
        \    "]
  sage_maker_image_version_alias : image_version_alias option;
      [@ocaml.doc
        "The SageMakerImageVersionAlias of the image to launch with. This value is in SemVer 2.0.0 \
         versioning format.\n"]
  sage_maker_image_version_arn : image_version_arn option;
      [@ocaml.doc
        "The ARN of the image version created on the instance. To clear the value set for \
         [SageMakerImageVersionArn], pass [None] as the value.\n"]
  sage_maker_image_arn : image_arn option;
      [@ocaml.doc "The ARN of the SageMaker AI image that the image version belongs to.\n"]
}
[@@ocaml.doc
  "Specifies the ARN's of a SageMaker AI image and SageMaker AI image version, and the instance \
   type that the version runs on.\n\n\
  \  When both [SageMakerImageVersionArn] and [SageMakerImageArn] are passed, \
   [SageMakerImageVersionArn] is used. Any updates to [SageMakerImageArn] will not take effect if \
   [SageMakerImageVersionArn] already exists in the [ResourceSpec] because \
   [SageMakerImageVersionArn] always takes precedence. To clear the value set for \
   [SageMakerImageVersionArn], pass [None] as the value.\n\
  \  \n\
  \   "]

