type nonrec update_workteam_request = {
  worker_access_configuration : worker_access_configuration option;
      [@ocaml.doc
        "Use this optional parameter to constrain access to an Amazon S3 resource based on the IP \
         address using supported IAM global condition keys. The Amazon S3 resource is accessed in \
         the worker portal using a Amazon S3 presigned URL.\n"]
  notification_configuration : notification_configuration option;
      [@ocaml.doc "Configures SNS topic notifications for available or expiring work items\n"]
  description : string200 option; [@ocaml.doc "An updated description for the work team.\n"]
  member_definitions : member_definitions option;
      [@ocaml.doc
        "A list of [MemberDefinition] objects that contains objects that identify the workers that \
         make up the work team. \n\n\
        \ Workforces can be created using Amazon Cognito or your own OIDC Identity Provider (IdP). \
         For private workforces created using Amazon Cognito use [CognitoMemberDefinition]. For \
         workforces created using your own OIDC identity provider (IdP) use \
         [OidcMemberDefinition]. You should not provide input for both of these parameters in a \
         single request.\n\
        \ \n\
        \  For workforces created using Amazon Cognito, private work teams correspond to Amazon \
         Cognito {i user groups} within the user pool used to create a workforce. All of the \
         [CognitoMemberDefinition] objects that make up the member definition must have the same \
         [ClientId] and [UserPool] values. To add a Amazon Cognito user group to an existing \
         worker pool, see {{:}Adding groups to a User Pool}. For more information about user \
         pools, see \
         {{:https://docs.aws.amazon.com/cognito/latest/developerguide/cognito-user-identity-pools.html}Amazon \
         Cognito User Pools}.\n\
        \  \n\
        \   For workforces created using your own OIDC IdP, specify the user groups that you want \
         to include in your private work team in [OidcMemberDefinition] by listing those groups in \
         [Groups]. Be aware that user groups that are already in the work team must also be listed \
         in [Groups] when you make this request to remain on the work team. If you do not include \
         these user groups, they will no longer be associated with the work team you update. \n\
        \   "]
