        "Indicates the minimum IMDS version that the notebook instance supports. When passed as \
         part of [CreateNotebookInstance], if no value is selected, then it defaults to IMDSv1. \
         This means that both IMDSv1 and IMDSv2 are supported. If passed as part of \
         [UpdateNotebookInstance], there is no default.\n"]
}
[@@ocaml.doc "Information on the IMDS configuration of the notebook instance\n"]

type nonrec update_notebook_instance_input = {
  instance_metadata_service_configuration : instance_metadata_service_configuration option;
      [@ocaml.doc "Information on the IMDS configuration of the notebook instance\n"]
  root_access : root_access option;
      [@ocaml.doc
        "Whether root access is enabled or disabled for users of the notebook instance. The \
         default value is [Enabled].\n\n\
        \  If you set this to [Disabled], users don't have root access on the notebook instance, \
         but lifecycle configuration scripts still run with root permissions.\n\
        \  \n\
        \   "]
  disassociate_additional_code_repositories : disassociate_additional_code_repositories option;
      [@ocaml.doc
        "A list of names or URLs of the default Git repositories to remove from this notebook \
         instance. This operation is idempotent. If you specify a Git repository that is not \
         associated with the notebook instance when you call this method, it does not throw an \
         error.\n"]
  disassociate_default_code_repository : disassociate_default_code_repository option;
      [@ocaml.doc
        "The name or URL of the default Git repository to remove from this notebook instance. This \
         operation is idempotent. If you specify a Git repository that is not associated with the \
         notebook instance when you call this method, it does not throw an error.\n"]
  disassociate_accelerator_types : disassociate_notebook_instance_accelerator_types option;
      [@ocaml.doc
        "This parameter is no longer supported. Elastic Inference (EI) is no longer available.\n\n\
        \ This parameter was used to specify a list of the EI instance types to remove from this \
         notebook instance.\n\
        \ "]
  accelerator_types : notebook_instance_accelerator_types option;
      [@ocaml.doc
        "This parameter is no longer supported. Elastic Inference (EI) is no longer available.\n\n\
        \ This parameter was used to specify a list of the EI instance types to associate with \
         this notebook instance.\n\
        \ "]
  additional_code_repositories : additional_code_repository_names_or_urls option;
      [@ocaml.doc
        "An array of up to three Git repositories to associate with the notebook instance. These \
         can be either the names of Git repositories stored as resources in your account, or the \
         URL of Git repositories in \
         {{:https://docs.aws.amazon.com/codecommit/latest/userguide/welcome.html}Amazon Web \
         Services CodeCommit} or in any other Git repository. These repositories are cloned at the \
         same level as the default repository of your notebook instance. For more information, see \
         {{:https://docs.aws.amazon.com/sagemaker/latest/dg/nbi-git-repo.html}Associating Git \
         Repositories with SageMaker AI Notebook Instances}.\n"]
  default_code_repository : code_repository_name_or_url option;
      [@ocaml.doc
        "The Git repository to associate with the notebook instance as its default code \
         repository. This can be either the name of a Git repository stored as a resource in your \
         account, or the URL of a Git repository in \
         {{:https://docs.aws.amazon.com/codecommit/latest/userguide/welcome.html}Amazon Web \
         Services CodeCommit} or in any other Git repository. When you open a notebook instance, \
         it opens in the directory that contains this repository. For more information, see \
         {{:https://docs.aws.amazon.com/sagemaker/latest/dg/nbi-git-repo.html}Associating Git \
         Repositories with SageMaker AI Notebook Instances}.\n"]
  volume_size_in_g_b : notebook_instance_volume_size_in_g_b option;
      [@ocaml.doc
        "The size, in GB, of the ML storage volume to attach to the notebook instance. The default \
         value is 5 GB. ML storage volumes are encrypted, so SageMaker AI can't determine the \
         amount of available free space on the volume. Because of this, you can increase the \
         volume size when you update a notebook instance, but you can't decrease the volume size. \
         If you want to decrease the size of the ML storage volume in use, create a new notebook \
         instance with the desired size.\n"]
  disassociate_lifecycle_config : disassociate_notebook_instance_lifecycle_config option;
      [@ocaml.doc
        "Set to [true] to remove the notebook instance lifecycle configuration currently \
         associated with the notebook instance. This operation is idempotent. If you specify a \
         lifecycle configuration that is not associated with the notebook instance when you call \
         this method, it does not throw an error.\n"]
  lifecycle_config_name : notebook_instance_lifecycle_config_name option;
      [@ocaml.doc
        "The name of a lifecycle configuration to associate with the notebook instance. For \
         information about lifestyle configurations, see \
         {{:https://docs.aws.amazon.com/sagemaker/latest/dg/notebook-lifecycle-config.html}Step \
         2.1: (Optional) Customize a Notebook Instance}.\n"]
  role_arn : role_arn option;
      [@ocaml.doc
        "The Amazon Resource Name (ARN) of the IAM role that SageMaker AI can assume to access the \
         notebook instance. For more information, see \
         {{:https://docs.aws.amazon.com/sagemaker/latest/dg/sagemaker-roles.html}SageMaker AI \
         Roles}. \n\n\
        \  To be able to pass this role to SageMaker AI, the caller of this API must have the \
         [iam:PassRole] permission.\n\
        \  \n\
        \   "]
  platform_identifier : platform_identifier option;
      [@ocaml.doc "The platform identifier of the notebook instance runtime environment.\n"]
  ip_address_type : ip_address_type option;
      [@ocaml.doc
        "The IP address type for the notebook instance. Specify [ipv4] for IPv4-only connectivity \
         or [dualstack] for both IPv4 and IPv6 connectivity. The notebook instance must be stopped \
         before updating this setting. When you specify [dualstack], the subnet must support IPv6 \
         addressing.\n"]
  instance_type : instance_type option; [@ocaml.doc "The Amazon ML compute instance type.\n"]
  notebook_instance_name : notebook_instance_name;
      [@ocaml.doc "The name of the notebook instance to update.\n"]
}
[@@ocaml.doc ""]

