type nonrec monitoring_schedule_name = string [@@ocaml.doc ""]

type nonrec schedule_expression = string [@@ocaml.doc ""]

type nonrec schedule_config = {
  data_analysis_end_time : string_ option;
      [@ocaml.doc
        "Sets the end time for a monitoring job window. Express this time as an offset to the \
         times that you schedule your monitoring jobs to run. You schedule monitoring jobs with \
         the [ScheduleExpression] parameter. Specify this offset in ISO 8601 duration format. For \
         example, if you want to end the window one hour before the start of each monitoring job, \
         you would specify: [\"-PT1H\"].\n\n\
        \ The end time that you specify must not follow the start time that you specify by more \
         than 24 hours. You specify the start time with the [DataAnalysisStartTime] parameter.\n\
        \ \n\
        \  If you set [ScheduleExpression] to [NOW], this parameter is required.\n\
        \  "]
  data_analysis_start_time : string_ option;
      [@ocaml.doc
        "Sets the start time for a monitoring job window. Express this time as an offset to the \
         times that you schedule your monitoring jobs to run. You schedule monitoring jobs with \
         the [ScheduleExpression] parameter. Specify this offset in ISO 8601 duration format. For \
         example, if you want to monitor the five hours of data in your dataset that precede the \
         start of each monitoring job, you would specify: [\"-PT5H\"].\n\n\
        \ The start time that you specify must not precede the end time that you specify by more \
         than 24 hours. You specify the end time with the [DataAnalysisEndTime] parameter.\n\
        \ \n\
        \  If you set [ScheduleExpression] to [NOW], this parameter is required.\n\
        \  "]
  schedule_expression : schedule_expression;
      [@ocaml.doc
        "A cron expression that describes details about the monitoring schedule.\n\n\
        \ The supported cron expressions are:\n\
        \ \n\
        \  {ul\n\
        \        {-  If you want to set the job to start every hour, use the following:\n\
        \            \n\
        \              [Hourly: cron(0 * ? * * *)] \n\
        \             \n\
        \              }\n\
        \        {-  If you want to start the job daily:\n\
        \            \n\
        \              [cron(0 \\[00-23\\] ? * * *)] \n\
        \             \n\
        \              }\n\
        \        {-  If you want to run the job one time, immediately, use the following keyword:\n\
        \            \n\
        \              [NOW] \n\
        \             \n\
        \              }\n\
        \        }\n\
        \   For example, the following are valid cron expressions:\n\
        \   \n\
        \    {ul\n\
        \          {-  Daily at noon UTC: [cron(0 12 ? * * *)] \n\
        \              \n\
        \               }\n\
        \          {-  Daily at midnight UTC: [cron(0 0 ? * * *)] \n\
        \              \n\
        \               }\n\
        \          }\n\
        \   To support running every 6, 12 hours, the following are also supported:\n\
        \   \n\
        \     [cron(0 \\[00-23\\]/\\[01-24\\] ? * * *)] \n\
        \    \n\
        \     For example, the following are valid cron expressions:\n\
        \     \n\
        \      {ul\n\
        \            {-  Every 12 hours, starting at 5pm UTC: [cron(0 17/12 ? * * *)] \n\
        \                \n\
        \                 }\n\
        \            {-  Every two hours starting at midnight: [cron(0 0/2 ? * * *)] \n\
        \                \n\
        \                 }\n\
        \            }\n\
        \    {ul\n\
        \          {-  Even though the cron expression is set to start at 5PM UTC, note that there \
         could be a delay of 0-20 minutes from the actual requested time to run the execution. \n\
        \              \n\
        \               }\n\
        \          {-  We recommend that if you would like a daily schedule, you do not provide \
         this parameter. Amazon SageMaker AI will pick a time for running every day.\n\
        \              \n\
        \               }\n\
        \          }\n\
        \    You can also specify the keyword [NOW] to run the monitoring job immediately, one \
         time, without recurring.\n\
        \    "]
}
[@@ocaml.doc "Configuration details about the monitoring schedule.\n"]

