      [@ocaml.doc
        "The additional data source that is used during inference in the Docker container for your \
         model package.\n"]
  additional_model_data_sources : additional_model_data_sources option;
      [@ocaml.doc
        "Data sources that are available to your model in addition to the one that you specify for \
         [ModelDataSource] when you use the [CreateModelPackage] action.\n"]
  nearest_model_name : string_ option;
      [@ocaml.doc
        "The name of a pre-trained machine learning benchmarked by Amazon SageMaker Inference \
         Recommender model that matches your model. You can find a list of benchmarked models by \
         calling [ListModelMetadata].\n"]
  framework_version : model_package_framework_version option;
      [@ocaml.doc "The framework version of the Model Package Container Image.\n"]
  framework : string_ option;
      [@ocaml.doc "The machine learning framework of the model package container image.\n"]
  model_input : model_input option; [@ocaml.doc "A structure with Model Input details.\n"]
  environment : environment_map option;
      [@ocaml.doc
        "The environment variables to set in the Docker container. Each key and value in the \
         [Environment] string to string map can have length of up to 1024. We support up to 16 \
         entries in the map.\n"]
  product_id : product_id option;
      [@ocaml.doc "The Amazon Web Services Marketplace product ID of the model package.\n"]
  model_data_source : model_data_source option;
      [@ocaml.doc "Specifies the location of ML model data to deploy during endpoint creation.\n"]
  model_data_url : url option;
      [@ocaml.doc
        "The Amazon S3 path where the model artifacts, which result from model training, are \
         stored. This path must point to a single [gzip] compressed tar archive ([.tar.gz] \
         suffix).\n\n\
        \  The model artifacts must be in an S3 bucket that is in the same region as the model \
         package.\n\
        \  \n\
        \   "]
  image_digest : image_digest option;
      [@ocaml.doc
        "An MD5 hash of the training algorithm that identifies the Docker image used for training.\n"]
  image : container_image option;
      [@ocaml.doc
        "The Amazon Elastic Container Registry (Amazon ECR) path where inference code is stored.\n\n\
        \ If you are using your own custom algorithm instead of an algorithm provided by \
         SageMaker, the inference code must meet SageMaker requirements. SageMaker supports both \
         [registry/repository\\[:tag\\]] and [registry/repository\\[@digest\\]] image path \
         formats. For more information, see \
         {{:https://docs.aws.amazon.com/sagemaker/latest/dg/your-algorithms.html}Using Your Own \
         Algorithms with Amazon SageMaker}.\n\
        \ "]
  container_hostname : container_hostname option;
      [@ocaml.doc "The DNS host name for the Docker container.\n"]
}
[@@ocaml.doc "Describes the Docker container for the model package.\n"]

