      [@ocaml.doc
        "The batch size for a rollback to the old endpoint fleet. If this field is absent, the \
         value is set to the default, which is 100% of the total capacity. When the default is \
         used, SageMaker AI provisions the entire capacity of the old fleet at once during \
         rollback.\n"]
  maximum_execution_timeout_in_seconds : maximum_execution_timeout_in_seconds option;
      [@ocaml.doc
        "The time limit for the total deployment. Exceeding this limit causes a timeout.\n"]
  wait_interval_in_seconds : wait_interval_in_seconds;
      [@ocaml.doc
        "The length of the baking period, during which SageMaker AI monitors alarms for each batch \
         on the new fleet.\n"]
  maximum_batch_size : inference_component_capacity_size;
      [@ocaml.doc
        "The batch size for each rolling step in the deployment process. For each step, SageMaker \
         AI provisions capacity on the new endpoint fleet, routes traffic to that fleet, and \
         terminates capacity on the old endpoint fleet. The value must be between 5% to 50% of the \
         copy count of the inference component.\n"]
}
