type nonrec traffic_routing_config = {
  linear_step_size : capacity_size option;
      [@ocaml.doc
        "Batch size for each step to turn on traffic on the new endpoint fleet. [Value] must be \
         10-50% of the variant's total instance count.\n"]
  canary_size : capacity_size option;
      [@ocaml.doc
        "Batch size for the first step to turn on traffic on the new endpoint fleet. [Value] must \
         be less than or equal to 50% of the variant's total instance count.\n"]
  wait_interval_in_seconds : wait_interval_in_seconds;
      [@ocaml.doc
        "The waiting time (in seconds) between incremental steps to turn on traffic on the new \
         endpoint fleet.\n"]
  type_ : traffic_routing_config_type;
      [@ocaml.doc
        "Traffic routing strategy type.\n\n\
        \ {ul\n\
        \       {-   [ALL_AT_ONCE]: Endpoint traffic shifts to the new fleet in a single step. \n\
        \           \n\
        \            }\n\
        \       {-   [CANARY]: Endpoint traffic shifts to the new fleet in two steps. The first \
         step is the canary, which is a small portion of the traffic. The second step is the \
         remainder of the traffic. \n\
        \           \n\
        \            }\n\
        \       {-   [LINEAR]: Endpoint traffic shifts to the new fleet in n steps of a \
         configurable size. \n\
        \           \n\
        \            }\n\
        \       }\n\
        \  "]
}
