type nonrec edge_output_config = {
  preset_deployment_config : string_ option;
      [@ocaml.doc
        "The configuration used to create deployment artifacts. Specify configuration options with \
         a JSON string. The available configuration options for each type are:\n\n\
        \ {ul\n\
        \       {-   [ComponentName] (optional) - Name of the GreenGrass V2 component. If not \
         specified, the default name generated consists of \"SagemakerEdgeManager\" and the name \
         of your SageMaker Edge Manager packaging job.\n\
        \           \n\
        \            }\n\
        \       {-   [ComponentDescription] (optional) - Description of the component.\n\
        \           \n\
        \            }\n\
        \       {-   [ComponentVersion] (optional) - The version of the component.\n\
        \           \n\
        \             Amazon Web Services IoT Greengrass uses semantic versions for components. \
         Semantic versions follow a{i  major.minor.patch} number system. For example, version \
         1.0.0 represents the first major release for a component. For more information, see the \
         {{:https://semver.org/}semantic version specification}.\n\
        \             \n\
        \               }\n\
        \       {-   [PlatformOS] (optional) - The name of the operating system for the platform. \
         Supported platforms include Windows and Linux.\n\
        \           \n\
        \            }\n\
        \       {-   [PlatformArchitecture] (optional) - The processor architecture for the \
         platform. \n\
        \           \n\
        \            Supported architectures Windows include: Windows32_x86, Windows64_x64.\n\
        \            \n\
        \             Supported architectures for Linux include: Linux x86_64, Linux ARMV8.\n\
        \             \n\
        \              }\n\
        \       }\n\
        \  "]
  preset_deployment_type : edge_preset_deployment_type option;
      [@ocaml.doc
        "The deployment type SageMaker Edge Manager will create. Currently only supports Amazon \
         Web Services IoT Greengrass Version 2 components.\n"]
  kms_key_id : kms_key_id option;
      [@ocaml.doc
        "The Amazon Web Services Key Management Service (Amazon Web Services KMS) key that Amazon \
         SageMaker uses to encrypt data on the storage volume after compilation job. If you don't \
         provide a KMS key ID, Amazon SageMaker uses the default KMS key for Amazon S3 for your \
         role's account.\n"]
  s3_output_location : s3_uri; [@ocaml.doc "The Amazon Simple Storage (S3) bucker URI.\n"]
}
[@@ocaml.doc "The output configuration.\n"]

