type nonrec accelerator_partition_config = {
  count : integer;
      [@ocaml.doc
        "The number of accelerator partitions to allocate with the specified partition type. If \
         you don't specify a value for vCPU and MemoryInGiB, SageMaker AI automatically allocates \
         ratio-based values for those parameters based on the accelerator partition count you \
         provide.\n"]
  type_ : mig_profile_type;
      [@ocaml.doc
        "The Multi-Instance GPU (MIG) profile type that defines the partition configuration. The \
         profile specifies the compute and memory allocation for each partition instance. The \
         available profile types depend on the instance type specified in the compute quota \
         configuration.\n"]
}
[@@ocaml.doc "Configuration for allocating accelerator partitions.\n"]

type nonrec compute_quota_resource_config = {
  accelerator_partition : accelerator_partition_config option;
      [@ocaml.doc "The accelerator partition configuration for fractional GPU allocation.\n"]
  memory_in_gi_b : memory_in_gi_b_amount option;
      [@ocaml.doc
        "The amount of memory in GiB to allocate. If you specify a value only for this parameter, \
         SageMaker AI automatically allocates a ratio-based value for vCPU based on this memory \
         that you provide. For example, if you allocate 200 out of 400 total memory in GiB, \
         SageMaker AI uses the ratio of 0.5 and allocates values to vCPU. Accelerators are set to \
         0.\n"]
  v_cpu : v_cpu_amount option;
      [@ocaml.doc
        "The number of vCPU to allocate. If you specify a value only for vCPU, SageMaker AI \
         automatically allocates ratio-based values for MemoryInGiB based on this vCPU parameter. \
         For example, if you allocate 20 out of 40 total vCPU, SageMaker AI uses the ratio of 0.5 \
         and allocates values to MemoryInGiB. Accelerators are set to 0.\n"]
  accelerators : accelerators_amount option;
      [@ocaml.doc
        "The number of accelerators to allocate. If you don't specify a value for vCPU and \
         MemoryInGiB, SageMaker AI automatically allocates ratio-based values for those parameters \
         based on the number of accelerators you provide. For example, if you allocate 16 out of \
         32 total accelerators, SageMaker AI uses the ratio of 0.5 and allocates values to vCPU \
         and MemoryInGiB.\n"]
  count : instance_count option;
      [@ocaml.doc
        "The number of instances to add to the instance group of a SageMaker HyperPod cluster.\n"]
  instance_type : cluster_instance_type;
      [@ocaml.doc "The instance type of the instance group for the cluster.\n"]
}
[@@ocaml.doc "Configuration of the resources used for the compute allocation definition.\n"]

