[@@ocaml.doc ""]

type nonrec resource_sharing_config = {
  absolute_borrow_limits : absolute_borrow_limit_resource_list option;
      [@ocaml.doc
        "The absolute limits on compute resources that can be borrowed from idle compute. When \
         specified, these limits define the maximum amount of specific resource types (such as \
         accelerators, vCPU, or memory) that an entity can borrow, regardless of the \
         percentage-based [BorrowLimit].\n"]
  borrow_limit : borrow_limit option;
      [@ocaml.doc
        "The limit on how much idle compute can be borrowed.The values can be 1 - 500 percent of \
         idle compute that the team is allowed to borrow.\n\n\
        \ Default is [50].\n\
        \ "]
  strategy : resource_sharing_strategy;
      [@ocaml.doc
        "The strategy of how idle compute is shared within the cluster. The following are the \
         options of strategies.\n\n\
        \ {ul\n\
        \       {-   [DontLend]: entities do not lend idle compute.\n\
        \           \n\
        \            }\n\
        \       {-   [Lend]: entities can lend idle compute to entities that can borrow.\n\
        \           \n\
        \            }\n\
        \       {-   [LendandBorrow]: entities can lend idle compute and borrow idle compute from \
         other entities.\n\
        \           \n\
        \            }\n\
        \       }\n\
        \   Default is [LendandBorrow].\n\
        \   "]
}
[@@ocaml.doc "Resource sharing configuration.\n"]

type nonrec preempt_team_tasks = LOWERPRIORITY [@ocaml.doc ""] | NEVER [@ocaml.doc ""]
[@@ocaml.doc ""]

type nonrec compute_quota_config = {
  preempt_team_tasks : preempt_team_tasks option;
      [@ocaml.doc
        "Allows workloads from within an entity to preempt same-team workloads. When set to \
         [LowerPriority], the entity's lower priority tasks are preempted by their own higher \
         priority tasks.\n\n\
        \ Default is [LowerPriority].\n\
        \ "]
  resource_sharing_config : resource_sharing_config option;
      [@ocaml.doc
        "Resource sharing configuration. This defines how an entity can lend and borrow idle \
         compute with other entities within the cluster.\n"]
  compute_quota_resources : compute_quota_resource_config_list option;
      [@ocaml.doc "Allocate compute resources by instance types.\n"]
}
[@@ocaml.doc
  "Configuration of the compute allocation definition for an entity. This includes the resource \
   sharing option and the setting to preempt low priority tasks.\n"]

