type nonrec fair_share_weight = int [@@ocaml.doc ""]

type nonrec compute_quota_target = {
  fair_share_weight : fair_share_weight option;
      [@ocaml.doc
        "Assigned entity fair-share weight. Idle compute will be shared across entities based on \
         these assigned weights. This weight is only used when [FairShare] is enabled.\n\n\
        \ A weight of 0 is the lowest priority and 100 is the highest. Weight 0 is the default.\n\
        \ "]
  team_name : compute_quota_target_team_name;
      [@ocaml.doc "Name of the team to allocate compute resources to.\n"]
