  image_release_version : image_release_version option;
      [@ocaml.doc
        "The version of the HyperPod-managed AMI to use for the instance group. Uses semantic \
         versioning in the format [MAJOR.MINOR.PATCH] (for example, [1.2.3]). If omitted, the \
         latest available version is used.\n"]
  auto_patch_config : cluster_auto_patch_config option;
      [@ocaml.doc
        "The configuration for automatic OS security patching. If present, the system \
         automatically applies PATCH AMI updates to this instance group.\n"]
  image_id : image_id option;
      [@ocaml.doc
        "When configuring your HyperPod cluster, you can specify an image ID using one of the \
         following options:\n\n\
        \ {ul\n\
        \       {-   [HyperPodPublicAmiId]: Use a HyperPod public AMI\n\
        \           \n\
        \            }\n\
        \       {-   [CustomAmiId]: Use your custom AMI\n\
        \           \n\
        \            }\n\
        \       {-   [default]: Use the default latest system image\n\
        \           \n\
        \            }\n\
        \       }\n\
        \   If you choose to use a custom AMI ([CustomAmiId]), ensure it meets the following \
         requirements:\n\
        \   \n\
        \    {ul\n\
        \          {-  Encryption: The custom AMI must be unencrypted.\n\
        \              \n\
        \               }\n\
        \          {-  Ownership: The custom AMI must be owned by the same Amazon Web Services \
         account that is creating the HyperPod cluster.\n\
        \              \n\
        \               }\n\
        \          {-  Volume support: Only the primary AMI snapshot volume is supported; \
         additional AMI volumes are not supported.\n\
        \              \n\
        \               }\n\
        \          }\n\
        \   When updating the instance group's AMI through the [UpdateClusterSoftware] operation, \
         if an instance group uses a custom AMI, you must provide an [ImageId] or use the default \
         as input. Note that if you don't specify an instance group in your \
         [UpdateClusterSoftware] request, then all of the instance groups are patched with the \
         specified image.\n\
        \   "]
  scheduled_update_config : scheduled_update_config option;
      [@ocaml.doc
        "The configuration object of the schedule that SageMaker uses to update the AMI.\n"]
  override_vpc_config : vpc_config option;
      [@ocaml.doc
        "To configure multi-AZ deployments, customize the Amazon VPC configuration at the instance \
         group level. You can specify different subnets and security groups across different AZs \
         in the instance group specification to override a SageMaker HyperPod cluster's default \
         Amazon VPC configuration. For more information about deploying a cluster in multiple AZs, \
         see \
         {{:https://docs.aws.amazon.com/sagemaker/latest/dg/sagemaker-hyperpod-prerequisites.html#sagemaker-hyperpod-prerequisites-multiple-availability-zones}Setting \
         up SageMaker HyperPod clusters across multiple AZs}.\n\n\
        \  When your Amazon VPC and subnets support IPv6, network communications differ based on \
         the cluster orchestration platform:\n\
        \  \n\
        \   {ul\n\
        \         {-  Slurm-orchestrated clusters automatically configure nodes with dual IPv6 and \
         IPv4 addresses, allowing immediate IPv6 network communications.\n\
        \             \n\
        \              }\n\
        \         {-  In Amazon EKS-orchestrated clusters, nodes receive dual-stack addressing, \
         but pods can only use IPv6 when the Amazon EKS cluster is explicitly IPv6-enabled. For \
         information about deploying an IPv6 Amazon EKS cluster, see \
         {{:https://docs.aws.amazon.com/eks/latest/userguide/deploy-ipv6-cluster.html#_deploy_an_ipv6_cluster_with_eksctl}Amazon \
         EKS IPv6 Cluster Deployment}.\n\
        \             \n\
        \              }\n\
        \         }\n\
        \   Additional resources for IPv6 configuration:\n\
        \   \n\
        \    {ul\n\
        \          {-  For information about adding IPv6 support to your VPC, see to \
         {{:https://docs.aws.amazon.com/vpc/latest/userguide/vpc-migrate-ipv6.html}IPv6 Support \
         for VPC}.\n\
        \              \n\
        \               }\n\
        \          {-  For information about creating a new IPv6-compatible VPC, see \
         {{:https://docs.aws.amazon.com/vpc/latest/userguide/create-vpc.html}Amazon VPC Creation \
         Guide}.\n\
        \              \n\
        \               }\n\
        \          {-  To configure SageMaker HyperPod with a custom Amazon VPC, see \
         {{:https://docs.aws.amazon.com/sagemaker/latest/dg/sagemaker-hyperpod-prerequisites.html#sagemaker-hyperpod-prerequisites-optional-vpc}Custom \
         Amazon VPC Setup for SageMaker HyperPod}.\n\
        \              \n\
        \               }\n\
        \          }\n\
        \   "]
  training_plan_arn : training_plan_arn option;
      [@ocaml.doc
        "The Amazon Resource Name (ARN); of the training plan to use for this cluster instance \
         group.\n\n\
        \ For more information about how to reserve GPU capacity for your SageMaker HyperPod \
         clusters using Amazon SageMaker Training Plan, see \n\
        \ {[\n\
        \  \
         {{:https://docs.aws.amazon.com/sagemaker/latest/APIReference/API_CreateTrainingPlan.html}CreateTrainingPlan} \n\
        \ ]}\n\
        \ .\n\
        \ "]
  on_start_deep_health_checks : on_start_deep_health_checks option;
      [@ocaml.doc
        "A flag indicating whether deep health checks should be performed when the cluster \
         instance group is created or updated.\n"]
  instance_storage_configs : cluster_instance_storage_configs option;
      [@ocaml.doc
        "Specifies the additional storage configurations for the instances in the SageMaker \
         HyperPod cluster instance group.\n"]
  threads_per_core : cluster_threads_per_core option;
      [@ocaml.doc
        "Specifies the value for {b Threads per core}. For instance types that support \
         multithreading, you can specify [1] for disabling multithreading and [2] for enabling \
         multithreading. For instance types that doesn't support multithreading, specify [1]. For \
         more information, see the reference table of \
         {{:https://docs.aws.amazon.com/AWSEC2/latest/UserGuide/cpu-options-supported-instances-values.html}CPU \
         cores and threads per CPU core per instance type} in the {i Amazon Elastic Compute Cloud \
         User Guide}.\n"]
  execution_role : role_arn;
      [@ocaml.doc "Specifies an IAM execution role to be assumed by the instance group.\n"]
  life_cycle_config : cluster_life_cycle_config option;
      [@ocaml.doc "Specifies the LifeCycle configuration for the instance group.\n"]
  instance_requirements : cluster_instance_requirements option;
      [@ocaml.doc
        "The instance requirements for the instance group, including the instance types to use. \
         Use this to create a flexible instance group that supports multiple instance types. The \
         [InstanceType] and [InstanceRequirements] properties are mutually exclusive.\n"]
  instance_type : cluster_instance_type option;
      [@ocaml.doc "Specifies the instance type of the instance group.\n"]
  instance_group_name : cluster_instance_group_name;
      [@ocaml.doc "Specifies the name of the instance group.\n"]
  min_instance_count : cluster_instance_count option;
      [@ocaml.doc
        "Defines the minimum number of instances required for an instance group to become \
         [InService]. If this threshold isn't met within 3 hours, the instance group rolls back to \
         its previous state - zero instances for new instance groups, or previous settings for \
         existing instance groups. [MinInstanceCount] only affects the initial transition to \
         [InService] and does not guarantee maintaining this minimum afterward. \n"]
  instance_count : cluster_instance_count;
      [@ocaml.doc
        "Specifies the number of instances to add to the instance group of a SageMaker HyperPod \
         cluster.\n"]
}
