type nonrec human_task_ui_arn = string [@@ocaml.doc ""]

type nonrec ui_config = {
  human_task_ui_arn : human_task_ui_arn option;
      [@ocaml.doc
        "The ARN of the worker task template used to render the worker UI and tools for labeling \
         job tasks.\n\n\
        \ Use this parameter when you are creating a labeling job for named entity recognition, 3D \
         point cloud and video frame labeling jobs. Use your labeling job task type to select one \
         of the following ARNs and use it with this parameter when you create a labeling job. \
         Replace [aws-region] with the Amazon Web Services Region you are creating your labeling \
         job in. For example, replace [aws-region] with [us-west-1] if you create a labeling job \
         in US West (N. California).\n\
        \ \n\
        \   {b Named Entity Recognition} \n\
        \  \n\
        \   Use the following [HumanTaskUiArn] for named entity recognition labeling jobs:\n\
        \   \n\
        \     [arn:aws:sagemaker:aws-region:394669845002:human-task-ui/NamedEntityRecognition] \n\
        \    \n\
        \      {b 3D Point Cloud HumanTaskUiArns} \n\
        \     \n\
        \      Use this [HumanTaskUiArn] for 3D point cloud object detection and 3D point cloud \
         object detection adjustment labeling jobs. \n\
        \      \n\
        \       {ul\n\
        \             {-   \
         [arn:aws:sagemaker:aws-region:394669845002:human-task-ui/PointCloudObjectDetection] \n\
        \                 \n\
        \                  }\n\
        \             }\n\
        \    Use this [HumanTaskUiArn] for 3D point cloud object tracking and 3D point cloud \
         object tracking adjustment labeling jobs. \n\
        \   \n\
        \    {ul\n\
        \          {-   \
         [arn:aws:sagemaker:aws-region:394669845002:human-task-ui/PointCloudObjectTracking] \n\
        \              \n\
        \               }\n\
        \          }\n\
        \    Use this [HumanTaskUiArn] for 3D point cloud semantic segmentation and 3D point cloud \
         semantic segmentation adjustment labeling jobs.\n\
        \   \n\
        \    {ul\n\
        \          {-   \
         [arn:aws:sagemaker:aws-region:394669845002:human-task-ui/PointCloudSemanticSegmentation] \n\
        \              \n\
        \               }\n\
        \          }\n\
        \    {b Video Frame HumanTaskUiArns} \n\
        \   \n\
        \    Use this [HumanTaskUiArn] for video frame object detection and video frame object \
         detection adjustment labeling jobs. \n\
        \    \n\
        \     {ul\n\
        \           {-   [arn:aws:sagemaker:region:394669845002:human-task-ui/VideoObjectDetection] \n\
        \               \n\
        \                }\n\
        \           }\n\
        \    Use this [HumanTaskUiArn] for video frame object tracking and video frame object \
         tracking adjustment labeling jobs. \n\
        \   \n\
        \    {ul\n\
        \          {-   \
         [arn:aws:sagemaker:aws-region:394669845002:human-task-ui/VideoObjectTracking] \n\
        \              \n\
        \               }\n\
        \          }\n\
        \  "]
  ui_template_s3_uri : s3_uri option;
      [@ocaml.doc
        "The Amazon S3 bucket location of the UI template, or worker task template. This is the \
         template used to render the worker UI and tools for labeling job tasks. For more \
         information about the contents of a UI template, see \
         {{:https://docs.aws.amazon.com/sagemaker/latest/dg/sms-custom-templates-step2.html} \
         Creating Your Custom Labeling Task Template}.\n"]
}
[@@ocaml.doc
  "Provided configuration information for the worker UI for a labeling job. Provide either \
   [HumanTaskUiArn] or [UiTemplateS3Uri].\n\n\
  \ For named entity recognition, 3D point cloud and video frame labeling jobs, use \
   [HumanTaskUiArn].\n\
  \ \n\
  \  For all other Ground Truth built-in task types and custom task types, use [UiTemplateS3Uri] \
   to specify the location of a worker task template in Amazon S3.\n\
  \  "]

