type nonrec metric_definition = {
  regex : metric_regex;
      [@ocaml.doc
        "A regular expression that searches the output of a training job and gets the value of the \
         metric. For more information about using regular expressions to define metrics, see \
         {{:https://docs.aws.amazon.com/sagemaker/latest/dg/automatic-model-tuning-define-metrics-variables.html}Defining \
         metrics and environment variables}.\n"]
  name : metric_name; [@ocaml.doc "The name of the metric.\n"]
}
[@@ocaml.doc
  "Specifies a metric that the training algorithm writes to [stderr] or [stdout]. You can view \
   these logs to understand how your training job performs and check for any errors encountered \
   during training. SageMaker hyperparameter tuning captures all defined metrics. Specify one of \
   the defined metrics to use as an objective metric using the \
   {{:https://docs.aws.amazon.com/sagemaker/latest/APIReference/API_HyperParameterTrainingJobDefinition.html#sagemaker-Type-HyperParameterTrainingJobDefinition-TuningObjective}TuningObjective} \
   parameter in the [HyperParameterTrainingJobDefinition] API to evaluate job performance during \
   hyperparameter tuning.\n"]

