type nonrec algorithm_specification = {
  training_image_config : training_image_config option;
      [@ocaml.doc
        "The configuration to use an image from a private Docker registry for a training job.\n"]
  container_arguments : training_container_arguments option;
      [@ocaml.doc
        "The arguments for a container used to run a training job. See \
         {{:https://docs.aws.amazon.com/sagemaker/latest/dg/your-algorithms-training-algo-dockerfile.html}How \
         Amazon SageMaker Runs Your Training Image} for additional information.\n"]
  container_entrypoint : training_container_entrypoint option;
      [@ocaml.doc
        "The {{:https://docs.docker.com/engine/reference/builder/}entrypoint script for a Docker \
         container} used to run a training job. This script takes precedence over the default \
         train processing instructions. See \
         {{:https://docs.aws.amazon.com/sagemaker/latest/dg/your-algorithms-training-algo-dockerfile.html}How \
         Amazon SageMaker Runs Your Training Image} for more information.\n"]
  enable_sage_maker_metrics_time_series : boolean_ option;
      [@ocaml.doc
        "To generate and save time-series metrics during training, set to [true]. The default is \
         [false] and time-series metrics aren't generated except in the following cases:\n\n\
        \ {ul\n\
        \       {-  You use one of the SageMaker built-in algorithms\n\
        \           \n\
        \            }\n\
        \       {-  You use one of the following \
         {{:https://docs.aws.amazon.com/sagemaker/latest/dg/pre-built-containers-frameworks-deep-learning.html}Prebuilt \
         SageMaker Docker Images}:\n\
        \           \n\
        \            {ul\n\
        \                  {-  Tensorflow (version >= 1.15)\n\
        \                      \n\
        \                       }\n\
        \                  {-  MXNet (version >= 1.6)\n\
        \                      \n\
        \                       }\n\
        \                  {-  PyTorch (version >= 1.3)\n\
        \                      \n\
        \                       }\n\
        \                  \n\
        \        }\n\
        \         }\n\
        \       {-  You specify at least one \
         {{:https://docs.aws.amazon.com/sagemaker/latest/APIReference/API_MetricDefinition.html}MetricDefinition} \n\
        \           \n\
        \            }\n\
        \       }\n\
        \  "]
  metric_definitions : metric_definition_list option;
      [@ocaml.doc
        "A list of metric definition objects. Each object specifies the metric name and regular \
         expressions used to parse algorithm logs. SageMaker publishes each metric to Amazon \
         CloudWatch.\n"]
  training_input_mode : training_input_mode; [@ocaml.doc ""]
  algorithm_name : arn_or_name option;
      [@ocaml.doc
        "The name of the algorithm resource to use for the training job. This must be an algorithm \
         resource that you created or subscribe to on Amazon Web Services Marketplace.\n\n\
        \  You must specify either the algorithm name to the [AlgorithmName] parameter or the \
         image URI of the algorithm container to the [TrainingImage] parameter.\n\
        \  \n\
        \   Note that the [AlgorithmName] parameter is mutually exclusive with the [TrainingImage] \
         parameter. If you specify a value for the [AlgorithmName] parameter, you can't specify a \
         value for [TrainingImage], and vice versa.\n\
        \   \n\
        \    If you specify values for both parameters, the training job might break; if you don't \
         specify any value for both parameters, the training job might raise a [null] error.\n\
        \    \n\
        \     "]
  training_image : algorithm_image option;
      [@ocaml.doc
        "The registry path of the Docker image that contains the training algorithm. For \
         information about docker registry paths for SageMaker built-in algorithms, see \
         {{:https://docs.aws.amazon.com/sagemaker/latest/dg/sagemaker-algo-docker-registry-paths.html}Docker \
         Registry Paths and Example Code} in the {i Amazon SageMaker developer guide}. SageMaker \
         supports both [registry/repository\\[:tag\\]] and [registry/repository\\[@digest\\]] \
         image path formats. For more information about using your custom training container, see \
         {{:https://docs.aws.amazon.com/sagemaker/latest/dg/your-algorithms.html}Using Your Own \
         Algorithms with Amazon SageMaker}.\n\n\
        \  You must specify either the algorithm name to the [AlgorithmName] parameter or the \
         image URI of the algorithm container to the [TrainingImage] parameter.\n\
        \  \n\
        \   For more information, see the note in the [AlgorithmName] parameter description.\n\
        \   \n\
        \    "]
}
[@@ocaml.doc
  "Specifies the training algorithm to use in a \
   {{:https://docs.aws.amazon.com/sagemaker/latest/APIReference/API_CreateTrainingJob.html}CreateTrainingJob} \
   request.\n\n\
  \  SageMaker uses its own SageMaker account credentials to pull and access built-in algorithms \
   so built-in algorithms are universally accessible across all Amazon Web Services accounts. As a \
   result, built-in algorithms have standard, unrestricted access. You cannot restrict built-in \
   algorithms using IAM roles. Use custom algorithms if you require specific access controls.\n\
  \  \n\
  \    For more information about algorithms provided by SageMaker, see \
   {{:https://docs.aws.amazon.com/sagemaker/latest/dg/algos.html}Algorithms}. For information \
   about using your own algorithms, see \
   {{:https://docs.aws.amazon.com/sagemaker/latest/dg/your-algorithms.html}Using Your Own \
   Algorithms with Amazon SageMaker}. \n\
  \    "]

type nonrec channel_name = string [@@ocaml.doc ""]

type nonrec s3_data_type =
  | CONVERSE [@ocaml.doc ""]
  | AUGMENTED_MANIFEST_FILE [@ocaml.doc ""]
  | S3_PREFIX [@ocaml.doc ""]
  | MANIFEST_FILE [@ocaml.doc ""]
[@@ocaml.doc ""]

type nonrec s3_data_distribution =
  | SHARDED_BY_S3_KEY [@ocaml.doc ""]
  | FULLY_REPLICATED [@ocaml.doc ""]
[@@ocaml.doc ""]

type nonrec attribute_name = string [@@ocaml.doc ""]

type nonrec attribute_names = attribute_name list [@@ocaml.doc ""]

type nonrec instance_group_name = string [@@ocaml.doc ""]

type nonrec instance_group_names = instance_group_name list [@@ocaml.doc ""]

type nonrec hub_access_config = {
  hub_content_arn : hub_content_arn;
      [@ocaml.doc
        "The ARN of your private model hub content. This should be a [ModelReference] resource \
         type that points to a SageMaker JumpStart public hub model.\n"]
}
[@@ocaml.doc
  "The configuration for a private hub model reference that points to a public SageMaker JumpStart \
   model.\n\n\
  \ For more information about private hubs, see \
   {{:https://docs.aws.amazon.com/sagemaker/latest/dg/jumpstart-curated-hubs.html}Private curated \
   hubs for foundation model access control in JumpStart}.\n\
  \ "]

type nonrec s3_data_source = {
  hub_access_config : hub_access_config option;
      [@ocaml.doc
        "The configuration for a private hub model reference that points to a SageMaker JumpStart \
         public hub model.\n"]
  model_access_config : model_access_config option; [@ocaml.doc ""]
  instance_group_names : instance_group_names option;
      [@ocaml.doc "A list of names of instance groups that get data from the S3 data source.\n"]
  attribute_names : attribute_names option;
      [@ocaml.doc
        "A list of one or more attribute names to use that are found in a specified augmented \
         manifest file.\n"]
  s3_data_distribution_type : s3_data_distribution option;
      [@ocaml.doc
        "If you want SageMaker to replicate the entire dataset on each ML compute instance that is \
         launched for model training, specify [FullyReplicated]. \n\n\
        \ If you want SageMaker to replicate a subset of data on each ML compute instance that is \
         launched for model training, specify [ShardedByS3Key]. If there are {i n} ML compute \
         instances launched for a training job, each instance gets approximately 1/{i n} of the \
         number of S3 objects. In this case, model training on each machine uses only the subset \
         of training data. \n\
        \ \n\
        \  Don't choose more ML compute instances for training than available S3 objects. If you \
         do, some nodes won't get any data and you will pay for nodes that aren't getting any \
         training data. This applies in both File and Pipe modes. Keep this in mind when \
         developing algorithms. \n\
        \  \n\
        \   In distributed training, where you use multiple ML compute EC2 instances, you might \
         choose [ShardedByS3Key]. If the algorithm requires copying training data to the ML \
         storage volume (when [TrainingInputMode] is set to [File]), this copies 1/{i n} of the \
         number of objects. \n\
        \   "]
  s3_uri : s3_uri;
      [@ocaml.doc
        "Depending on the value specified for the [S3DataType], identifies either a key name \
         prefix or a manifest. For example: \n\n\
        \ {ul\n\
        \       {-   A key name prefix might look like this: [s3://bucketname/exampleprefix/] \n\
        \           \n\
        \            }\n\
        \       {-   A manifest might look like this: [s3://bucketname/example.manifest] \n\
        \           \n\
        \             A manifest is an S3 object which is a JSON file consisting of an array of \
         elements. The first element is a prefix which is followed by one or more suffixes. \
         SageMaker appends the suffix elements to the prefix to get a full set of [S3Uri]. Note \
         that the prefix must be a valid non-empty [S3Uri] that precludes users from specifying a \
         manifest whose individual [S3Uri] is sourced from different S3 buckets.\n\
        \            \n\
        \              The following code example shows a valid manifest format: \n\
        \             \n\
        \               [\\[ {\"prefix\": \"s3://customer_bucket/some/prefix/\"},] \n\
        \              \n\
        \                [ \"relative/path/to/custdata-1\",] \n\
        \               \n\
        \                 [ \"relative/path/custdata-2\",] \n\
        \                \n\
        \                  [ ...] \n\
        \                 \n\
        \                   [ \"relative/path/custdata-N\"] \n\
        \                  \n\
        \                    [\\]] \n\
        \                   \n\
        \                     This JSON is equivalent to the following [S3Uri] list:\n\
        \                    \n\
        \                      [s3://customer_bucket/some/prefix/relative/path/to/custdata-1] \n\
        \                     \n\
        \                       [s3://customer_bucket/some/prefix/relative/path/custdata-2] \n\
        \                      \n\
        \                        [...] \n\
        \                       \n\
        \                         [s3://customer_bucket/some/prefix/relative/path/custdata-N] \n\
        \                        \n\
        \                         The complete set of [S3Uri] in this manifest is the input data \
         for the channel for this data source. The object that each [S3Uri] points to must be \
         readable by the IAM role that SageMaker uses to perform tasks on your behalf. \n\
        \                         \n\
        \                          }\n\
        \       }\n\
        \   Your input bucket must be located in same Amazon Web Services region as your training \
         job.\n\
        \   "]
  s3_data_type : s3_data_type;
      [@ocaml.doc
        "If you choose [S3Prefix], [S3Uri] identifies a key name prefix. SageMaker uses all \
         objects that match the specified key name prefix for model training. \n\n\
        \ If you choose [ManifestFile], [S3Uri] identifies an object that is a manifest file \
         containing a list of object keys that you want SageMaker to use for model training. \n\
        \ \n\
        \  If you choose [AugmentedManifestFile], [S3Uri] identifies an object that is an \
         augmented manifest file in JSON lines format. This file contains the data you want to use \
         for model training. [AugmentedManifestFile] can only be used if the Channel's input mode \
         is [Pipe].\n\
        \  \n\
        \   If you choose [Converse], [S3Uri] identifies an Amazon S3 location that contains data \
         formatted according to Converse format. This format structures conversational messages \
         with specific roles and content types used for training and fine-tuning foundational \
         models.\n\
        \   "]
}
[@@ocaml.doc
  "Describes the S3 data source.\n\n\
  \ Your input bucket must be in the same Amazon Web Services region as your training job.\n\
  \ "]

type nonrec file_system_access_mode = RO [@ocaml.doc ""] | RW [@ocaml.doc ""] [@@ocaml.doc ""]

type nonrec file_system_type = FSXLUSTRE [@ocaml.doc ""] | EFS [@ocaml.doc ""] [@@ocaml.doc ""]

type nonrec file_system_data_source = {
  directory_path : directory_path;
      [@ocaml.doc "The full path to the directory to associate with the channel.\n"]
  file_system_type : file_system_type; [@ocaml.doc "The file system type. \n"]
  file_system_access_mode : file_system_access_mode;
      [@ocaml.doc
        "The access mode of the mount of the directory associated with the channel. A directory \
         can be mounted either in [ro] (read-only) or [rw] (read-write) mode.\n"]
  file_system_id : file_system_id; [@ocaml.doc "The file system id.\n"]
}
[@@ocaml.doc "Specifies a file system data source for a channel.\n"]

type nonrec hub_data_set_arn = string [@@ocaml.doc ""]

type nonrec dataset_source = {
  dataset_arn : hub_data_set_arn;
      [@ocaml.doc " The Amazon Resource Name (ARN) of the dataset resource. \n"]
}
[@@ocaml.doc " Specifies a dataset source for a channel. \n"]

type nonrec data_source = {
  dataset_source : dataset_source option;
      [@ocaml.doc " The dataset resource that's associated with a channel. \n"]
  file_system_data_source : file_system_data_source option;
      [@ocaml.doc "The file system that is associated with a channel.\n"]
  s3_data_source : s3_data_source option;
      [@ocaml.doc "The S3 location of the data source that is associated with a channel.\n"]
}
[@@ocaml.doc "Describes the location of the channel data.\n"]

type nonrec record_wrapper = RECORDIO [@ocaml.doc ""] | NONE [@ocaml.doc ""] [@@ocaml.doc ""]

type nonrec seed = Smaws_Lib.CoreTypes.Int64.t [@@ocaml.doc ""]

type nonrec shuffle_config = {
  seed : seed; [@ocaml.doc "Determines the shuffling order in [ShuffleConfig] value.\n"]
}
[@@ocaml.doc
  "A configuration for a shuffle option for input data in a channel. If you use [S3Prefix] for \
   [S3DataType], the results of the S3 key prefix matches are shuffled. If you use [ManifestFile], \
   the order of the S3 object references in the [ManifestFile] is shuffled. If you use \
   [AugmentedManifestFile], the order of the JSON lines in the [AugmentedManifestFile] is \
   shuffled. The shuffling order is determined using the [Seed] value.\n\n\
  \ For Pipe input mode, when [ShuffleConfig] is specified shuffling is done at the start of every \
   epoch. With large datasets, this ensures that the order of the training data is different for \
   each epoch, and it helps reduce bias and possible overfitting. In a multi-node training job \
   when [ShuffleConfig] is combined with [S3DataDistributionType] of [ShardedByS3Key], the data is \
   shuffled across nodes so that the content sent to a particular node on the first epoch might be \
   sent to a different node on the second epoch.\n\
  \ "]

type nonrec channel = {
  shuffle_config : shuffle_config option;
      [@ocaml.doc
        "A configuration for a shuffle option for input data in a channel. If you use [S3Prefix] \
         for [S3DataType], this shuffles the results of the S3 key prefix matches. If you use \
         [ManifestFile], the order of the S3 object references in the [ManifestFile] is shuffled. \
         If you use [AugmentedManifestFile], the order of the JSON lines in the \
         [AugmentedManifestFile] is shuffled. The shuffling order is determined using the [Seed] \
         value.\n\n\
        \ For Pipe input mode, shuffling is done at the start of every epoch. With large datasets \
         this ensures that the order of the training data is different for each epoch, it helps \
         reduce bias and possible overfitting. In a multi-node training job when ShuffleConfig is \
         combined with [S3DataDistributionType] of [ShardedByS3Key], the data is shuffled across \
         nodes so that the content sent to a particular node on the first epoch might be sent to a \
         different node on the second epoch.\n\
        \ "]
  input_mode : training_input_mode option;
      [@ocaml.doc
        "(Optional) The input mode to use for the data channel in a training job. If you don't set \
         a value for [InputMode], SageMaker uses the value set for [TrainingInputMode]. Use this \
         parameter to override the [TrainingInputMode] setting in a \
         {{:https://docs.aws.amazon.com/sagemaker/latest/APIReference/API_AlgorithmSpecification.html}AlgorithmSpecification} \
         request when you have a channel that needs a different input mode from the training job's \
         general setting. To download the data from Amazon Simple Storage Service (Amazon S3) to \
         the provisioned ML storage volume, and mount the directory to a Docker volume, use [File] \
         input mode. To stream data directly from Amazon S3 to the container, choose [Pipe] input \
         mode.\n\n\
        \ To use a model for incremental training, choose [File] input model.\n\
        \ "]
  record_wrapper_type : record_wrapper option;
      [@ocaml.doc
        " \n\n\
         Specify RecordIO as the value when input data is in raw format but the training algorithm \
         requires the RecordIO format. In this case, SageMaker wraps each individual S3 object in \
         a RecordIO record. If the input data is already in RecordIO format, you don't need to set \
         this attribute. For more information, see \
         {{:https://mxnet.apache.org/api/architecture/note_data_loading#data-format}Create a \
         Dataset Using RecordIO}. \n\n\
        \ In File mode, leave this field unset or set it to None.\n\
        \ "]
  compression_type : compression_type option;
      [@ocaml.doc
        "If training data is compressed, the compression type. The default value is [None]. \
         [CompressionType] is used only in Pipe input mode. In File mode, leave this field unset \
         or set it to None.\n"]
  content_type : content_type option; [@ocaml.doc "The MIME type of the data.\n"]
  data_source : data_source; [@ocaml.doc "The location of the channel data.\n"]
  channel_name : channel_name; [@ocaml.doc "The name of the channel. \n"]
}
[@@ocaml.doc "A channel is a named input source that training algorithms can consume. \n"]

type nonrec input_data_config = channel list [@@ocaml.doc ""]

type nonrec output_compression_type = NONE [@ocaml.doc ""] | GZIP [@ocaml.doc ""] [@@ocaml.doc ""]

type nonrec output_data_config = {
  compression_type : output_compression_type option;
      [@ocaml.doc
        "The model output compression type. Select [None] to output an uncompressed model, \
         recommended for large model outputs. Defaults to gzip.\n"]
  s3_output_path : s3_uri;
      [@ocaml.doc
        "Identifies the S3 path where you want SageMaker to store the model artifacts. For \
         example, [s3://bucket-name/key-name-prefix]. \n"]
  kms_key_id : kms_key_id option;
      [@ocaml.doc
        "The Amazon Web Services Key Management Service (Amazon Web Services KMS) key that \
         SageMaker uses to encrypt the model artifacts at rest using Amazon S3 server-side \
         encryption. The [KmsKeyId] can be any of the following formats: \n\n\
        \ {ul\n\
        \       {-  // KMS Key ID\n\
        \           \n\
        \             [\"1234abcd-12ab-34cd-56ef-1234567890ab\"] \n\
        \            \n\
        \             }\n\
        \       {-  // Amazon Resource Name (ARN) of a KMS Key\n\
        \           \n\
        \             \
         [\"arn:aws:kms:us-west-2:111122223333:key/1234abcd-12ab-34cd-56ef-1234567890ab\"] \n\
        \            \n\
        \             }\n\
        \       {-  // KMS Key Alias\n\
        \           \n\
        \             [\"alias/ExampleAlias\"] \n\
        \            \n\
        \             }\n\
        \       {-  // Amazon Resource Name (ARN) of a KMS Key Alias\n\
        \           \n\
        \             [\"arn:aws:kms:us-west-2:111122223333:alias/ExampleAlias\"] \n\
        \            \n\
        \             }\n\
        \       }\n\
        \   If you use a KMS key ID or an alias of your KMS key, the SageMaker execution role must \
         include permissions to call [kms:Encrypt]. If you don't provide a KMS key ID, SageMaker \
         uses the default KMS key for Amazon S3 for your role's account. For more information, see \
         {{:https://docs.aws.amazon.com/AmazonS3/latest/userguide/UsingKMSEncryption.html}KMS-Managed \
         Encryption Keys} in the {i Amazon Simple Storage Service Developer Guide}. If the output \
         data is stored in Amazon S3 Express One Zone, it is encrypted with server-side encryption \
         with Amazon S3 managed keys (SSE-S3). KMS key is not supported for Amazon S3 Express One \
         Zone\n\
        \   \n\
        \    The KMS key policy must grant permission to the IAM role that you specify in your \
         [CreateTrainingJob], [CreateTransformJob], or [CreateHyperParameterTuningJob] requests. \
         For more information, see \
         {{:https://docs.aws.amazon.com/kms/latest/developerguide/key-policies.html}Using Key \
         Policies in Amazon Web Services KMS} in the {i Amazon Web Services Key Management Service \
         Developer Guide}.\n\
        \    "]
}
[@@ocaml.doc "Provides information about how to store model training results (model artifacts).\n"]

