type nonrec resource_config = {
  instance_placement_config : instance_placement_config option;
      [@ocaml.doc
        "Configuration for how training job instances are placed and allocated within \
         UltraServers. Only applicable for UltraServer capacity.\n"]
  training_plan_arn : training_plan_arn option;
      [@ocaml.doc
        "The Amazon Resource Name (ARN); of the training plan to use for this resource \
         configuration.\n"]
  instance_groups : instance_groups option;
      [@ocaml.doc "The configuration of a heterogeneous cluster in JSON format.\n"]
  keep_alive_period_in_seconds : keep_alive_period_in_seconds option;
      [@ocaml.doc
        "The duration of time in seconds to retain configured resources in a warm pool for \
         subsequent training jobs.\n"]
  volume_kms_key_id : kms_key_id option;
      [@ocaml.doc
        "The Amazon Web Services KMS key that SageMaker uses to encrypt data on the storage volume \
         attached to the ML compute instance(s) that run the training job.\n\n\
        \  Certain Nitro-based instances include local storage, dependent on the instance type. \
         Local storage volumes are encrypted using a hardware module on the instance. You can't \
         request a [VolumeKmsKeyId] when using an instance type with local storage.\n\
        \  \n\
        \   For a list of instance types that support local instance storage, see \
         {{:https://docs.aws.amazon.com/AWSEC2/latest/UserGuide/InstanceStorage.html#instance-store-volumes}Instance \
         Store Volumes}.\n\
        \   \n\
        \    For more information about local instance storage encryption, see \
         {{:https://docs.aws.amazon.com/AWSEC2/latest/UserGuide/ssd-instance-store.html}SSD \
         Instance Store Volumes}.\n\
        \    \n\
        \      The [VolumeKmsKeyId] can be in any of the following formats:\n\
        \      \n\
        \       {ul\n\
        \             {-  // KMS Key ID\n\
        \                 \n\
        \                   [\"1234abcd-12ab-34cd-56ef-1234567890ab\"] \n\
        \                  \n\
        \                   }\n\
        \             {-  // Amazon Resource Name (ARN) of a KMS Key\n\
        \                 \n\
        \                   \
         [\"arn:aws:kms:us-west-2:111122223333:key/1234abcd-12ab-34cd-56ef-1234567890ab\"] \n\
        \                  \n\
        \                   }\n\
        \             }\n\
        \  "]
  volume_size_in_g_b : optional_volume_size_in_g_b option;
      [@ocaml.doc
        "The size of the ML storage volume that you want to provision. \n\n\
        \ SageMaker automatically selects the volume size for serverless training jobs. You cannot \
         customize this setting.\n\
        \ \n\
        \  ML storage volumes store model artifacts and incremental states. Training algorithms \
         might also use the ML storage volume for scratch space. If you want to store the training \
         data in the ML storage volume, choose [File] as the [TrainingInputMode] in the algorithm \
         specification. \n\
        \  \n\
        \   When using an ML instance with \
         {{:https://docs.aws.amazon.com/AWSEC2/latest/UserGuide/ssd-instance-store.html#nvme-ssd-volumes}NVMe \
         SSD volumes}, SageMaker doesn't provision Amazon EBS General Purpose SSD (gp2) storage. \
         Available storage is fixed to the NVMe-type instance's storage capacity. SageMaker \
         configures storage paths for training datasets, checkpoints, model artifacts, and outputs \
         to use the entire capacity of the instance storage. For example, ML instance families \
         with the NVMe-type instance storage include [ml.p4d], [ml.g4dn], and [ml.g5]. \n\
        \   \n\
        \    When using an ML instance with the EBS-only storage option and without instance \
         storage, you must define the size of EBS volume through [VolumeSizeInGB] in the \
         [ResourceConfig] API. For example, ML instance families that use EBS volumes include \
         [ml.c5] and [ml.p2]. \n\
        \    \n\
        \     To look up instance types and their instance storage types and volumes, see \
         {{:http://aws.amazon.com/ec2/instance-types/}Amazon EC2 Instance Types}.\n\
        \     \n\
        \      To find the default local paths defined by the SageMaker training platform, see \
         {{:https://docs.aws.amazon.com/sagemaker/latest/dg/model-train-storage.html}Amazon \
         SageMaker Training Storage Folders for Training Datasets, Checkpoints, Model Artifacts, \
         and Outputs}.\n\
        \      "]
  instance_count : training_instance_count option;
      [@ocaml.doc
        "The number of ML compute instances to use. For distributed training, provide a value \
         greater than 1. \n"]
  instance_type : training_instance_type option; [@ocaml.doc "The ML compute instance type. \n"]
}
[@@ocaml.doc
  "Describes the resources, including machine learning (ML) compute instances and ML storage \
   volumes, to use for model training. \n"]

type nonrec max_runtime_in_seconds = int [@@ocaml.doc ""]

type nonrec max_wait_time_in_seconds = int [@@ocaml.doc ""]

type nonrec max_pending_time_in_seconds = int [@@ocaml.doc ""]

type nonrec stopping_condition = {
  max_pending_time_in_seconds : max_pending_time_in_seconds option;
      [@ocaml.doc
        "The maximum length of time, in seconds, that a training or compilation job can be pending \
         before it is stopped.\n\n\
        \  When working with training jobs that use capacity from \
         {{:https://docs.aws.amazon.com/sagemaker/latest/dg/reserve-capacity-with-training-plans.html}training \
         plans}, not all [Pending] job states count against the [MaxPendingTimeInSeconds] limit. \
         The following scenarios do not increment the [MaxPendingTimeInSeconds] counter:\n\
        \  \n\
        \   {ul\n\
        \         {-  The plan is in a [Scheduled] state: Jobs queued (in [Pending] status) before \
         a plan's start date (waiting for scheduled start time)\n\
        \             \n\
        \              }\n\
        \         {-  Between capacity reservations: Jobs temporarily back to [Pending] status \
         between two capacity reservation periods\n\
        \             \n\
        \              }\n\
        \         }\n\
        \    [MaxPendingTimeInSeconds] only increments when jobs are actively waiting for capacity \
         in an [Active] plan.\n\
        \   \n\
        \    "]
  max_wait_time_in_seconds : max_wait_time_in_seconds option;
      [@ocaml.doc
        "The maximum length of time, in seconds, that a managed Spot training job has to complete. \
         It is the amount of time spent waiting for Spot capacity plus the amount of time the job \
         can run. It must be equal to or greater than [MaxRuntimeInSeconds]. If the job does not \
         complete during this time, SageMaker ends the job.\n\n\
        \ When [RetryStrategy] is specified in the job request, [MaxWaitTimeInSeconds] specifies \
         the maximum time for all of the attempts in total, not each individual attempt.\n\
        \ "]
  max_runtime_in_seconds : max_runtime_in_seconds option;
      [@ocaml.doc
        "The maximum length of time, in seconds, that a training or compilation job can run before \
         it is stopped.\n\n\
        \ For compilation jobs, if the job does not complete during this time, a [TimeOut] error \
         is generated. We recommend starting with 900 seconds and increasing as necessary based on \
         your model.\n\
        \ \n\
        \  For all other jobs, if the job does not complete during this time, SageMaker ends the \
         job. When [RetryStrategy] is specified in the job request, [MaxRuntimeInSeconds] \
         specifies the maximum time for all of the attempts in total, not each individual attempt. \
         The default value is 1 day. The maximum value is 28 days.\n\
        \  \n\
        \   The maximum time that a [TrainingJob] can run in total, including any time spent \
         publishing metrics or archiving and uploading models after it has been stopped, is 30 \
         days.\n\
        \   "]
}
[@@ocaml.doc
  "Specifies a limit to how long a job can run. When the job reaches the time limit, SageMaker \
   ends the job. Use this API to cap costs.\n\n\
  \ To stop a training job, SageMaker sends the algorithm the [SIGTERM] signal, which delays job \
   termination for 120 seconds. Algorithms can use this 120-second window to save the model \
   artifacts, so the results of training are not lost. \n\
  \ \n\
  \  The training algorithms provided by SageMaker automatically save the intermediate results of \
   a model training job when possible. This attempt to save artifacts is only a best effort case \
   as model might not be in a state from which it can be saved. For example, if training has just \
   started, the model might not be ready to save. When saved, this intermediate data is a valid \
   model artifact. You can use it to create a model with [CreateModel].\n\
  \  \n\
  \    The Neural Topic Model (NTM) currently does not support saving intermediate model \
   artifacts. When training NTMs, make sure that the maximum runtime is sufficient for the \
   training job to complete.\n\
  \    \n\
  \     "]

type nonrec status_message = string [@@ocaml.doc ""]

type nonrec secondary_status_transition = {
  status_message : status_message option;
      [@ocaml.doc
        "A detailed description of the progress within a secondary status. \n\n\
        \ SageMaker provides secondary statuses and status messages that apply to each of them:\n\
        \ \n\
        \   Starting  {ul\n\
        \                   {-  Starting the training job.\n\
        \                       \n\
        \                        }\n\
        \                   {-  Launching requested ML instances.\n\
        \                       \n\
        \                        }\n\
        \                   {-  Insufficient capacity error from EC2 while launching instances, \
         retrying!\n\
        \                       \n\
        \                        }\n\
        \                   {-  Launched instance was unhealthy, replacing it!\n\
        \                       \n\
        \                        }\n\
        \                   {-  Preparing the instances for training.\n\
        \                       \n\
        \                        }\n\
        \                   }  Training  {ul\n\
        \                                      {-  Training image download completed. Training in \
         progress.\n\
        \                                          \n\
        \                                           }\n\
        \                                      }\n\
        \      Status messages are subject to change. Therefore, we recommend not including them \
         in code that programmatically initiates actions. For examples, don't use status messages \
         in if statements.\n\
        \      \n\
        \        To have an overview of your training job's progress, view [TrainingJobStatus] and \
         [SecondaryStatus] in \
         {{:https://docs.aws.amazon.com/sagemaker/latest/APIReference/API_DescribeTrainingJob.html}DescribeTrainingJob}, \
         and [StatusMessage] together. For example, at the start of a training job, you might see \
         the following:\n\
        \        \n\
        \         {ul\n\
        \               {-   [TrainingJobStatus] - InProgress\n\
        \                   \n\
        \                    }\n\
        \               {-   [SecondaryStatus] - Training\n\
        \                   \n\
        \                    }\n\
        \               {-   [StatusMessage] - Downloading the training image\n\
        \                   \n\
        \                    }\n\
        \               }\n\
        \  "]
  end_time : timestamp option;
      [@ocaml.doc
        "A timestamp that shows when the training job transitioned out of this secondary status \
         state into another secondary status state or when the training job has ended.\n"]
  start_time : timestamp;
      [@ocaml.doc
        "A timestamp that shows when the training job transitioned to the current secondary status \
         state.\n"]
  status : secondary_status;
      [@ocaml.doc
        "Contains a secondary status information from a training job.\n\n\
        \ Status might be one of the following secondary statuses:\n\
        \ \n\
        \   InProgress  {ul\n\
        \                     {-   [Starting] - Starting the training job.\n\
        \                         \n\
        \                          }\n\
        \                     {-   [Downloading] - An optional stage for algorithms that support \
         [File] training input mode. It indicates that data is being downloaded to the ML storage \
         volumes.\n\
        \                         \n\
        \                          }\n\
        \                     {-   [Training] - Training is in progress.\n\
        \                         \n\
        \                          }\n\
        \                     {-   [Uploading] - Training is complete and the model artifacts are \
         being uploaded to the S3 location.\n\
        \                         \n\
        \                          }\n\
        \                     }  Completed  {ul\n\
        \                                         {-   [Completed] - The training job has completed.\n\
        \                                             \n\
        \                                              }\n\
        \                                         }\n\
        \    Failed  {ul\n\
        \                  {-   [Failed] - The training job has failed. The reason for the failure \
         is returned in the [FailureReason] field of [DescribeTrainingJobResponse].\n\
        \                      \n\
        \                       }\n\
        \                  }\n\
        \    Stopped  {ul\n\
        \                   {-   [MaxRuntimeExceeded] - The job stopped because it exceeded the \
         maximum allowed runtime.\n\
        \                       \n\
        \                        }\n\
        \                   {-   [Stopped] - The training job has stopped.\n\
        \                       \n\
        \                        }\n\
        \                   }  Stopping  {ul\n\
        \                                      {-   [Stopping] - Stopping the training job.\n\
        \                                          \n\
        \                                           }\n\
        \                                      }\n\
        \     We no longer support the following secondary statuses:\n\
        \     \n\
        \      {ul\n\
        \            {-   [LaunchingMLInstances] \n\
        \                \n\
        \                 }\n\
        \            {-   [PreparingTrainingStack] \n\
        \                \n\
        \                 }\n\
        \            {-   [DownloadingTrainingImage] \n\
        \                \n\
        \                 }\n\
        \            }\n\
        \  "]
}
[@@ocaml.doc
  "An array element of [SecondaryStatusTransitions] for \
   {{:https://docs.aws.amazon.com/sagemaker/latest/APIReference/API_DescribeTrainingJob.html}DescribeTrainingJob}. \
   It provides additional details about a status that the training job has transitioned through. A \
   training job can be in one of several states, for example, starting, downloading, training, or \
   uploading. Within each state, there are a number of intermediate states. For example, within \
   the starting state, SageMaker could be starting the training job or launching the ML instances. \
   These transitional states are referred to as the job's secondary status. \n\n\
  \ \n\
  \ "]

type nonrec secondary_status_transitions = secondary_status_transition list [@@ocaml.doc ""]

