      [@ocaml.doc " The model package configuration. \n"]
  output_model_package_arn : model_package_arn option;
      [@ocaml.doc
        " The output model package Amazon Resource Name (ARN) that contains model weights or \
         checkpoint. \n"]
  debug_rule_evaluation_statuses : debug_rule_evaluation_statuses option;
      [@ocaml.doc "Information about the evaluation status of the rules for the training job.\n"]
  tensor_board_output_config : tensor_board_output_config option; [@ocaml.doc ""]
  debug_rule_configurations : debug_rule_configurations option;
      [@ocaml.doc "Information about the debug rule configuration.\n"]
  experiment_config : experiment_config option; [@ocaml.doc ""]
  debug_hook_config : debug_hook_config option; [@ocaml.doc ""]
  billable_time_in_seconds : billable_time_in_seconds option;
      [@ocaml.doc "The billable time in seconds.\n"]
  training_time_in_seconds : training_time_in_seconds option;
      [@ocaml.doc "The training time in seconds.\n"]
  checkpoint_config : checkpoint_config option; [@ocaml.doc ""]
  enable_managed_spot_training : boolean_ option;
      [@ocaml.doc
        "When true, enables managed spot training using Amazon EC2 Spot instances to run training \
         jobs instead of on-demand instances. For more information, see \
         {{:https://docs.aws.amazon.com/sagemaker/latest/dg/model-managed-spot-training.html}Managed \
         Spot Training}.\n"]
  enable_inter_container_traffic_encryption : boolean_ option;
      [@ocaml.doc
        "To encrypt all communications between ML compute instances in distributed training, \
         choose [True]. Encryption provides greater security for distributed training, but \
         training might take longer. How long it takes depends on the amount of communication \
         between compute instances, especially if you use a deep learning algorithm in distributed \
         training.\n"]
  enable_network_isolation : boolean_ option;
      [@ocaml.doc
        "If the [TrainingJob] was created with network isolation, the value is set to [true]. If \
         network isolation is enabled, nodes can't communicate beyond the VPC they run in.\n"]
  final_metric_data_list : final_metric_data_list option;
      [@ocaml.doc
        "A list of final metric values that are set when the training job completes. Used only if \
         the training job was configured to use metrics.\n"]
  secondary_status_transitions : secondary_status_transitions option;
      [@ocaml.doc
        "A history of all of the secondary statuses that the training job has transitioned through.\n"]
  last_modified_time : timestamp option;
      [@ocaml.doc
        "A timestamp that indicates when the status of the training job was last modified.\n"]
  training_end_time : timestamp option;
      [@ocaml.doc
        "Indicates the time when the training job ends on training instances. You are billed for \
         the time interval between the value of [TrainingStartTime] and this time. For successful \
         jobs and stopped jobs, this is the time after model artifacts are uploaded. For failed \
         jobs, this is the time when SageMaker detects a job failure.\n"]
  training_start_time : timestamp option;
      [@ocaml.doc
        "Indicates the time when the training job starts on training instances. You are billed for \
         the time interval between this time and the value of [TrainingEndTime]. The start time in \
         CloudWatch Logs might be later than this time. The difference is due to the time it takes \
         to download the training data and to the size of the training container.\n"]
  creation_time : timestamp option;
      [@ocaml.doc "A timestamp that indicates when the training job was created.\n"]
  stopping_condition : stopping_condition option;
      [@ocaml.doc
        "Specifies a limit to how long a model training job can run. It also specifies how long a \
         managed Spot training job has to complete. When the job reaches the time limit, SageMaker \
         ends the training job. Use this API to cap model training costs.\n\n\
        \ To stop a job, SageMaker sends the algorithm the [SIGTERM] signal, which delays job \
         termination for 120 seconds. Algorithms can use this 120-second window to save the model \
         artifacts, so the results of training are not lost. \n\
        \ "]
  vpc_config : vpc_config option;
      [@ocaml.doc
        "A \
         {{:https://docs.aws.amazon.com/sagemaker/latest/APIReference/API_VpcConfig.html}VpcConfig} \
         object that specifies the VPC that this training job has access to. For more information, \
         see {{:https://docs.aws.amazon.com/sagemaker/latest/dg/train-vpc.html}Protect Training \
         Jobs by Using an Amazon Virtual Private Cloud}.\n"]
  warm_pool_status : warm_pool_status option;
      [@ocaml.doc "The status of the warm pool associated with the training job.\n"]
  resource_config : resource_config option;
      [@ocaml.doc
        "Resources, including ML compute instances and ML storage volumes, that are configured for \
         model training.\n"]
  output_data_config : output_data_config option;
      [@ocaml.doc
        "The S3 path where model artifacts that you configured when creating the job are stored. \
         SageMaker creates subfolders for model artifacts.\n"]
  input_data_config : input_data_config option;
      [@ocaml.doc
        "An array of [Channel] objects that describes each data input channel.\n\n\
        \ Your input must be in the same Amazon Web Services region as your training job.\n\
        \ "]
  role_arn : role_arn option;
      [@ocaml.doc
        "The Amazon Web Services Identity and Access Management (IAM) role configured for the \
         training job.\n"]
  algorithm_specification : algorithm_specification option;
      [@ocaml.doc "Information about the algorithm used for training, and algorithm metadata.\n"]
  hyper_parameters : hyper_parameters option; [@ocaml.doc "Algorithm-specific parameters.\n"]
  failure_reason : failure_reason option;
      [@ocaml.doc "If the training job failed, the reason it failed.\n"]
  secondary_status : secondary_status option;
      [@ocaml.doc
        " Provides detailed information about the state of the training job. For detailed \
         information about the secondary status of the training job, see [StatusMessage] under \
         {{:https://docs.aws.amazon.com/sagemaker/latest/APIReference/API_SecondaryStatusTransition.html}SecondaryStatusTransition}.\n\n\
        \ SageMaker provides primary statuses and secondary statuses that apply to each of them:\n\
        \ \n\
        \   InProgress  {ul\n\
        \                     {-   [Starting] - Starting the training job.\n\
        \                         \n\
        \                          }\n\
        \                     {-   [Downloading] - An optional stage for algorithms that support \
         [File] training input mode. It indicates that data is being downloaded to the ML storage \
         volumes.\n\
        \                         \n\
        \                          }\n\
        \                     {-   [Training] - Training is in progress.\n\
        \                         \n\
        \                          }\n\
        \                     {-   [Uploading] - Training is complete and the model artifacts are \
         being uploaded to the S3 location.\n\
        \                         \n\
        \                          }\n\
        \                     }  Completed  {ul\n\
        \                                         {-   [Completed] - The training job has completed.\n\
        \                                             \n\
        \                                              }\n\
        \                                         }\n\
        \    Failed  {ul\n\
        \                  {-   [Failed] - The training job has failed. The reason for the failure \
         is returned in the [FailureReason] field of [DescribeTrainingJobResponse].\n\
        \                      \n\
        \                       }\n\
        \                  }\n\
        \    Stopped  {ul\n\
        \                   {-   [MaxRuntimeExceeded] - The job stopped because it exceeded the \
         maximum allowed runtime.\n\
        \                       \n\
        \                        }\n\
        \                   {-   [Stopped] - The training job has stopped.\n\
        \                       \n\
        \                        }\n\
        \                   }  Stopping  {ul\n\
        \                                      {-   [Stopping] - Stopping the training job.\n\
        \                                          \n\
        \                                           }\n\
        \                                      }\n\
        \      Valid values for [SecondaryStatus] are subject to change. \n\
        \      \n\
        \        We no longer support the following secondary statuses:\n\
        \        \n\
        \         {ul\n\
        \               {-   [LaunchingMLInstances] \n\
        \                   \n\
        \                    }\n\
        \               {-   [PreparingTrainingStack] \n\
        \                   \n\
        \                    }\n\
        \               {-   [DownloadingTrainingImage] \n\
        \                   \n\
        \                    }\n\
        \               }\n\
        \  "]
  training_job_status : training_job_status option;
      [@ocaml.doc
        "The status of the training job.\n\n\
        \ Training job statuses are:\n\
        \ \n\
        \  {ul\n\
        \        {-   [InProgress] - The training is in progress.\n\
        \            \n\
        \             }\n\
        \        {-   [Completed] - The training job has completed.\n\
        \            \n\
        \             }\n\
        \        {-   [Failed] - The training job has failed. To see the reason for the failure, \
         see the [FailureReason] field in the response to a [DescribeTrainingJobResponse] call.\n\
        \            \n\
        \             }\n\
        \        {-   [Stopping] - The training job is stopping.\n\
        \            \n\
        \             }\n\
        \        {-   [Stopped] - The training job has stopped.\n\
        \            \n\
        \             }\n\
        \        }\n\
        \   For more detailed information, see [SecondaryStatus]. \n\
        \   "]
  model_artifacts : model_artifacts option;
      [@ocaml.doc
        "Information about the Amazon S3 location that is configured for storing model artifacts.\n"]
  auto_ml_job_arn : auto_ml_job_arn option;
      [@ocaml.doc "The Amazon Resource Name (ARN) of the job.\n"]
  labeling_job_arn : labeling_job_arn option;
      [@ocaml.doc "The Amazon Resource Name (ARN) of the labeling job.\n"]
  tuning_job_arn : hyper_parameter_tuning_job_arn option;
      [@ocaml.doc
        "The Amazon Resource Name (ARN) of the associated hyperparameter tuning job if the \
         training job was launched by a hyperparameter tuning job.\n"]
  training_job_arn : training_job_arn option;
      [@ocaml.doc "The Amazon Resource Name (ARN) of the training job.\n"]
  training_job_name : training_job_name option; [@ocaml.doc "The name of the training job.\n"]
}
[@@ocaml.doc "Contains information about a training job.\n"]

type nonrec app_managed = bool [@@ocaml.doc ""]

type nonrec processing_s3_data_type = S3_PREFIX [@ocaml.doc ""] | MANIFEST_FILE [@ocaml.doc ""]
[@@ocaml.doc ""]

type nonrec processing_s3_compression_type = GZIP [@ocaml.doc ""] | NONE [@ocaml.doc ""]
[@@ocaml.doc ""]

type nonrec processing_s3_input = {
  s3_compression_type : processing_s3_compression_type option;
      [@ocaml.doc
        "Whether to GZIP-decompress the data in Amazon S3 as it is streamed into the processing \
         container. [Gzip] can only be used when [Pipe] mode is specified as the [S3InputMode]. In \
         [Pipe] mode, Amazon SageMaker streams input data from the source directly to your \
         container without using the EBS volume.\n"]
  s3_data_distribution_type : processing_s3_data_distribution_type option;
      [@ocaml.doc
        "Whether to distribute the data from Amazon S3 to all processing instances with \
         [FullyReplicated], or whether the data from Amazon S3 is sharded by Amazon S3 key, \
         downloading one shard of data to each processing instance.\n"]
  s3_input_mode : processing_s3_input_mode option;
      [@ocaml.doc
        "Whether to use [File] or [Pipe] input mode. In File mode, Amazon SageMaker copies the \
         data from the input source onto the local ML storage volume before starting your \
         processing container. This is the most commonly used input mode. In [Pipe] mode, Amazon \
         SageMaker streams input data from the source directly to your processing container into \
         named pipes without using the ML storage volume.\n"]
  s3_data_type : processing_s3_data_type;
      [@ocaml.doc
        "Whether you use an [S3Prefix] or a [ManifestFile] for the data type. If you choose \
         [S3Prefix], [S3Uri] identifies a key name prefix. Amazon SageMaker uses all objects with \
         the specified key name prefix for the processing job. If you choose [ManifestFile], \
         [S3Uri] identifies an object that is a manifest file containing a list of object keys \
         that you want Amazon SageMaker to use for the processing job.\n"]
  local_path : processing_local_path option;
      [@ocaml.doc
        "The local path in your container where you want Amazon SageMaker to write input data to. \
         [LocalPath] is an absolute path to the input data and must begin with \
         [/opt/ml/processing/]. [LocalPath] is a required parameter when [AppManaged] is [False] \
         (default).\n"]
  s3_uri : s3_uri;
      [@ocaml.doc
        "The URI of the Amazon S3 prefix Amazon SageMaker downloads data required to run a \
         processing job.\n"]
}
[@@ocaml.doc
  "Configuration for downloading input data from Amazon S3 into the processing container.\n"]

