type nonrec transform_s3_data_source = {
  s3_uri : s3_uri;
      [@ocaml.doc
        "Depending on the value specified for the [S3DataType], identifies either a key name \
         prefix or a manifest. For example:\n\n\
        \ {ul\n\
        \       {-   A key name prefix might look like this: [s3://bucketname/exampleprefix/]. \n\
        \           \n\
        \            }\n\
        \       {-   A manifest might look like this: [s3://bucketname/example.manifest] \n\
        \           \n\
        \             The manifest is an S3 object which is a JSON file with the following format: \n\
        \            \n\
        \              [\\[ {\"prefix\": \"s3://customer_bucket/some/prefix/\"},] \n\
        \             \n\
        \               [\"relative/path/to/custdata-1\",] \n\
        \              \n\
        \                [\"relative/path/custdata-2\",] \n\
        \               \n\
        \                 [...] \n\
        \                \n\
        \                  [\"relative/path/custdata-N\"] \n\
        \                 \n\
        \                   [\\]] \n\
        \                  \n\
        \                    The preceding JSON matches the following [S3Uris]: \n\
        \                   \n\
        \                     [s3://customer_bucket/some/prefix/relative/path/to/custdata-1] \n\
        \                    \n\
        \                      [s3://customer_bucket/some/prefix/relative/path/custdata-2] \n\
        \                     \n\
        \                       [...] \n\
        \                      \n\
        \                        [s3://customer_bucket/some/prefix/relative/path/custdata-N] \n\
        \                       \n\
        \                         The complete set of [S3Uris] in this manifest constitutes the \
         input data for the channel for this datasource. The object that each [S3Uris] points to \
         must be readable by the IAM role that Amazon SageMaker uses to perform tasks on your \
         behalf.\n\
        \                        \n\
        \                         }\n\
        \       }\n\
        \  "]
  s3_data_type : s3_data_type;
      [@ocaml.doc
        "If you choose [S3Prefix], [S3Uri] identifies a key name prefix. Amazon SageMaker uses all \
         objects with the specified key name prefix for batch transform. \n\n\
        \ If you choose [ManifestFile], [S3Uri] identifies an object that is a manifest file \
         containing a list of object keys that you want Amazon SageMaker to use for batch \
         transform. \n\
        \ \n\
        \  The following values are compatible: [ManifestFile], [S3Prefix] \n\
        \  \n\
        \   The following value is not compatible: [AugmentedManifestFile] \n\
        \   "]
}
[@@ocaml.doc "Describes the S3 data source.\n"]

