type nonrec split_type =
  | TFRECORD [@ocaml.doc ""]
  | RECORDIO [@ocaml.doc ""]
  | LINE [@ocaml.doc ""]
  | NONE [@ocaml.doc ""]
[@@ocaml.doc ""]

type nonrec transform_input = {
  split_type : split_type option;
      [@ocaml.doc
        "The method to use to split the transform job's data files into smaller batches. Splitting \
         is necessary when the total size of each object is too large to fit in a single request. \
         You can also use data splitting to improve performance by processing multiple concurrent \
         mini-batches. The default value for [SplitType] is [None], which indicates that input \
         data files are not split, and request payloads contain the entire contents of an input \
         object. Set the value of this parameter to [Line] to split records on a newline character \
         boundary. [SplitType] also supports a number of record-oriented binary data formats. \
         Currently, the supported record formats are:\n\n\
        \ {ul\n\
        \       {-  RecordIO\n\
        \           \n\
        \            }\n\
        \       {-  TFRecord\n\
        \           \n\
        \            }\n\
        \       }\n\
        \   When splitting is enabled, the size of a mini-batch depends on the values of the \
         [BatchStrategy] and [MaxPayloadInMB] parameters. When the value of [BatchStrategy] is \
         [MultiRecord], Amazon SageMaker sends the maximum number of records in each request, up \
         to the [MaxPayloadInMB] limit. If the value of [BatchStrategy] is [SingleRecord], Amazon \
         SageMaker sends individual records in each request.\n\
        \   \n\
        \     Some data formats represent a record as a binary payload wrapped with extra padding \
         bytes. When splitting is applied to a binary data format, padding is removed if the value \
         of [BatchStrategy] is set to [SingleRecord]. Padding is not removed if the value of \
         [BatchStrategy] is set to [MultiRecord].\n\
        \     \n\
        \      For more information about [RecordIO], see \
         {{:https://mxnet.apache.org/api/faq/recordio}Create a Dataset Using RecordIO} in the \
         MXNet documentation. For more information about [TFRecord], see \
         {{:https://www.tensorflow.org/guide/data#consuming_tfrecord_data}Consuming TFRecord data} \
         in the TensorFlow documentation.\n\
        \      \n\
        \       "]
  compression_type : compression_type option;
      [@ocaml.doc
        "If your transform data is compressed, specify the compression type. Amazon SageMaker \
         automatically decompresses the data for the transform job accordingly. The default value \
         is [None].\n"]
  content_type : content_type option;
      [@ocaml.doc
        "The multipurpose internet mail extension (MIME) type of the data. Amazon SageMaker uses \
         the MIME type with each http call to transfer data to the transform job.\n"]
  data_source : transform_data_source;
      [@ocaml.doc
        "Describes the location of the channel data, which is, the S3 location of the input data \
         that the model can consume.\n"]
}
[@@ocaml.doc
  "Describes the input source of a transform job and the way the transform job consumes it.\n"]

type nonrec accept = string [@@ocaml.doc ""]

type nonrec assembly_type = LINE [@ocaml.doc ""] | NONE [@ocaml.doc ""] [@@ocaml.doc ""]

type nonrec transform_output = {
  kms_key_id : kms_key_id option;
      [@ocaml.doc
        "The Amazon Web Services Key Management Service (Amazon Web Services KMS) key that Amazon \
         SageMaker uses to encrypt the model artifacts at rest using Amazon S3 server-side \
         encryption. The [KmsKeyId] can be any of the following formats: \n\n\
        \ {ul\n\
        \       {-  Key ID: [1234abcd-12ab-34cd-56ef-1234567890ab] \n\
        \           \n\
        \            }\n\
        \       {-  Key ARN: \
         [arn:aws:kms:us-west-2:111122223333:key/1234abcd-12ab-34cd-56ef-1234567890ab] \n\
        \           \n\
        \            }\n\
        \       {-  Alias name: [alias/ExampleAlias] \n\
        \           \n\
        \            }\n\
        \       {-  Alias name ARN: [arn:aws:kms:us-west-2:111122223333:alias/ExampleAlias] \n\
        \           \n\
        \            }\n\
        \       }\n\
        \   If you don't provide a KMS key ID, Amazon SageMaker uses the default KMS key for \
         Amazon S3 for your role's account. For more information, see \
         {{:https://docs.aws.amazon.com/AmazonS3/latest/dev/UsingKMSEncryption.html}KMS-Managed \
         Encryption Keys} in the {i Amazon Simple Storage Service Developer Guide.} \n\
        \   \n\
        \    The KMS key policy must grant permission to the IAM role that you specify in your \
         {{:https://docs.aws.amazon.com/sagemaker/latest/APIReference/API_CreateModel.html}CreateModel} \
         request. For more information, see \
         {{:https://docs.aws.amazon.com/kms/latest/developerguide/key-policies.html}Using Key \
         Policies in Amazon Web Services KMS} in the {i Amazon Web Services Key Management Service \
         Developer Guide}.\n\
        \    "]
  assemble_with : assembly_type option;
      [@ocaml.doc
        "Defines how to assemble the results of the transform job as a single S3 object. Choose a \
         format that is most convenient to you. To concatenate the results in binary format, \
         specify [None]. To add a newline character at the end of every transformed record, \
         specify [Line].\n"]
  accept : accept option;
      [@ocaml.doc
        "The MIME type used to specify the output data. Amazon SageMaker uses the MIME type with \
         each http call to transfer data from the transform job.\n"]
  s3_output_path : s3_uri;
      [@ocaml.doc
        "The Amazon S3 path where you want Amazon SageMaker to store the results of the transform \
         job. For example, [s3://bucket-name/key-name-prefix].\n\n\
        \ For every S3 object used as input for the transform job, batch transform stores the \
         transformed data with an .[out] suffix in a corresponding subfolder in the location in \
         the output prefix. For example, for the input data stored at \
         [s3://bucket-name/input-name-prefix/dataset01/data.csv], batch transform stores the \
         transformed data at [s3://bucket-name/output-name-prefix/input-name-prefix/data.csv.out]. \
         Batch transform doesn't upload partially processed objects. For an input S3 object that \
         contains multiple records, it creates an .[out] file only if the transform job succeeds \
         on the entire file. When the input contains multiple S3 objects, the batch transform job \
         processes the listed S3 objects and uploads only the output for successfully processed \
         objects. If any object fails in the transform job batch transform marks the job as failed \
         to prompt investigation.\n\
        \ "]
}
[@@ocaml.doc "Describes the results of a transform job.\n"]

