  transform_ami_version : transform_ami_version option;
      [@ocaml.doc
        "Specifies an option from a collection of preconfigured Amazon Machine Image (AMI) images. \
         Each image is configured by Amazon Web Services with a set of software and driver \
         versions.\n\n\
        \  al2-ami-sagemaker-batch-gpu-470  {ul\n\
        \                                         {-  Accelerator: GPU\n\
        \                                             \n\
        \                                              }\n\
        \                                         {-  NVIDIA driver version: 470\n\
        \                                             \n\
        \                                              }\n\
        \                                         }\n\
        \    al2-ami-sagemaker-batch-gpu-535  {ul\n\
        \                                           {-  Accelerator: GPU\n\
        \                                               \n\
        \                                                }\n\
        \                                           {-  NVIDIA driver version: 535\n\
        \                                               \n\
        \                                                }\n\
        \                                           }\n\
        \    "]
  volume_kms_key_id : kms_key_id option;
      [@ocaml.doc
        "The Amazon Web Services Key Management Service (Amazon Web Services KMS) key that Amazon \
         SageMaker uses to encrypt model data on the storage volume attached to the ML compute \
         instance(s) that run the batch transform job.\n\n\
        \  Certain Nitro-based instances include local storage, dependent on the instance type. \
         Local storage volumes are encrypted using a hardware module on the instance. You can't \
         request a [VolumeKmsKeyId] when using an instance type with local storage.\n\
        \  \n\
        \   For a list of instance types that support local instance storage, see \
         {{:https://docs.aws.amazon.com/AWSEC2/latest/UserGuide/InstanceStorage.html#instance-store-volumes}Instance \
         Store Volumes}.\n\
        \   \n\
        \    For more information about local instance storage encryption, see \
         {{:https://docs.aws.amazon.com/AWSEC2/latest/UserGuide/ssd-instance-store.html}SSD \
         Instance Store Volumes}.\n\
        \    \n\
        \       The [VolumeKmsKeyId] can be any of the following formats:\n\
        \      \n\
        \       {ul\n\
        \             {-  Key ID: [1234abcd-12ab-34cd-56ef-1234567890ab] \n\
        \                 \n\
        \                  }\n\
        \             {-  Key ARN: \
         [arn:aws:kms:us-west-2:111122223333:key/1234abcd-12ab-34cd-56ef-1234567890ab] \n\
        \                 \n\
        \                  }\n\
        \             {-  Alias name: [alias/ExampleAlias] \n\
        \                 \n\
        \                  }\n\
        \             {-  Alias name ARN: [arn:aws:kms:us-west-2:111122223333:alias/ExampleAlias] \n\
        \                 \n\
        \                  }\n\
        \             }\n\
        \  "]
  instance_count : transform_instance_count;
      [@ocaml.doc
        "The number of ML compute instances to use in the transform job. The default value is [1], \
         and the maximum is [100]. For distributed transform jobs, specify a value greater than \
         [1].\n"]
  instance_type : transform_instance_type;
      [@ocaml.doc
        "The ML compute instance type for the transform job. If you are using built-in algorithms \
         to transform moderately sized datasets, we recommend using ml.m4.xlarge or \
         [ml.m5.large]instance types.\n"]
}
[@@ocaml.doc
  "Describes the resources, including ML instance types and ML instance count, to use for \
   transform job.\n"]

type nonrec json_path = string [@@ocaml.doc ""]

type nonrec join_source = NONE [@ocaml.doc ""] | INPUT [@ocaml.doc ""] [@@ocaml.doc ""]

type nonrec data_processing = {
  join_source : join_source option;
      [@ocaml.doc
        "Specifies the source of the data to join with the transformed data. The valid values are \
         [None] and [Input]. The default value is [None], which specifies not to join the input \
         with the transformed data. If you want the batch transform job to join the original input \
         data with the transformed data, set [JoinSource] to [Input]. You can specify \
         [OutputFilter] as an additional filter to select a portion of the joined dataset and \
         store it in the output file.\n\n\
        \ For JSON or JSONLines objects, such as a JSON array, SageMaker adds the transformed data \
         to the input JSON object in an attribute called [SageMakerOutput]. The joined result for \
         JSON must be a key-value pair object. If the input is not a key-value pair object, \
         SageMaker creates a new JSON file. In the new JSON file, and the input data is stored \
         under the [SageMakerInput] key and the results are stored in [SageMakerOutput].\n\
        \ \n\
        \  For CSV data, SageMaker takes each row as a JSON array and joins the transformed data \
         with the input by appending each transformed row to the end of the input. The joined data \
         has the original input data followed by the transformed data and the output is a CSV file.\n\
        \  \n\
        \   For information on how joining in applied, see \
         {{:https://docs.aws.amazon.com/sagemaker/latest/dg/batch-transform-data-processing.html#batch-transform-data-processing-workflow}Workflow \
         for Associating Inferences with Input Records}.\n\
        \   "]
  output_filter : json_path option;
      [@ocaml.doc
        "A \
         {{:https://docs.aws.amazon.com/sagemaker/latest/dg/batch-transform-data-processing.html#data-processing-operators}JSONPath} \
         expression used to select a portion of the joined dataset to save in the output file for \
         a batch transform job. If you want SageMaker to store the entire input dataset in the \
         output file, leave the default value, [$]. If you specify indexes that aren't within the \
         dimension size of the joined dataset, you get an error.\n\n\
        \ Examples: [\"$\"], [\"$\\[0,5:\\]\"], [\"$\\['id','SageMakerOutput'\\]\"] \n\
        \ "]
  input_filter : json_path option;
      [@ocaml.doc
        "A \
         {{:https://docs.aws.amazon.com/sagemaker/latest/dg/batch-transform-data-processing.html#data-processing-operators}JSONPath} \
         expression used to select a portion of the input data to pass to the algorithm. Use the \
         [InputFilter] parameter to exclude fields, such as an ID column, from the input. If you \
         want SageMaker to pass the entire input dataset to the algorithm, accept the default \
         value [$].\n\n\
        \ Examples: [\"$\"], [\"$\\[1:\\]\"], [\"$.features\"] \n\
        \ "]
}
[@@ocaml.doc
  "The data structure used to specify the data to be used for inference in a batch transform job \
   and to associate the data that is relevant to the prediction results in the output. The input \
   filter provided allows you to exclude input data that is not needed for inference in a batch \
   transform job. The output filter provided allows you to include input data relevant to \
   interpreting the predictions in the output from the job. For more information, see \
   {{:https://docs.aws.amazon.com/sagemaker/latest/dg/batch-transform-data-processing.html}Associate \
   Prediction Results with their Corresponding Input Records}.\n"]

type nonrec transform_job = {
  tags : tag_list option; [@ocaml.doc "A list of tags associated with the transform job.\n"]
  experiment_config : experiment_config option; [@ocaml.doc ""]
  data_processing : data_processing option; [@ocaml.doc ""]
  auto_ml_job_arn : auto_ml_job_arn option;
      [@ocaml.doc
        "The Amazon Resource Name (ARN) of the AutoML job that created the transform job.\n"]
  labeling_job_arn : labeling_job_arn option;
      [@ocaml.doc
        "The Amazon Resource Name (ARN) of the labeling job that created the transform job.\n"]
  transform_end_time : timestamp option;
      [@ocaml.doc
        "Indicates when the transform job has been completed, or has stopped or failed. You are \
         billed for the time interval between this time and the value of [TransformStartTime].\n"]
  transform_start_time : timestamp option;
      [@ocaml.doc
        "Indicates when the transform job starts on ML instances. You are billed for the time \
         interval between this time and the value of [TransformEndTime].\n"]
  creation_time : timestamp option;
      [@ocaml.doc "A timestamp that shows when the transform Job was created.\n"]
  transform_resources : transform_resources option; [@ocaml.doc ""]
  data_capture_config : batch_data_capture_config option; [@ocaml.doc ""]
  transform_output : transform_output option; [@ocaml.doc ""]
  transform_input : transform_input option; [@ocaml.doc ""]
  environment : transform_environment_map option;
      [@ocaml.doc
        "The environment variables to set in the Docker container. We support up to 16 key and \
         values entries in the map.\n"]
  batch_strategy : batch_strategy option;
      [@ocaml.doc
        "Specifies the number of records to include in a mini-batch for an HTTP inference request. \
         A record is a single unit of input data that inference can be made on. For example, a \
         single line in a CSV file is a record.\n"]
  max_payload_in_m_b : max_payload_in_m_b option;
      [@ocaml.doc
        "The maximum allowed size of the payload, in MB. A payload is the data portion of a record \
         (without metadata). The value in [MaxPayloadInMB] must be greater than, or equal to, the \
         size of a single record. To estimate the size of a record in MB, divide the size of your \
         dataset by the number of records. To ensure that the records fit within the maximum \
         payload size, we recommend using a slightly larger value. The default value is 6 MB. For \
         cases where the payload might be arbitrarily large and is transmitted using HTTP chunked \
         encoding, set the value to 0. This feature works only in supported algorithms. Currently, \
         SageMaker built-in algorithms do not support HTTP chunked encoding.\n"]
  model_client_config : model_client_config option; [@ocaml.doc ""]
  max_concurrent_transforms : max_concurrent_transforms option;
      [@ocaml.doc
        "The maximum number of parallel requests that can be sent to each instance in a transform \
         job. If [MaxConcurrentTransforms] is set to 0 or left unset, SageMaker checks the \
         optional execution-parameters to determine the settings for your chosen algorithm. If the \
         execution-parameters endpoint is not enabled, the default value is 1. For built-in \
