type nonrec time_series_transformations = {
  aggregation : aggregation_transformations option;
      [@ocaml.doc
        "A key value pair defining the aggregation method for a column, where the key is the \
         column name and the value is the aggregation method.\n\n\
        \ The supported aggregation methods are [sum] (default), [avg], [first], [min], [max].\n\
        \ \n\
        \   Aggregation is only supported for the target column.\n\
        \   \n\
        \    "]
  filling : filling_transformations option;
      [@ocaml.doc
        "A key value pair defining the filling method for a column, where the key is the column \
         name and the value is an object which defines the filling logic. You can specify multiple \
         filling methods for a single column.\n\n\
        \ The supported filling methods and their corresponding options are:\n\
        \ \n\
        \  {ul\n\
        \        {-   [frontfill]: [none] (Supported only for target column)\n\
        \            \n\
        \             }\n\
        \        {-   [middlefill]: [zero], [value], [median], [mean], [min], [max] \n\
        \            \n\
        \             }\n\
        \        {-   [backfill]: [zero], [value], [median], [mean], [min], [max] \n\
        \            \n\
        \             }\n\
        \        {-   [futurefill]: [zero], [value], [median], [mean], [min], [max] \n\
        \            \n\
        \             }\n\
        \        }\n\
        \   To set a filling method to a specific value, set the fill parameter to the chosen \
         filling method value (for example [\"backfill\" : \"value\"]), and define the filling \
         value in an additional parameter prefixed with \"_value\". For example, to set [backfill] \
         to a value of [2], you must include two parameters: [\"backfill\": \"value\"] and \
         [\"backfill_value\":\"2\"].\n\
        \   "]
}
[@@ocaml.doc
  "Transformations allowed on the dataset. Supported transformations are [Filling] and \
   [Aggregation]. [Filling] specifies how to add values to missing values in the dataset. \
   [Aggregation] defines how to aggregate data that does not align with forecast frequency.\n"]

