type nonrec time_series_forecasting_job_config = {
  candidate_generation_config : candidate_generation_config option; [@ocaml.doc ""]
  holiday_config : holiday_config option;
      [@ocaml.doc
        "The collection of holiday featurization attributes used to incorporate national holiday \
         information into your forecasting model.\n"]
  time_series_config : time_series_config;
      [@ocaml.doc "The collection of components that defines the time-series.\n"]
  transformations : time_series_transformations option;
      [@ocaml.doc
        "The transformations modifying specific attributes of the time-series, such as filling \
         strategies for missing values.\n"]
  forecast_quantiles : forecast_quantiles option;
      [@ocaml.doc
        "The quantiles used to train the model for forecasts at a specified quantile. You can \
         specify quantiles from [0.01] (p1) to [0.99] (p99), by increments of 0.01 or higher. Up \
         to five forecast quantiles can be specified. When [ForecastQuantiles] is not provided, \
         the AutoML job uses the quantiles p10, p50, and p90 as default.\n"]
  forecast_horizon : forecast_horizon;
      [@ocaml.doc
        "The number of time-steps that the model predicts. The forecast horizon is also called the \
         prediction length. The maximum forecast horizon is the lesser of 500 time-steps or 1/4 of \
         the time-steps in the dataset.\n"]
  forecast_frequency : forecast_frequency;
      [@ocaml.doc
        "The frequency of predictions in a forecast.\n\n\
        \ Valid intervals are an integer followed by Y (Year), M (Month), W (Week), D (Day), H \
         (Hour), and min (Minute). For example, [1D] indicates every day and [15min] indicates \
         every 15 minutes. The value of a frequency must not overlap with the next larger \
         frequency. For example, you must use a frequency of [1H] instead of [60min].\n\
        \ \n\
        \  The valid values for each frequency are the following:\n\
        \  \n\
        \   {ul\n\
        \         {-  Minute - 1-59\n\
        \             \n\
        \              }\n\
        \         {-  Hour - 1-23\n\
        \             \n\
        \              }\n\
        \         {-  Day - 1-6\n\
        \             \n\
        \              }\n\
        \         {-  Week - 1-4\n\
        \             \n\
        \              }\n\
        \         {-  Month - 1-11\n\
        \             \n\
        \              }\n\
        \         {-  Year - 1\n\
        \             \n\
        \              }\n\
        \         }\n\
        \  "]
  completion_criteria : auto_ml_job_completion_criteria option; [@ocaml.doc ""]
  feature_specification_s3_uri : s3_uri option;
      [@ocaml.doc
        "A URL to the Amazon S3 data source containing additional selected features that \
         complement the target, itemID, timestamp, and grouped columns set in [TimeSeriesConfig]. \
         When not provided, the AutoML job V2 includes all the columns from the original dataset \
         that are not already declared in [TimeSeriesConfig]. If provided, the AutoML job V2 only \
         considers these additional columns as a complement to the ones declared in \
         [TimeSeriesConfig].\n\n\
        \ You can input [FeatureAttributeNames] (optional) in JSON format as shown below: \n\
        \ \n\
        \   [{ \"FeatureAttributeNames\":\\[\"col1\", \"col2\", ...\\] }].\n\
        \  \n\
        \   You can also specify the data type of the feature (optional) in the format shown below:\n\
        \   \n\
        \     [{ \"FeatureDataTypes\":{\"col1\":\"numeric\", \"col2\":\"categorical\" ... } }] \n\
        \    \n\
        \     Autopilot supports the following data types: [numeric], [categorical], [text], and \
         [datetime].\n\
        \     \n\
        \       These column keys must not include any column set in [TimeSeriesConfig].\n\
        \       \n\
        \        "]
}
[@@ocaml.doc
  "The collection of settings used by an AutoML job V2 for the time-series forecasting problem type.\n"]

type nonrec throughput_config_description = {
  provisioned_write_capacity_units : capacity_unit option;
      [@ocaml.doc
        " For provisioned feature groups, this indicates the write throughput you are billed for \
         and can consume without throttling. \n\n\
        \ This field is not applicable for on-demand feature groups. \n\
        \ "]
  provisioned_read_capacity_units : capacity_unit option;
      [@ocaml.doc
        " For provisioned feature groups with online store enabled, this indicates the read \
         throughput you are billed for and can consume without throttling. \n\n\
        \ This field is not applicable for on-demand feature groups. \n\
        \ "]
  throughput_mode : throughput_mode;
      [@ocaml.doc
        "The mode used for your feature group throughput: [ON_DEMAND] or [PROVISIONED]. \n"]
}
[@@ocaml.doc
  "Active throughput configuration of the feature group. There are two modes: [ON_DEMAND] and \
   [PROVISIONED]. With on-demand mode, you are charged for data reads and writes that your \
   application performs on your feature group. You do not need to specify read and write \
   throughput because Feature Store accommodates your workloads as they ramp up and down. You can \
   switch a feature group to on-demand only once in a 24 hour period. With provisioned throughput \
   mode, you specify the read and write capacity per second that you expect your application to \
   require, and you are billed based on those limits. Exceeding provisioned throughput will result \
   in your requests being throttled. \n\n\
  \ Note: [PROVISIONED] throughput mode is supported only for feature groups that are \
   offline-only, or use the \
   {{:https://docs.aws.amazon.com/sagemaker/latest/APIReference/API_OnlineStoreConfig.html#sagemaker-Type-OnlineStoreConfig-StorageType} \
   [Standard] } tier online store. \n\
  \ "]

type nonrec throughput_config = {
  provisioned_write_capacity_units : capacity_unit option;
      [@ocaml.doc
        " For provisioned feature groups, this indicates the write throughput you are billed for \
         and can consume without throttling. \n\n\
        \ This field is not applicable for on-demand feature groups. \n\
        \ "]
  provisioned_read_capacity_units : capacity_unit option;
      [@ocaml.doc
        " For provisioned feature groups with online store enabled, this indicates the read \
         throughput you are billed for and can consume without throttling. \n\n\
        \ This field is not applicable for on-demand feature groups. \n\
        \ "]
  throughput_mode : throughput_mode;
      [@ocaml.doc
        "The mode used for your feature group throughput: [ON_DEMAND] or [PROVISIONED]. \n"]
}
[@@ocaml.doc
  "Used to set feature group throughput configuration. There are two modes: [ON_DEMAND] and \
   [PROVISIONED]. With on-demand mode, you are charged for data reads and writes that your \
   application performs on your feature group. You do not need to specify read and write \
   throughput because Feature Store accommodates your workloads as they ramp up and down. You can \
   switch a feature group to on-demand only once in a 24 hour period. With provisioned throughput \
   mode, you specify the read and write capacity per second that you expect your application to \
   require, and you are billed based on those limits. Exceeding provisioned throughput will result \
   in your requests being throttled. \n\n\
  \ Note: [PROVISIONED] throughput mode is supported only for feature groups that are \
   offline-only, or use the \
   {{:https://docs.aws.amazon.com/sagemaker/latest/APIReference/API_OnlineStoreConfig.html#sagemaker-Type-OnlineStoreConfig-StorageType} \
   [Standard] } tier online store. \n\
  \ "]

