type nonrec text_generation_job_config = {
  model_access_config : model_access_config option; [@ocaml.doc ""]
  text_generation_hyper_parameters : text_generation_hyper_parameters option;
      [@ocaml.doc
        "The hyperparameters used to configure and optimize the learning process of the base \
         model. You can set any combination of the following hyperparameters for all base models. \
         For more information on each supported hyperparameter, see \
         {{:https://docs.aws.amazon.com/sagemaker/latest/dg/autopilot-llms-finetuning-set-hyperparameters.html}Optimize \
         the learning process of your text generation models with hyperparameters}.\n\n\
        \ {ul\n\
        \       {-   [\"epochCount\"]: The number of times the model goes through the entire \
         training dataset. Its value should be a string containing an integer value within the \
         range of \"1\" to \"10\".\n\
        \           \n\
        \            }\n\
        \       {-   [\"batchSize\"]: The number of data samples used in each iteration of \
         training. Its value should be a string containing an integer value within the range of \
         \"1\" to \"64\".\n\
        \           \n\
        \            }\n\
        \       {-   [\"learningRate\"]: The step size at which a model's parameters are updated \
         during training. Its value should be a string containing a floating-point value within \
         the range of \"0\" to \"1\".\n\
        \           \n\
        \            }\n\
        \       {-   [\"learningRateWarmupSteps\"]: The number of training steps during which the \
         learning rate gradually increases before reaching its target or maximum value. Its value \
         should be a string containing an integer value within the range of \"0\" to \"250\".\n\
        \           \n\
        \            }\n\
        \       }\n\
        \   Here is an example where all four hyperparameters are configured.\n\
        \   \n\
        \     [{ \"epochCount\":\"5\", \"learningRate\":\"0.5\", \"batchSize\": \"32\", \
         \"learningRateWarmupSteps\": \"10\" }] \n\
        \    "]
  base_model_name : base_model_name option;
      [@ocaml.doc
        "The name of the base model to fine-tune. Autopilot supports fine-tuning a variety of \
         large language models. For information on the list of supported models, see \
         {{:https://docs.aws.amazon.com/sagemaker/latest/dg/autopilot-llms-finetuning-models.html#autopilot-llms-finetuning-supported-llms}Text \
         generation models supporting fine-tuning in Autopilot}. If no [BaseModelName] is \
         provided, the default model used is {b Falcon7BInstruct}. \n"]
  completion_criteria : auto_ml_job_completion_criteria option;
      [@ocaml.doc
        "How long a fine-tuning job is allowed to run. For [TextGenerationJobConfig] problem \
         types, the [MaxRuntimePerTrainingJobInSeconds] attribute of [AutoMLJobCompletionCriteria] \
         defaults to 72h (259200s).\n"]
}
[@@ocaml.doc
  "The collection of settings used by an AutoML job V2 for the text generation problem type.\n\n\
  \  The text generation models that support fine-tuning in Autopilot are currently accessible \
   exclusively in regions supported by Canvas. Refer to the documentation of Canvas for the \
   {{:https://docs.aws.amazon.com/sagemaker/latest/dg/canvas.html}full list of its supported \
   Regions}.\n\
  \  \n\
  \   "]

