type nonrec tabular_job_config = {
  sample_weight_attribute_name : sample_weight_attribute_name option;
      [@ocaml.doc
        "If specified, this column name indicates which column of the dataset should be treated as \
         sample weights for use by the objective metric during the training, evaluation, and the \
         selection of the best model. This column is not considered as a predictive feature. For \
         more information on Autopilot metrics, see \
         {{:https://docs.aws.amazon.com/sagemaker/latest/dg/autopilot-metrics-validation.html}Metrics \
         and validation}.\n\n\
        \ Sample weights should be numeric, non-negative, with larger values indicating which rows \
         are more important than others. Data points that have invalid or no weight value are \
         excluded.\n\
        \ \n\
        \  Support for sample weights is available in \
         {{:https://docs.aws.amazon.com/sagemaker/latest/APIReference/API_AutoMLAlgorithmConfig.html}Ensembling} \
         mode only.\n\
        \  "]
  target_attribute_name : target_attribute_name;
      [@ocaml.doc
        "The name of the target variable in supervised learning, usually represented by 'y'.\n"]
  problem_type : problem_type option;
      [@ocaml.doc
        "The type of supervised learning problem available for the model candidates of the AutoML \
         job V2. For more information, see \
         {{:https://docs.aws.amazon.com/sagemaker/latest/dg/autopilot-datasets-problem-types.html#autopilot-problem-types} \
         SageMaker Autopilot problem types}.\n\n\
        \  You must either specify the type of supervised learning problem in [ProblemType] and \
         provide the \
         {{:https://docs.aws.amazon.com/sagemaker/latest/APIReference/API_CreateAutoMLJobV2.html#sagemaker-CreateAutoMLJobV2-request-AutoMLJobObjective}AutoMLJobObjective} \
         metric, or none at all.\n\
        \  \n\
        \   "]
  generate_candidate_definitions_only : generate_candidate_definitions_only option;
      [@ocaml.doc
        "Generates possible candidates without training the models. A model candidate is a \
         combination of data preprocessors, algorithms, and algorithm parameter settings.\n"]
  mode : auto_ml_mode option;
      [@ocaml.doc
        "The method that Autopilot uses to train the data. You can either specify the mode \
         manually or let Autopilot choose for you based on the dataset size by selecting [AUTO]. \
         In [AUTO] mode, Autopilot chooses [ENSEMBLING] for datasets smaller than 100 MB, and \
         [HYPERPARAMETER_TUNING] for larger ones.\n\n\
        \ The [ENSEMBLING] mode uses a multi-stack ensemble model to predict classification and \
         regression tasks directly from your dataset. This machine learning mode combines several \
         base models to produce an optimal predictive model. It then uses a stacking ensemble \
         method to combine predictions from contributing members. A multi-stack ensemble model can \
         provide better performance over a single model by combining the predictive capabilities \
         of multiple models. See \
         {{:https://docs.aws.amazon.com/sagemaker/latest/dg/autopilot-model-support-validation.html#autopilot-algorithm-support}Autopilot \
         algorithm support} for a list of algorithms supported by [ENSEMBLING] mode.\n\
        \ \n\
        \  The [HYPERPARAMETER_TUNING] (HPO) mode uses the best hyperparameters to train the best \
         version of a model. HPO automatically selects an algorithm for the type of problem you \
         want to solve. Then HPO finds the best hyperparameters according to your objective \
         metric. See \
         {{:https://docs.aws.amazon.com/sagemaker/latest/dg/autopilot-model-support-validation.html#autopilot-algorithm-support}Autopilot \
         algorithm support} for a list of algorithms supported by [HYPERPARAMETER_TUNING] mode.\n\
        \  "]
  feature_specification_s3_uri : s3_uri option;
      [@ocaml.doc
        "A URL to the Amazon S3 data source containing selected features from the input data \
         source to run an Autopilot job V2. You can input [FeatureAttributeNames] (optional) in \
         JSON format as shown below: \n\n\
        \  [{ \"FeatureAttributeNames\":\\[\"col1\", \"col2\", ...\\] }].\n\
        \ \n\
        \  You can also specify the data type of the feature (optional) in the format shown below:\n\
        \  \n\
        \    [{ \"FeatureDataTypes\":{\"col1\":\"numeric\", \"col2\":\"categorical\" ... } }] \n\
        \   \n\
        \     These column keys may not include the target column.\n\
        \     \n\
        \       In ensembling mode, Autopilot only supports the following data types: [numeric], \
         [categorical], [text], and [datetime]. In HPO mode, Autopilot can support [numeric], \
         [categorical], [text], [datetime], and [sequence].\n\
        \       \n\
        \        If only [FeatureDataTypes] is provided, the column keys ([col1], [col2],..) \
         should be a subset of the column names in the input data. \n\
        \        \n\
        \         If both [FeatureDataTypes] and [FeatureAttributeNames] are provided, then the \
         column keys should be a subset of the column names provided in [FeatureAttributeNames]. \n\
        \         \n\
        \          The key name [FeatureAttributeNames] is fixed. The values listed in \
         [\\[\"col1\", \"col2\", ...\\]] are case sensitive and should be a list of strings \
         containing unique values that are a subset of the column names in the input data. The \
         list of columns provided must not include the target column.\n\
        \          "]
  completion_criteria : auto_ml_job_completion_criteria option; [@ocaml.doc ""]
  candidate_generation_config : candidate_generation_config option;
      [@ocaml.doc "The configuration information of how model candidates are generated.\n"]
}
[@@ocaml.doc "The collection of settings used by an AutoML job V2 for the tabular problem type.\n"]

