type nonrec search_training_plan_offerings_request = {
  training_plan_arn : string_ option;
      [@ocaml.doc
        "The Amazon Resource Name (ARN); of an existing training plan to search for extension \
         offerings. When specified, the API returns extension offerings that can be used to extend \
         the specified training plan.\n"]
  target_resources : sage_maker_resource_names option;
      [@ocaml.doc
        "The target resources (e.g., SageMaker Training Jobs, SageMaker HyperPod, SageMaker \
         Endpoints, Studio apps) to search for in the offerings.\n\n\
        \ Training plans are specific to their target resource.\n\
        \ \n\
        \  {ul\n\
        \        {-  A training plan designed for SageMaker training jobs can only be used to \
         schedule and run training jobs.\n\
        \            \n\
        \             }\n\
        \        {-  A training plan for HyperPod clusters can be used exclusively to provide \
         compute resources to a cluster's instance group.\n\
        \            \n\
        \             }\n\
        \        {-  A training plan for SageMaker endpoints can be used exclusively to provide \
         compute resources to SageMaker endpoints for model deployment.\n\
        \            \n\
        \             }\n\
        \        {-  A training plan for Studio apps can be used to launch JupyterLab and Code \
         Editor apps on reserved training plan capacity.\n\
        \            \n\
        \             }\n\
        \        }\n\
        \  "]
  duration_hours : training_plan_duration_hours_input option;
      [@ocaml.doc "The desired duration in hours for the training plan offerings.\n"]
  end_time_before : timestamp option;
      [@ocaml.doc
        "A filter to search for reserved capacity offerings with an end time before a specified \
         date.\n"]
  start_time_after : timestamp option;
      [@ocaml.doc
        "A filter to search for training plan offerings with a start time after a specified date.\n"]
  ultra_server_count : ultra_server_count option;
      [@ocaml.doc "The number of UltraServers to search for.\n"]
  ultra_server_type : ultra_server_type option;
      [@ocaml.doc "The type of UltraServer to search for, such as ml.u-p6e-gb200x72.\n"]
  instance_count : reserved_capacity_instance_count option;
      [@ocaml.doc
        "The number of instances you want to reserve in the training plan offerings. This allows \
         you to specify the quantity of compute resources needed for your SageMaker training jobs \
         or SageMaker HyperPod clusters, helping you find reserved capacity offerings that match \
         your requirements.\n"]
  instance_type : reserved_capacity_instance_type option;
      [@ocaml.doc
        "The type of instance you want to search for in the available training plan offerings. \
         This field allows you to filter the search results based on the specific compute \
         resources you require for your SageMaker training jobs or SageMaker HyperPod clusters. \
         When searching for training plan offerings, specifying the instance type helps you find \
         Reserved Instances that match your computational needs.\n"]
}
