type nonrec offline_store_config = {
  table_format : table_format option;
      [@ocaml.doc
        "Format for the offline store table. Supported formats are Glue (Default) and \
         {{:https://iceberg.apache.org/}Apache Iceberg}.\n"]
  data_catalog_config : data_catalog_config option;
      [@ocaml.doc
        "The meta data of the Glue table for the [OfflineStore]. If not provided, Feature Store \
         auto-generates the table name, database, and catalog when the [OfflineStore] is created. \
         You can optionally provide this configuration to specify custom values. This applies to \
         both Glue and Apache Iceberg table formats.\n"]
  disable_glue_table_creation : boolean_ option;
      [@ocaml.doc
        "Set to [True] to disable the automatic creation of an Amazon Web Services Glue table when \
         configuring an [OfflineStore]. If set to [True] and [DataCatalogConfig] is provided, \
         Feature Store associates the provided catalog configuration with the feature group \
         without creating a table. In this case, you are responsible for creating and managing the \
         Glue table. If set to [True] without [DataCatalogConfig], no Glue table is created or \
         associated with the feature group. The [Iceberg] table format is only supported when this \
         is set to [False].\n\n\
        \ If set to [False] and [DataCatalogConfig] is provided, Feature Store creates the table \
         using the specified names. If set to [False] without [DataCatalogConfig], Feature Store \
         auto-generates the table name following \
         {{:https://docs.aws.amazon.com/athena/latest/ug/tables-databases-columns-names.html}Athena's \
         naming recommendations}. This applies to both Glue and Apache Iceberg table formats.\n\
        \ \n\
        \  The default value is [False].\n\
        \  "]
  s3_storage_config : s3_storage_config;
      [@ocaml.doc "The Amazon Simple Storage (Amazon S3) location of [OfflineStore].\n"]
}
