type nonrec hyper_parameter_tuning_job_strategy_type =
  | GRID [@ocaml.doc ""]
  | HYPERBAND [@ocaml.doc ""]
  | RANDOM [@ocaml.doc ""]
  | BAYESIAN [@ocaml.doc ""]
[@@ocaml.doc
  "The strategy hyperparameter tuning uses to find the best combination of hyperparameters for \
   your model. \n"]

type nonrec hyperband_strategy_min_resource = int [@@ocaml.doc ""]

type nonrec hyperband_strategy_max_resource = int [@@ocaml.doc ""]

type nonrec hyperband_strategy_config = {
  max_resource : hyperband_strategy_max_resource option;
      [@ocaml.doc
        "The maximum number of resources (such as epochs) that can be used by a training job \
         launched by a hyperparameter tuning job. Once a job reaches the [MaxResource] value, it \
         is stopped. If a value for [MaxResource] is not provided, and [Hyperband] is selected as \
         the hyperparameter tuning strategy, [HyperbandTraining] attempts to infer [MaxResource] \
         from the following keys (if present) in \
         {{:https://docs.aws.amazon.com/sagemaker/latest/APIReference/API_HyperParameterTrainingJobDefinition.html#sagemaker-Type-HyperParameterTrainingJobDefinition-StaticHyperParameters}StaticsHyperParameters}:\n\n\
        \ {ul\n\
        \       {-   [epochs] \n\
        \           \n\
        \            }\n\
        \       {-   [numepochs] \n\
        \           \n\
        \            }\n\
        \       {-   [n-epochs] \n\
        \           \n\
        \            }\n\
        \       {-   [n_epochs] \n\
        \           \n\
        \            }\n\
        \       {-   [num_epochs] \n\
        \           \n\
        \            }\n\
        \       }\n\
        \   If [HyperbandStrategyConfig] is unable to infer a value for [MaxResource], it \
         generates a validation error. The maximum value is 20,000 epochs. All metrics that \
         correspond to an objective metric are used to derive \
         {{:https://docs.aws.amazon.com/sagemaker/latest/dg/automatic-model-tuning-early-stopping.html}early \
         stopping decisions}. For \
         {{:https://docs.aws.amazon.com/sagemaker/latest/dg/distributed-training.html}distributed} \
         training jobs, ensure that duplicate metrics are not printed in the logs across the \
         individual nodes in a training job. If multiple nodes are publishing duplicate or \
         incorrect metrics, training jobs may make an incorrect stopping decision and stop the job \
         prematurely. \n\
        \   "]
  min_resource : hyperband_strategy_min_resource option;
      [@ocaml.doc
        "The minimum number of resources (such as epochs) that can be used by a training job \
         launched by a hyperparameter tuning job. If the value for [MinResource] has not been \
         reached, the training job is not stopped by [Hyperband].\n"]
}
[@@ocaml.doc
  "The configuration for [Hyperband], a multi-fidelity based hyperparameter tuning strategy. \
   [Hyperband] uses the final and intermediate results of a training job to dynamically allocate \
   resources to utilized hyperparameter configurations while automatically stopping \
   under-performing configurations. This parameter should be provided only if [Hyperband] is \
   selected as the [StrategyConfig] under the [HyperParameterTuningJobConfig] API.\n"]

type nonrec hyper_parameter_tuning_job_strategy_config = {
  hyperband_strategy_config : hyperband_strategy_config option;
      [@ocaml.doc
        "The configuration for the object that specifies the [Hyperband] strategy. This parameter \
         is only supported for the [Hyperband] selection for [Strategy] within the \
         [HyperParameterTuningJobConfig] API.\n"]
}
[@@ocaml.doc
  "The configuration for a training job launched by a hyperparameter tuning job. Choose [Bayesian] \
   for Bayesian optimization, and [Random] for random search optimization. For more advanced use \
   cases, use [Hyperband], which evaluates objective metrics for training jobs after every epoch. \
   For more information about strategies, see \
   {{:https://docs.aws.amazon.com/sagemaker/latest/dg/automatic-model-tuning-how-it-works.html}How \
   Hyperparameter Tuning Works}.\n"]

