  | LINEAR [@ocaml.doc ""]
  | AUTO [@ocaml.doc ""]
[@@ocaml.doc ""]

type nonrec integer_parameter_range = {
  scaling_type : hyper_parameter_scaling_type option;
      [@ocaml.doc
        "The scale that hyperparameter tuning uses to search the hyperparameter range. For \
         information about choosing a hyperparameter scale, see \
         {{:https://docs.aws.amazon.com/sagemaker/latest/dg/automatic-model-tuning-define-ranges.html#scaling-type}Hyperparameter \
         Scaling}. One of the following values:\n\n\
        \  Auto  SageMaker hyperparameter tuning chooses the best scale for the hyperparameter.\n\
        \        \n\
        \          Linear  Hyperparameter tuning searches the values in the hyperparameter range \
         by using a linear scale.\n\
        \                  \n\
        \                    Logarithmic  Hyperparameter tuning searches the values in the \
         hyperparameter range by using a logarithmic scale.\n\
        \                                 \n\
        \                                  Logarithmic scaling works only for ranges that have \
         only values greater than 0.\n\
        \                                  \n\
        \                                    "]
  max_value : parameter_value; [@ocaml.doc "The maximum value of the hyperparameter to search.\n"]
  min_value : parameter_value; [@ocaml.doc "The minimum value of the hyperparameter to search.\n"]
  name : parameter_key; [@ocaml.doc "The name of the hyperparameter to search.\n"]
}
[@@ocaml.doc
  "For a hyperparameter of the integer type, specifies the range that a hyperparameter tuning job \
   searches.\n"]

type nonrec integer_parameter_ranges = integer_parameter_range list [@@ocaml.doc ""]

type nonrec continuous_parameter_range = {
  scaling_type : hyper_parameter_scaling_type option;
      [@ocaml.doc
        "The scale that hyperparameter tuning uses to search the hyperparameter range. For \
         information about choosing a hyperparameter scale, see \
         {{:https://docs.aws.amazon.com/sagemaker/latest/dg/automatic-model-tuning-define-ranges.html#scaling-type}Hyperparameter \
         Scaling}. One of the following values:\n\n\
        \  Auto  SageMaker hyperparameter tuning chooses the best scale for the hyperparameter.\n\
        \        \n\
        \          Linear  Hyperparameter tuning searches the values in the hyperparameter range \
         by using a linear scale.\n\
        \                  \n\
        \                    Logarithmic  Hyperparameter tuning searches the values in the \
         hyperparameter range by using a logarithmic scale.\n\
        \                                 \n\
        \                                  Logarithmic scaling works only for ranges that have \
         only values greater than 0.\n\
        \                                  \n\
        \                                    ReverseLogarithmic  Hyperparameter tuning searches \
         the values in the hyperparameter range by using a reverse logarithmic scale.\n\
        \                                                        \n\
        \                                                         Reverse logarithmic scaling \
         works only for ranges that are entirely within the range 0<=x<1.0.\n\
        \                                                         \n\
        \                                                           "]
  max_value : parameter_value;
      [@ocaml.doc
        "The maximum value for the hyperparameter. The tuning job uses floating-point values \
         between [MinValue] value and this value for tuning.\n"]
  min_value : parameter_value;
      [@ocaml.doc
        "The minimum value for the hyperparameter. The tuning job uses floating-point values \
         between this value and [MaxValue]for tuning.\n"]
  name : parameter_key; [@ocaml.doc "The name of the continuous hyperparameter to tune.\n"]
}
[@@ocaml.doc "A list of continuous hyperparameters to tune.\n"]

