type nonrec objective_status_counters = {
  failed : objective_status_counter option;
      [@ocaml.doc
        "The number of training jobs whose final objective metric was not evaluated and used in \
         the hyperparameter tuning process. This typically occurs when the training job failed or \
         did not emit an objective metric.\n"]
  pending : objective_status_counter option;
      [@ocaml.doc
        "The number of training jobs that are in progress and pending evaluation of their final \
         objective metric.\n"]
  succeeded : objective_status_counter option;
      [@ocaml.doc
        "The number of training jobs whose final objective metric was evaluated by the \
         hyperparameter tuning job and used in the hyperparameter tuning process.\n"]
}
[@@ocaml.doc
  "Specifies the number of training jobs that this hyperparameter tuning job launched, categorized \
   by the status of their objective metric. The objective metric status shows whether the final \
   objective metric for the training job has been evaluated by the tuning job and used in the \
   hyperparameter tuning process.\n"]

type nonrec metric_value = float [@@ocaml.doc ""]

type nonrec final_hyper_parameter_tuning_job_objective_metric = {
  value : metric_value; [@ocaml.doc "The value of the objective metric.\n"]
  metric_name : metric_name;
      [@ocaml.doc
        "The name of the objective metric. For SageMaker built-in algorithms, metrics are defined \
         per algorithm. See the \
         {{:https://docs.aws.amazon.com/sagemaker/latest/dg/xgboost-tuning.html}metrics for \
         XGBoost} as an example. You can also use a custom algorithm for training and define your \
         own metrics. For more information, see \
         {{:https://docs.aws.amazon.com/sagemaker/latest/dg/automatic-model-tuning-define-metrics-variables.html}Define \
         metrics and environment variables}.\n"]
  type_ : hyper_parameter_tuning_job_objective_type option;
      [@ocaml.doc
        "Select if you want to minimize or maximize the objective metric during hyperparameter \
         tuning. \n"]
}
[@@ocaml.doc
  "Shows the latest objective metric emitted by a training job that was launched by a \
   hyperparameter tuning job. You define the objective metric in the \
   [HyperParameterTuningJobObjective] parameter of \
   {{:https://docs.aws.amazon.com/sagemaker/latest/APIReference/API_HyperParameterTuningJobConfig.html}HyperParameterTuningJobConfig}.\n"]

type nonrec objective_status =
  | Failed [@ocaml.doc ""]
  | Pending [@ocaml.doc ""]
  | Succeeded [@ocaml.doc ""]
[@@ocaml.doc ""]

type nonrec hyper_parameter_training_job_summary = {
  objective_status : objective_status option;
      [@ocaml.doc
        "The status of the objective metric for the training job:\n\n\
        \ {ul\n\
        \       {-  Succeeded: The final objective metric for the training job was evaluated by \
         the hyperparameter tuning job and used in the hyperparameter tuning process.\n\
        \           \n\
        \            }\n\
        \       }\n\
        \   {ul\n\
        \         {-  Pending: The training job is in progress and evaluation of its final \
         objective metric is pending.\n\
        \             \n\
        \              }\n\
        \         }\n\
        \   {ul\n\
        \         {-  Failed: The final objective metric for the training job was not evaluated, \
         and was not used in the hyperparameter tuning process. This typically occurs when the \
         training job failed or did not emit an objective metric.\n\
        \             \n\
        \              }\n\
        \         }\n\
        \  "]
  final_hyper_parameter_tuning_job_objective_metric :
    final_hyper_parameter_tuning_job_objective_metric option;
      [@ocaml.doc
        "The \
         {{:https://docs.aws.amazon.com/sagemaker/latest/APIReference/API_FinalHyperParameterTuningJobObjectiveMetric.html}FinalHyperParameterTuningJobObjectiveMetric} \
         object that specifies the value of the objective metric of the tuning job that launched \
         this training job.\n"]
  failure_reason : failure_reason option; [@ocaml.doc "The reason that the training job failed. \n"]
  tuned_hyper_parameters : hyper_parameters;
      [@ocaml.doc "A list of the hyperparameters for which you specified ranges to search.\n"]
  training_job_status : training_job_status; [@ocaml.doc "The status of the training job.\n"]
  training_end_time : timestamp option;
      [@ocaml.doc
        "Specifies the time when the training job ends on training instances. You are billed for \
         the time interval between the value of [TrainingStartTime] and this time. For successful \
         jobs and stopped jobs, this is the time after model artifacts are uploaded. For failed \
         jobs, this is the time when SageMaker detects a job failure.\n"]
  training_start_time : timestamp option;
      [@ocaml.doc "The date and time that the training job started.\n"]
  creation_time : timestamp; [@ocaml.doc "The date and time that the training job was created.\n"]
  tuning_job_name : hyper_parameter_tuning_job_name option;
      [@ocaml.doc "The HyperParameter tuning job that launched the training job.\n"]
  training_job_arn : training_job_arn;
      [@ocaml.doc "The Amazon Resource Name (ARN) of the training job.\n"]
  training_job_name : training_job_name; [@ocaml.doc "The name of the training job.\n"]
  training_job_definition_name : hyper_parameter_training_job_definition_name option;
      [@ocaml.doc "The training job definition name.\n"]
}
[@@ocaml.doc "The container for the summary information about a training job.\n"]

type nonrec parent_hyper_parameter_tuning_job = {
  hyper_parameter_tuning_job_name : hyper_parameter_tuning_job_name option;
      [@ocaml.doc
        "The name of the hyperparameter tuning job to be used as a starting point for a new \
