  created_by : user_context option; [@ocaml.doc ""]
  creation_time : timestamp option;
      [@ocaml.doc "The date and time that the model card was created.\n"]
  security_config : model_card_security_config option;
      [@ocaml.doc "The security configuration used to protect model card data.\n"]
  model_card_status : model_card_status option;
      [@ocaml.doc
        "The approval status of the model card within your organization. Different organizations \
         might have different criteria for model card review and approval.\n\n\
