type nonrec multi_model_config = {
  model_cache_setting : model_cache_setting option;
      [@ocaml.doc
        "Whether to cache models for a multi-model endpoint. By default, multi-model endpoints \
         cache models so that a model does not have to be loaded into memory each time it is \
         invoked. Some use cases do not benefit from model caching. For example, if an endpoint \
         hosts a large number of models that are each invoked infrequently, the endpoint might \
         perform better if you disable model caching. To disable model caching, set the value of \
         this parameter to [Disabled].\n"]
}
[@@ocaml.doc "Specifies additional configuration for hosting multi-model endpoints.\n"]

type nonrec container_definition = {
  container_metrics_config : container_metrics_config option;
      [@ocaml.doc
        "The configuration for container metrics scraping. Specifies the metrics endpoint path and \
         publishing frequency. If not specified when [EnableDetailedObservability] is [True], the \
         default path [/metrics] on port [8080] is used. For first-party and Deep Learning \
         Containers (DLC), the endpoint path is determined automatically and this configuration is \
         optional.\n"]
  multi_model_config : multi_model_config option;
      [@ocaml.doc "Specifies additional configuration for multi-model endpoints.\n"]
  inference_specification_name : inference_specification_name option;
      [@ocaml.doc "The inference specification name in the model package version.\n"]
  model_package_name : versioned_arn_or_name option;
      [@ocaml.doc
        "The name or Amazon Resource Name (ARN) of the model package to use to create the model.\n"]
  environment : environment_map option;
      [@ocaml.doc
        "The environment variables to set in the Docker container. Don't include any sensitive \
         data in your environment variables.\n\n\
        \ The maximum length of each key and value in the [Environment] map is 1024 bytes. The \
         maximum length of all keys and values in the map, combined, is 32 KB. If you pass \
         multiple containers to a [CreateModel] request, then the maximum length of all of their \
         maps, combined, is also 32 KB.\n\
        \ "]
  additional_model_data_sources : additional_model_data_sources option;
      [@ocaml.doc
        "Data sources that are available to your model in addition to the one that you specify for \
         [ModelDataSource] when you use the [CreateModel] action.\n"]
  model_data_source : model_data_source option;
      [@ocaml.doc
        "Specifies the location of ML model data to deploy.\n\n\
        \  Currently you cannot use [ModelDataSource] in conjunction with SageMaker batch \
         transform, SageMaker serverless endpoints, SageMaker multi-model endpoints, and SageMaker \
         Marketplace.\n\
        \  \n\
        \   "]
  model_data_url : url option;
      [@ocaml.doc
        "The S3 path where the model artifacts, which result from model training, are stored. This \
         path must point to a single gzip compressed tar archive (.tar.gz suffix). The S3 path is \
         required for SageMaker built-in algorithms, but not if you use your own algorithms. For \
         more information on built-in algorithms, see \
         {{:https://docs.aws.amazon.com/sagemaker/latest/dg/sagemaker-algo-docker-registry-paths.html}Common \
         Parameters}. \n\n\
        \  The model artifacts must be in an S3 bucket that is in the same region as the model or \
         endpoint you are creating.\n\
        \  \n\
        \    If you provide a value for this parameter, SageMaker uses Amazon Web Services \
         Security Token Service to download model artifacts from the S3 path you provide. Amazon \
         Web Services STS is activated in your Amazon Web Services account by default. If you \
         previously deactivated Amazon Web Services STS for a region, you need to reactivate \
         Amazon Web Services STS for that region. For more information, see \
         {{:https://docs.aws.amazon.com/IAM/latest/UserGuide/id_credentials_temp_enable-regions.html}Activating \
         and Deactivating Amazon Web Services STS in an Amazon Web Services Region} in the {i \
         Amazon Web Services Identity and Access Management User Guide}.\n\
        \    \n\
        \      If you use a built-in algorithm to create a model, SageMaker requires that you \
         provide a S3 path to the model artifacts in [ModelDataUrl].\n\
        \      \n\
        \       "]
  mode : container_mode option;
      [@ocaml.doc "Whether the container hosts a single model or multiple models.\n"]
  image_config : image_config option;
      [@ocaml.doc
        "Specifies whether the model container is in Amazon ECR or a private Docker registry \
         accessible from your Amazon Virtual Private Cloud (VPC). For information about storing \
         containers in a private Docker registry, see \
         {{:https://docs.aws.amazon.com/sagemaker/latest/dg/your-algorithms-containers-inference-private.html}Use \
         a Private Docker Registry for Real-Time Inference Containers}. \n\n\
        \  The model artifacts in an Amazon S3 bucket and the Docker image for inference container \
         in Amazon EC2 Container Registry must be in the same region as the model or endpoint you \
         are creating.\n\
        \  \n\
        \   "]
  image : container_image option;
      [@ocaml.doc
        "The path where inference code is stored. This can be either in Amazon EC2 Container \
         Registry or in a Docker registry that is accessible from the same VPC that you configure \
         for your endpoint. If you are using your own custom algorithm instead of an algorithm \
         provided by SageMaker, the inference code must meet SageMaker requirements. SageMaker \
         supports both [registry/repository\\[:tag\\]] and [registry/repository\\[@digest\\]] \
         image path formats. For more information, see \
         {{:https://docs.aws.amazon.com/sagemaker/latest/dg/your-algorithms.html}Using Your Own \
         Algorithms with Amazon SageMaker}. \n\n\
        \  The model artifacts in an Amazon S3 bucket and the Docker image for inference container \
         in Amazon EC2 Container Registry must be in the same region as the model or endpoint you \
         are creating.\n\
        \  \n\
        \   "]
  container_hostname : container_hostname option;
      [@ocaml.doc
        "This parameter is ignored for models that contain only a [PrimaryContainer].\n\n\
        \ When a [ContainerDefinition] is part of an inference pipeline, the value of the \
         parameter uniquely identifies the container for the purposes of logging and metrics. For \
         information, see \
         {{:https://docs.aws.amazon.com/sagemaker/latest/dg/inference-pipeline-logs-metrics.html}Use \
         Logs and Metrics to Monitor an Inference Pipeline}. If you don't specify a value for this \
         parameter for a [ContainerDefinition] that is part of an inference pipeline, a unique \
         name is automatically assigned based on the position of the [ContainerDefinition] in the \
         pipeline. If you specify a value for the [ContainerHostName] for any \
         [ContainerDefinition] that is part of an inference pipeline, you must specify a value for \
         the [ContainerHostName] parameter of every [ContainerDefinition] in that pipeline.\n\
        \ "]
}
[@@ocaml.doc "Describes the container, as part of model definition.\n"]

