type nonrec filter = {
  value : filter_value option;
      [@ocaml.doc
        "A value used with [Name] and [Operator] to determine which resources satisfy the filter's \
         condition. For numerical properties, [Value] must be an integer or floating-point \
         decimal. For timestamp properties, [Value] must be an ISO 8601 date-time string of the \
         following format: [YYYY-mm-dd'T'HH:MM:SS].\n"]
  operator : operator option;
      [@ocaml.doc
        "A Boolean binary operator that is used to evaluate the filter. The operator field \
         contains one of the following values:\n\n\
        \  Equals  The value of [Name] equals [Value].\n\
        \          \n\
        \            NotEquals  The value of [Name] doesn't equal [Value].\n\
        \                       \n\
        \                         Exists  The [Name] property exists.\n\
        \                                 \n\
        \                                   NotExists  The [Name] property does not exist.\n\
        \                                              \n\
        \                                                GreaterThan  The value of [Name] is \
         greater than [Value]. Not supported for text properties.\n\
        \                                                             \n\
        \                                                               GreaterThanOrEqualTo  \n\
         The value of [Name] is greater than or equal to [Value]. Not supported for text \
         properties.\n\n\
        \  LessThan  The value of [Name] is less than [Value]. Not supported for text properties.\n\
        \            \n\
        \              LessThanOrEqualTo  The value of [Name] is less than or equal to [Value]. \
         Not supported for text properties.\n\
        \                                 \n\
        \                                   In  The value of [Name] is one of the comma delimited \
         strings in [Value]. Only supported for text properties.\n\
        \                                       \n\
        \                                         Contains  The value of [Name] contains the \
         string [Value]. Only supported for text properties.\n\
        \                                                   \n\
        \                                                    A [SearchExpression] can include the \
         [Contains] operator multiple times when the value of [Name] is one of the following:\n\
        \                                                    \n\
        \                                                     {ul\n\
        \                                                           {-   [Experiment.DisplayName] \n\
        \                                                               \n\
        \                                                                }\n\
        \                                                           {-   \
         [Experiment.ExperimentName] \n\
        \                                                               \n\
        \                                                                }\n\
        \                                                           {-   [Experiment.Tags] \n\
        \                                                               \n\
        \                                                                }\n\
        \                                                           {-   [Trial.DisplayName] \n\
        \                                                               \n\
        \                                                                }\n\
        \                                                           {-   [Trial.TrialName] \n\
        \                                                               \n\
        \                                                                }\n\
        \                                                           {-   [Trial.Tags] \n\
        \                                                               \n\
        \                                                                }\n\
        \                                                           {-   \
         [TrialComponent.DisplayName] \n\
        \                                                               \n\
        \                                                                }\n\
        \                                                           {-   \
         [TrialComponent.TrialComponentName] \n\
        \                                                               \n\
        \                                                                }\n\
        \                                                           {-   [TrialComponent.Tags] \n\
        \                                                               \n\
        \                                                                }\n\
        \                                                           {-   \
         [TrialComponent.InputArtifacts] \n\
        \                                                               \n\
        \                                                                }\n\
        \                                                           {-   \
         [TrialComponent.OutputArtifacts] \n\
        \                                                               \n\
        \                                                                }\n\
        \                                                           }\n\
        \   A [SearchExpression] can include only one [Contains] operator for all other values of \
         [Name]. In these cases, if you include multiple [Contains] operators in the \
         [SearchExpression], the result is the following error message: \"['CONTAINS' operator \
         usage limit of 1 exceeded.]\"\n\
        \   \n\
        \     "]
  name : resource_property_name;
      [@ocaml.doc
        "A resource property name. For example, [TrainingJobName]. For valid property names, see \
         {{:https://docs.aws.amazon.com/sagemaker/latest/APIReference/API_SearchRecord.html}SearchRecord}. \
         You must specify a valid property for the resource.\n"]
}
[@@ocaml.doc
  "A conditional statement for a search expression that includes a resource property, a Boolean \
   operator, and a value. Resources that match the statement are returned in the results from the \
   {{:https://docs.aws.amazon.com/sagemaker/latest/APIReference/API_Search.html}Search} API.\n\n\
  \ If you specify a [Value], but not an [Operator], SageMaker uses the equals operator.\n\
  \ \n\
  \  In search, there are several property types:\n\
  \  \n\
  \    Metrics  To define a metric filter, enter a value using the form [\"Metrics.<name>\"], \
   where [<name>] is a metric name. For example, the following filter searches for training jobs \
   with an [\"accuracy\"] metric greater than [\"0.9\"]:\n\
  \             \n\
  \               [{] \n\
  \              \n\
  \                [\"Name\": \"Metrics.accuracy\",] \n\
  \               \n\
  \                 [\"Operator\": \"GreaterThan\",] \n\
  \                \n\
  \                  [\"Value\": \"0.9\"] \n\
  \                 \n\
  \                   [}] \n\
  \                  \n\
  \                    HyperParameters  To define a hyperparameter filter, enter a value with the \
   form [\"HyperParameters.<name>\"]. Decimal hyperparameter values are treated as a decimal in a \
   comparison if the specified [Value] is also a decimal value. If the specified [Value] is an \
   integer, the decimal hyperparameter values are treated as integers. For example, the following \
   filter is satisfied by training jobs with a [\"learning_rate\"] hyperparameter that is less \
   than [\"0.5\"]:\n\
  \                                     \n\
  \                                       [ {] \n\
  \                                      \n\
  \                                        [ \"Name\": \"HyperParameters.learning_rate\",] \n\
  \                                       \n\
  \                                         [ \"Operator\": \"LessThan\",] \n\
  \                                        \n\
  \                                          [ \"Value\": \"0.5\"] \n\
  \                                         \n\
  \                                           [ }] \n\
  \                                          \n\
  \                                            Tags  To define a tag filter, enter a value with \
   the form [Tags.<key>].\n\
  \                                                  \n\
  \                                                    "]

