type nonrec labeling_job_output_config = {
  sns_topic_arn : sns_topic_arn option;
      [@ocaml.doc
        "An Amazon Simple Notification Service (Amazon SNS) output topic ARN. Provide a \
         [SnsTopicArn] if you want to do real time chaining to another streaming job and receive \
         an Amazon SNS notifications each time a data object is submitted by a worker.\n\n\
        \ If you provide an [SnsTopicArn] in [OutputConfig], when workers complete labeling tasks, \
         Ground Truth will send labeling task output data to the SNS output topic you specify \
         here. \n\
        \ \n\
        \  To learn more, see \
         {{:https://docs.aws.amazon.com/sagemaker/latest/dg/sms-streaming-labeling-job.html#sms-streaming-how-it-works-output-data}Receive \
         Output Data from a Streaming Labeling Job}. \n\
        \  "]
  kms_key_id : kms_key_id option;
      [@ocaml.doc
        "The Amazon Web Services Key Management Service ID of the key used to encrypt the output \
         data, if any.\n\n\
        \ If you provide your own KMS key ID, you must add the required permissions to your KMS \
         key described in \
         {{:https://docs.aws.amazon.com/sagemaker/latest/dg/sms-security-permission.html#sms-security-kms-permissions}Encrypt \
         Output Data and Storage Volume with Amazon Web Services KMS}.\n\
        \ \n\
        \  If you don't provide a KMS key ID, Amazon SageMaker uses the default Amazon Web \
         Services KMS key for Amazon S3 for your role's account to encrypt your output data.\n\
        \  \n\
        \   If you use a bucket policy with an [s3:PutObject] permission that only allows objects \
         with server-side encryption, set the condition key of [s3:x-amz-server-side-encryption] \
         to [\"aws:kms\"]. For more information, see \
         {{:https://docs.aws.amazon.com/AmazonS3/latest/dev/UsingKMSEncryption.html}KMS-Managed \
         Encryption Keys} in the {i Amazon Simple Storage Service Developer Guide.} \n\
        \   "]
  s3_output_path : s3_uri; [@ocaml.doc "The Amazon S3 location to write output data.\n"]
}
[@@ocaml.doc "Output configuration information for a labeling job.\n"]

