type nonrec labeling_job_resource_config = {
  vpc_config : vpc_config option; [@ocaml.doc ""]
  volume_kms_key_id : kms_key_id option;
      [@ocaml.doc
        "The Amazon Web Services Key Management Service (Amazon Web Services KMS) key that Amazon \
         SageMaker uses to encrypt data on the storage volume attached to the ML compute \
         instance(s) that run the training and inference jobs used for automated data labeling. \n\n\
        \ You can only specify a [VolumeKmsKeyId] when you create a labeling job with automated \
         data labeling enabled using the API operation [CreateLabelingJob]. You cannot specify an \
         Amazon Web Services KMS key to encrypt the storage volume used for automated data \
         labeling model training and inference when you create a labeling job using the console. \
         To learn more, see \
         {{:https://docs.aws.amazon.com/sagemaker/latest/dg/sms-security.html}Output Data and \
         Storage Volume Encryption}.\n\
        \ \n\
        \  The [VolumeKmsKeyId] can be any of the following formats:\n\
        \  \n\
        \   {ul\n\
        \         {-  KMS Key ID\n\
        \             \n\
        \               [\"1234abcd-12ab-34cd-56ef-1234567890ab\"] \n\
        \              \n\
        \               }\n\
        \         {-  Amazon Resource Name (ARN) of a KMS Key\n\
        \             \n\
        \               \
         [\"arn:aws:kms:us-west-2:111122223333:key/1234abcd-12ab-34cd-56ef-1234567890ab\"] \n\
        \              \n\
        \               }\n\
        \         }\n\
        \  "]
}
[@@ocaml.doc
  "Configure encryption on the storage volume attached to the ML compute instance used to run \
   automated data labeling model training and inference. \n"]

