         must select one of the following ARNs:\n\n\
        \ {ul\n\
        \       {-   {i Image classification} \n\
        \           \n\
        \             \n\
        \            {[\n\
        \            arn:aws:sagemaker:{i \
         region}:027400017018:labeling-job-algorithm-specification/image-classification\n\
        \            ]}\n\
        \             \n\
        \            \n\
        \             }\n\
        \       {-   {i Text classification} \n\
        \           \n\
        \             \n\
        \            {[\n\
        \            arn:aws:sagemaker:{i \
         region}:027400017018:labeling-job-algorithm-specification/text-classification\n\
        \            ]}\n\
        \             \n\
        \            \n\
        \             }\n\
        \       {-   {i Object detection} \n\
        \           \n\
        \             \n\
        \            {[\n\
        \            arn:aws:sagemaker:{i \
         region}:027400017018:labeling-job-algorithm-specification/object-detection\n\
        \            ]}\n\
        \             \n\
        \            \n\
        \             }\n\
        \       {-   {i Semantic Segmentation} \n\
        \           \n\
        \             \n\
        \            {[\n\
        \            arn:aws:sagemaker:{i \
         region}:027400017018:labeling-job-algorithm-specification/semantic-segmentation\n\
        \            ]}\n\
        \             \n\
        \            \n\
        \             }\n\
        \       }\n\
        \  "]
}
