type nonrec human_task_config = {
  public_workforce_task_price : public_workforce_task_price option;
      [@ocaml.doc
        "The price that you pay for each task performed by an Amazon Mechanical Turk worker.\n"]
  annotation_consolidation_config : annotation_consolidation_config option;
      [@ocaml.doc "Configures how labels are consolidated across human workers.\n"]
  max_concurrent_task_count : max_concurrent_task_count option;
      [@ocaml.doc
        "Defines the maximum number of data objects that can be labeled by human workers at the \
         same time. Also referred to as batch size. Each object may have more than one worker at \
         one time. The default value is 1000 objects. To increase the maximum value to 5000 \
         objects, contact Amazon Web Services Support.\n"]
  task_availability_lifetime_in_seconds : task_availability_lifetime_in_seconds option;
      [@ocaml.doc
        "The length of time that a task remains available for labeling by human workers. The \
         default and maximum values for this parameter depend on the type of workforce you use.\n\n\
        \ {ul\n\
        \       {-  If you choose the Amazon Mechanical Turk workforce, the maximum is 12 hours \
         (43,200 seconds). The default is 6 hours (21,600 seconds).\n\
        \           \n\
        \            }\n\
        \       {-  If you choose a private or vendor workforce, the default value is 30 days \
         (2592,000 seconds) for non-AL mode. For most users, the maximum is also 30 days.\n\
        \           \n\
        \            }\n\
        \       }\n\
        \  "]
  task_time_limit_in_seconds : task_time_limit_in_seconds;
      [@ocaml.doc
        "The amount of time that a worker has to complete a task. \n\n\
        \ If you create a custom labeling job, the maximum value for this parameter is 8 hours \
         (28,800 seconds).\n\
        \ \n\
        \  If you create a labeling job using a \
         {{:https://docs.aws.amazon.com/sagemaker/latest/dg/sms-task-types.html}built-in task \
         type} the maximum for this parameter depends on the task type you use:\n\
        \  \n\
        \   {ul\n\
        \         {-  For \
         {{:https://docs.aws.amazon.com/sagemaker/latest/dg/sms-label-images.html}image} and \
         {{:https://docs.aws.amazon.com/sagemaker/latest/dg/sms-label-text.html}text} labeling \
         jobs, the maximum is 8 hours (28,800 seconds).\n\
        \             \n\
        \              }\n\
        \         {-  For \
         {{:https://docs.aws.amazon.com/sagemaker/latest/dg/sms-point-cloud.html}3D point cloud} \
         and {{:https://docs.aws.amazon.com/sagemaker/latest/dg/sms-video.html}video frame} \
         labeling jobs, the maximum is 30 days (2952,000 seconds) for non-AL mode. For most users, \
         the maximum is also 30 days.\n\
        \             \n\
        \              }\n\
        \         }\n\
        \  "]
  number_of_human_workers_per_data_object : number_of_human_workers_per_data_object;
      [@ocaml.doc "The number of human workers that will label an object. \n"]
  task_description : task_description;
      [@ocaml.doc "A description of the task for your human workers.\n"]
  task_title : task_title; [@ocaml.doc "A title for the task for your human workers.\n"]
  task_keywords : task_keywords option;
      [@ocaml.doc
        "Keywords used to describe the task so that workers on Amazon Mechanical Turk can discover \
         the task.\n"]
  pre_human_task_lambda_arn : lambda_function_arn option;
      [@ocaml.doc
        "The Amazon Resource Name (ARN) of a Lambda function that is run before a data object is \
         sent to a human worker. Use this function to provide input to a custom labeling job.\n\n\
        \ For {{:https://docs.aws.amazon.com/sagemaker/latest/dg/sms-task-types.html}built-in task \
         types}, use one of the following Amazon SageMaker Ground Truth Lambda function ARNs for \
         [PreHumanTaskLambdaArn]. For custom labeling workflows, see \
         {{:https://docs.aws.amazon.com/sagemaker/latest/dg/sms-custom-templates-step3.html#sms-custom-templates-step3-prelambda}Pre-annotation \
         Lambda}. \n\
