      [@ocaml.doc "Configuration information for automated data labeling.\n"]
  stopping_conditions : labeling_job_stopping_conditions option;
      [@ocaml.doc
        "A set of conditions for stopping a labeling job. If any of the conditions are met, the \
         job is automatically stopped.\n"]
  label_category_config_s3_uri : s3_uri option;
      [@ocaml.doc
        "The S3 location of the JSON file that defines the categories used to label data objects. \
         Please note the following label-category limits:\n\n\
        \ {ul\n\
        \       {-  Semantic segmentation labeling jobs using automated labeling: 20 labels\n\
        \           \n\
        \            }\n\
        \       {-  Box bounding labeling jobs (all): 10 labels\n\
        \           \n\
        \            }\n\
        \       }\n\
        \   The file is a JSON structure in the following format:\n\
        \   \n\
        \     [{] \n\
        \    \n\
        \      [ \"document-version\": \"2018-11-28\"] \n\
        \     \n\
        \       [ \"labels\": \\[] \n\
        \      \n\
        \        [ {] \n\
        \       \n\
        \         \n\
        \        {[\n\
        \         \"label\": \"{i label 1}\"\n\
        \        ]}\n\
        \         \n\
        \        \n\
        \          [ },] \n\
        \         \n\
        \           [ {] \n\
        \          \n\
        \            \n\
        \           {[\n\
        \            \"label\": \"{i label 2}\"\n\
        \           ]}\n\
        \            \n\
        \           \n\
        \             [ },] \n\
        \            \n\
        \              [ ...] \n\
        \             \n\
        \               [ {] \n\
        \              \n\
        \                \n\
        \               {[\n\
        \                \"label\": \"{i label n}\"\n\
        \               ]}\n\
        \                \n\
        \               \n\
        \                 [ }] \n\
        \                \n\
        \                  [ \\]] \n\
        \                 \n\
        \                   [}] \n\
        \                  "]
  role_arn : role_arn;
      [@ocaml.doc
        "The Amazon Resource Name (ARN) that SageMaker assumes to perform tasks on your behalf \
         during data labeling.\n"]
  output_config : labeling_job_output_config;
      [@ocaml.doc
        "The location of the job's output data and the Amazon Web Services Key Management Service \
         key ID for the key used to encrypt the output data, if any.\n"]
  input_config : labeling_job_input_config;
      [@ocaml.doc
        "Input configuration information for the labeling job, such as the Amazon S3 location of \
         the data objects and the location of the manifest file that describes the data objects.\n"]
  label_attribute_name : label_attribute_name option;
      [@ocaml.doc "The attribute used as the label in the output manifest file.\n"]
