      [@ocaml.doc "The Amazon Resource Name (ARN) of the labeling job.\n"]
  labeling_job_name : labeling_job_name;
      [@ocaml.doc "The name assigned to the labeling job when it was created.\n"]
  job_reference_code : job_reference_code;
      [@ocaml.doc "A unique identifier for work done as part of a labeling job.\n"]
  last_modified_time : timestamp;
      [@ocaml.doc "The date and time that the labeling job was last updated.\n"]
  creation_time : timestamp; [@ocaml.doc "The date and time that the labeling job was created.\n"]
  failure_reason : failure_reason option;
      [@ocaml.doc "If the job failed, the reason that it failed. \n"]
  label_counters : label_counters;
