type nonrec autotune = {
  mode : autotune_mode; [@ocaml.doc "Set [Mode] to [Enabled] if you want to use Autotune.\n"]
}
[@@ocaml.doc
  "A flag to indicate if you want to use Autotune to automatically find optimal values for the \
   following fields:\n\n\
  \ {ul\n\
  \       {-   \
   {{:https://docs.aws.amazon.com/sagemaker/latest/APIReference/API_HyperParameterTuningJobConfig.html#sagemaker-Type-HyperParameterTuningJobConfig-ParameterRanges}ParameterRanges}: \
   The names and ranges of parameters that a hyperparameter tuning job can optimize.\n\
  \           \n\
  \            }\n\
  \       {-   \
   {{:https://docs.aws.amazon.com/sagemaker/latest/APIReference/API_ResourceLimits.html}ResourceLimits}: \
   The maximum resources that can be used for a training job. These resources include the maximum \
   number of training jobs, the maximum runtime of a tuning job, and the maximum number of \
   training jobs to run at the same time.\n\
  \           \n\
  \            }\n\
  \       {-   \
   {{:https://docs.aws.amazon.com/sagemaker/latest/APIReference/API_HyperParameterTuningJobConfig.html#sagemaker-Type-HyperParameterTuningJobConfig-TrainingJobEarlyStoppingType}TrainingJobEarlyStoppingType}: \
   A flag that specifies whether or not to use early stopping for training jobs launched by a \
   hyperparameter tuning job.\n\
  \           \n\
  \            }\n\
  \       {-   \
   {{:https://docs.aws.amazon.com/sagemaker/latest/APIReference/API_HyperParameterTrainingJobDefinition.html#sagemaker-Type-HyperParameterTrainingJobDefinition-RetryStrategy}RetryStrategy}: \
   The number of times to retry a training job.\n\
  \           \n\
  \            }\n\
  \       {-   \
   {{:https://docs.aws.amazon.com/sagemaker/latest/APIReference/API_HyperParameterTuningJobConfig.html}Strategy}: \
   Specifies how hyperparameter tuning chooses the combinations of hyperparameter values to use \
   for the training jobs that it launches.\n\
  \           \n\
  \            }\n\
  \       {-   \
   {{:https://docs.aws.amazon.com/sagemaker/latest/APIReference/API_ConvergenceDetected.html}ConvergenceDetected}: \
   A flag to indicate that Automatic model tuning (AMT) has detected model convergence.\n\
  \           \n\
  \            }\n\
  \       }\n\
  \  "]

