type nonrec production_variant_core_dump_config = {
  kms_key_id : kms_key_id option;
      [@ocaml.doc
        "The Amazon Web Services Key Management Service (Amazon Web Services KMS) key that \
         SageMaker uses to encrypt the core dump data at rest using Amazon S3 server-side \
         encryption. The [KmsKeyId] can be any of the following formats: \n\n\
        \ {ul\n\
        \       {-  // KMS Key ID\n\
        \           \n\
        \             [\"1234abcd-12ab-34cd-56ef-1234567890ab\"] \n\
        \            \n\
        \             }\n\
        \       {-  // Amazon Resource Name (ARN) of a KMS Key\n\
        \           \n\
        \             \
         [\"arn:aws:kms:us-west-2:111122223333:key/1234abcd-12ab-34cd-56ef-1234567890ab\"] \n\
        \            \n\
        \             }\n\
        \       {-  // KMS Key Alias\n\
        \           \n\
        \             [\"alias/ExampleAlias\"] \n\
        \            \n\
        \             }\n\
        \       {-  // Amazon Resource Name (ARN) of a KMS Key Alias\n\
        \           \n\
        \             [\"arn:aws:kms:us-west-2:111122223333:alias/ExampleAlias\"] \n\
        \            \n\
        \             }\n\
        \       }\n\
        \   If you use a KMS key ID or an alias of your KMS key, the SageMaker execution role must \
         include permissions to call [kms:Encrypt]. If you don't provide a KMS key ID, SageMaker \
         uses the default KMS key for Amazon S3 for your role's account. SageMaker uses \
         server-side encryption with KMS-managed keys for [OutputDataConfig]. If you use a bucket \
         policy with an [s3:PutObject] permission that only allows objects with server-side \
         encryption, set the condition key of [s3:x-amz-server-side-encryption] to [\"aws:kms\"]. \
         For more information, see \
         {{:https://docs.aws.amazon.com/AmazonS3/latest/dev/UsingKMSEncryption.html}KMS-Managed \
         Encryption Keys} in the {i Amazon Simple Storage Service Developer Guide.} \n\
        \   \n\
        \    The KMS key policy must grant permission to the IAM role that you specify in your \
         [CreateEndpoint] and [UpdateEndpoint] requests. For more information, see \
         {{:https://docs.aws.amazon.com/kms/latest/developerguide/key-policies.html}Using Key \
         Policies in Amazon Web Services KMS} in the {i Amazon Web Services Key Management Service \
         Developer Guide}.\n\
        \    "]
  destination_s3_uri : destination_s3_uri;
      [@ocaml.doc "The Amazon S3 bucket to send the core dump to.\n"]
}
[@@ocaml.doc
  "Specifies configuration for a core dump from the model container when the process crashes.\n"]

