type nonrec production_variant = {
  capacity_reservation_config : production_variant_capacity_reservation_config option;
      [@ocaml.doc
        "Settings for the capacity reservation for the compute instances that SageMaker AI \
         reserves for an endpoint. \n"]
  inference_ami_version : production_variant_inference_ami_version option;
      [@ocaml.doc
        "Specifies an option from a collection of preconfigured Amazon Machine Image (AMI) images. \
         Each image is configured by Amazon Web Services with a set of software and driver \
         versions. Amazon Web Services optimizes these configurations for different machine \
         learning workloads.\n\n\
        \ By selecting an AMI version, you can ensure that your inference environment is \
         compatible with specific software requirements, such as CUDA driver versions, Linux \
         kernel versions, or Amazon Web Services Neuron driver versions.\n\
        \ \n\
        \  The AMI version names, and their configurations, are the following:\n\
        \  \n\
        \    al2-ami-sagemaker-inference-gpu-2  {ul\n\
        \                                             {-  Accelerator: GPU\n\
        \                                                 \n\
        \                                                  }\n\
        \                                             {-  NVIDIA driver version: 535\n\
        \                                                 \n\
        \                                                  }\n\
        \                                             {-  CUDA version: 12.2\n\
        \                                                 \n\
        \                                                  }\n\
        \                                             }\n\
        \    al2-ami-sagemaker-inference-gpu-2-1  {ul\n\
        \                                               {-  Accelerator: GPU\n\
        \                                                   \n\
        \                                                    }\n\
        \                                               {-  NVIDIA driver version: 535\n\
        \                                                   \n\
        \                                                    }\n\
        \                                               {-  CUDA version: 12.2\n\
        \                                                   \n\
        \                                                    }\n\
        \                                               {-  NVIDIA Container Toolkit with disabled \
         CUDA-compat mounting\n\
        \                                                   \n\
        \                                                    }\n\
        \                                               }\n\
        \    al2-ami-sagemaker-inference-gpu-3-1  {ul\n\
        \                                               {-  Accelerator: GPU\n\
        \                                                   \n\
        \                                                    }\n\
        \                                               {-  NVIDIA driver version: 550\n\
        \                                                   \n\
        \                                                    }\n\
        \                                               {-  CUDA version: 12.4\n\
        \                                                   \n\
        \                                                    }\n\
        \                                               {-  NVIDIA Container Toolkit with disabled \
         CUDA-compat mounting\n\
        \                                                   \n\
        \                                                    }\n\
        \                                               }\n\
        \    al2023-ami-sagemaker-inference-gpu-4-1  {ul\n\
        \                                                  {-  Accelerator: GPU\n\
        \                                                      \n\
        \                                                       }\n\
        \                                                  {-  NVIDIA driver version: 580\n\
        \                                                      \n\
        \                                                       }\n\
        \                                                  {-  CUDA version: 13.0\n\
        \                                                      \n\
        \                                                       }\n\
        \                                                  {-  NVIDIA Container Toolkit with \
         disabled CUDA-compat mounting\n\
        \                                                      \n\
        \                                                       }\n\
        \                                                  }\n\
        \    al2-ami-sagemaker-inference-neuron-2  {ul\n\
        \                                                {-  Accelerator: Inferentia2 and Trainium\n\
        \                                                    \n\
        \                                                     }\n\
        \                                                {-  Neuron driver version: 2.19\n\
        \                                                    \n\
        \                                                     }\n\
        \                                                }\n\
        \    "]
  routing_config : production_variant_routing_config option;
      [@ocaml.doc
        "Settings that control how the endpoint routes incoming traffic to the instances that the \
         endpoint hosts.\n"]
  managed_instance_scaling : production_variant_managed_instance_scaling option;
      [@ocaml.doc
        "Settings that control the range in the number of instances that the endpoint provisions \
         as it scales up or down to accommodate traffic. \n"]
  enable_ssm_access : production_variant_ssm_access option;
      [@ocaml.doc
        " You can use this parameter to turn on native Amazon Web Services Systems Manager (SSM) \
         access for a production variant behind an endpoint. By default, SSM access is disabled \
         for all production variants behind an endpoint. You can turn on or turn off SSM access \
         for a production variant behind an existing endpoint by creating a new endpoint \
         configuration and calling [UpdateEndpoint]. \n"]
  container_startup_health_check_timeout_in_seconds :
    production_variant_container_startup_health_check_timeout_in_seconds option;
      [@ocaml.doc
        "The timeout value, in seconds, for your inference container to pass health check by \
         SageMaker Hosting. For more information about health check, see \
         {{:https://docs.aws.amazon.com/sagemaker/latest/dg/your-algorithms-inference-code.html#your-algorithms-inference-algo-ping-requests}How \
         Your Container Should Respond to Health Check (Ping) Requests}.\n"]
  model_data_download_timeout_in_seconds :
    production_variant_model_data_download_timeout_in_seconds option;
      [@ocaml.doc
        "The timeout value, in seconds, to download and extract the model that you want to host \
         from Amazon S3 to the individual inference instance associated with this production \
         variant.\n"]
  volume_size_in_g_b : production_variant_volume_size_in_g_b option;
      [@ocaml.doc
        "The size, in GB, of the ML storage volume attached to individual inference instance \
         associated with the production variant. Currently only Amazon EBS gp2 storage volumes are \
         supported.\n"]
  serverless_config : production_variant_serverless_config option;
      [@ocaml.doc
        "The serverless configuration for an endpoint. Specifies a serverless endpoint \
         configuration instead of an instance-based endpoint configuration.\n"]
  core_dump_config : production_variant_core_dump_config option;
      [@ocaml.doc
        "Specifies configuration for a core dump from the model container when the process crashes.\n"]
  accelerator_type : production_variant_accelerator_type option;
      [@ocaml.doc
        "This parameter is no longer supported. Elastic Inference (EI) is no longer available.\n\n\
        \ This parameter was used to specify the size of the EI instance to use for the production \
         variant.\n\
        \ "]
  initial_variant_weight : variant_weight option;
      [@ocaml.doc
        "Determines initial traffic distribution among all of the models that you specify in the \
         endpoint configuration. The traffic to a production variant is determined by the ratio of \
         the [VariantWeight] to the sum of all [VariantWeight] values across all \
         ProductionVariants. If unspecified, it defaults to 1.0. \n"]
  variant_instance_provision_timeout_in_seconds :
    variant_instance_provision_timeout_in_seconds option;
      [@ocaml.doc
        "The timeout value, in seconds, for provisioning instances for the production variant. \
         When SageMaker encounters an insufficient capacity error while provisioning instances, it \
         retries with the next instance pool (if configured) or waits until the timeout expires. \
         This timeout applies only to capacity provisioning and does not include the time for \
         model download or container startup.\n\n\
        \ Valid values: 300 to 3600.\n\
        \ "]
  instance_pools : instance_pool_list option;
      [@ocaml.doc
        "A list of instance pools for the production variant. Each instance pool specifies an \
         instance type and its priority for provisioning. Use instance pools to configure \
         heterogeneous endpoints that deploy models across multiple instance types.\n"]
  instance_type : production_variant_instance_type option;
      [@ocaml.doc "The ML compute instance type.\n"]
  initial_instance_count : initial_task_count option;
      [@ocaml.doc "Number of instances to launch initially.\n"]
  model_name : model_name option;
      [@ocaml.doc
        "The name of the model that you want to host. This is the name that you specified when \
         creating the model.\n"]
  variant_name : variant_name; [@ocaml.doc "The name of the production variant.\n"]
}
[@@ocaml.doc
  " Identifies a model that you want to host and the resources chosen to deploy for hosting it. If \
   you are deploying multiple models, tell SageMaker how to distribute traffic among the models by \
   specifying variant weights. For more information on production variants, check \
   {{:https://docs.aws.amazon.com/sagemaker/latest/dg/model-ab-testing.html} Production variants}. \n"]

