type nonrec clarify_text_config = {
  granularity : clarify_text_granularity;
      [@ocaml.doc
        "The unit of granularity for the analysis of text features. For example, if the unit is \
         ['token'], then each token (like a word in English) of the text is treated as a feature. \
         SHAP values are computed for each unit/feature.\n"]
  language : clarify_text_language;
      [@ocaml.doc
        "Specifies the language of the text features in {{: \
         https://en.wikipedia.org/wiki/List_of_ISO_639-1_codes}ISO 639-1} or \
         {{:https://en.wikipedia.org/wiki/ISO_639-3}ISO 639-3} code of a supported language. \n\n\
        \  For a mix of multiple languages, use code ['xx'].\n\
        \  \n\
        \   "]
}
[@@ocaml.doc
  "A parameter used to configure the SageMaker Clarify explainer to treat text features as text so \
   that explanations are provided for individual units of text. Required only for natural language \
   processing (NLP) explainability. \n"]

type nonrec clarify_shap_config = {
  text_config : clarify_text_config option;
      [@ocaml.doc
        "A parameter that indicates if text features are treated as text and explanations are \
         provided for individual units of text. Required for natural language processing (NLP) \
         explainability only.\n"]
  seed : clarify_shap_seed option;
      [@ocaml.doc
        "The starting value used to initialize the random number generator in the explainer. \
         Provide a value for this parameter to obtain a deterministic SHAP result.\n"]
  use_logit : clarify_shap_use_logit option;
      [@ocaml.doc
        "A Boolean toggle to indicate if you want to use the logit function (true) or log-odds \
         units (false) for model predictions. Defaults to false.\n"]
  number_of_samples : clarify_shap_number_of_samples option;
      [@ocaml.doc
        "The number of samples to be used for analysis by the Kernal SHAP algorithm. \n\n\
        \  The number of samples determines the size of the synthetic dataset, which has an impact \
         on latency of explainability requests. For more information, see the {b Synthetic data} \
         of \
         {{:https://docs.aws.amazon.com/sagemaker/latest/dg/clarify-online-explainability-create-endpoint.html}Configure \
         and create an endpoint}.\n\
        \  \n\
        \   "]
  shap_baseline_config : clarify_shap_baseline_config;
      [@ocaml.doc "The configuration for the SHAP baseline of the Kernal SHAP algorithm.\n"]
}
