type nonrec enable_enhanced_metrics = bool [@@ocaml.doc ""]

type nonrec enable_detailed_observability = bool [@@ocaml.doc ""]

type nonrec metrics_config = {
  metric_publish_frequency_in_seconds : metric_publish_frequency_in_seconds option;
      [@ocaml.doc
        "The interval, in seconds, at which metrics are published to Amazon CloudWatch. Defaults \
         to [60]. Valid values: [10], [30], [60], [120], [180], [240], [300].\n\n\
        \ When [EnableEnhancedMetrics] is set to [False], this interval applies to utilization \
         metrics only. Invocation metrics continue to be published at the default 60-second \
         interval. When [EnableEnhancedMetrics] is set to [True], this interval applies to both \
         utilization and invocation metrics.\n\
        \ \n\
        \  When [EnableDetailedObservability] is set to [True], this interval applies to per-GPU \
         metrics, per-instance host metrics, container metrics, and fleet-level inference \
         component lifecycle and placement metrics.\n\
        \  "]
  enable_detailed_observability : enable_detailed_observability option;
      [@ocaml.doc
        "Indicates whether detailed observability is enabled for the endpoint. When set to [True], \
         the following metrics are published at the configured frequency:\n\n\
        \ {ul\n\
        \       {-  Container-level inference metrics scraped from the container's Prometheus \
         endpoint (such as request latency, error counts, and throughput). Available metrics vary \
         by framework.\n\
        \           \n\
        \            }\n\
        \       {-  Per-GPU metrics (utilization, memory, and temperature) attributed to \
         individual inference components.\n\
        \           \n\
        \            }\n\
        \       {-  Per-instance host metrics (CPU, memory, and disk utilization).\n\
        \           \n\
        \            }\n\
        \       {-  Inference component placement metrics (copy count per Availability Zone).\n\
        \           \n\
        \            }\n\
        \       }\n\
        \   For first-party and Deep Learning Containers (DLC), the Prometheus endpoint path is \
         determined automatically. For Bring-Your-Own-Container (BYOC) cases, you can optionally \
         set [ContainerMetricsConfig] to specify a custom endpoint path. If not specified, the \
         default path [/metrics] on port [8080] is used.\n\
        \   \n\
        \    When set to [False], these additional metrics are not published. Standard invocation \
         and utilization metrics controlled by [EnableEnhancedMetrics] are unaffected.\n\
        \    \n\
        \     The default value for new endpoint configurations is [True]. For existing endpoint \
         configurations created before this feature, the value is [False] unless explicitly set.\n\
        \     "]
  enable_enhanced_metrics : enable_enhanced_metrics option;
      [@ocaml.doc
        "Specifies whether to enable enhanced metrics for the endpoint. Enhanced metrics provide \
         utilization and invocation data at instance and container granularity. Container \
         granularity is supported for Inference Components. The default is [False].\n"]
}
[@@ocaml.doc "The configuration for Utilization metrics.\n"]

