      [@ocaml.doc
        "The status of the endpoint.\n\n\
        \ {ul\n\
        \       {-   [OutOfService]: Endpoint is not available to take incoming requests.\n\
        \           \n\
        \            }\n\
        \       {-   [Creating]: \
         {{:https://docs.aws.amazon.com/sagemaker/latest/APIReference/API_CreateEndpoint.html}CreateEndpoint} \
         is executing.\n\
        \           \n\
        \            }\n\
        \       {-   [Updating]: \
         {{:https://docs.aws.amazon.com/sagemaker/latest/APIReference/API_UpdateEndpoint.html}UpdateEndpoint} \
         or \
         {{:https://docs.aws.amazon.com/sagemaker/latest/APIReference/API_UpdateEndpointWeightsAndCapacities.html}UpdateEndpointWeightsAndCapacities} \
         is executing.\n\
        \           \n\
        \            }\n\
        \       {-   [SystemUpdating]: Endpoint is undergoing maintenance and cannot be updated or \
         deleted or re-scaled until it has completed. This maintenance operation does not change \
         any customer-specified values such as VPC config, KMS encryption, model, instance type, \
         or instance count.\n\
        \           \n\
        \            }\n\
        \       {-   [RollingBack]: Endpoint fails to scale up or down or change its variant \
         weight and is in the process of rolling back to its previous configuration. Once the \
         rollback completes, endpoint returns to an [InService] status. This transitional status \
         only applies to an endpoint that has autoscaling enabled and is undergoing variant weight \
         or capacity changes as part of an \
         {{:https://docs.aws.amazon.com/sagemaker/latest/APIReference/API_UpdateEndpointWeightsAndCapacities.html}UpdateEndpointWeightsAndCapacities} \
         call or when the \
         {{:https://docs.aws.amazon.com/sagemaker/latest/APIReference/API_UpdateEndpointWeightsAndCapacities.html}UpdateEndpointWeightsAndCapacities} \
         operation is called explicitly.\n\
        \           \n\
        \            }\n\
        \       {-   [InService]: Endpoint is available to process incoming requests.\n\
        \           \n\
        \            }\n\
        \       {-   [Deleting]: \
         {{:https://docs.aws.amazon.com/sagemaker/latest/APIReference/API_DeleteEndpoint.html}DeleteEndpoint} \
         is executing.\n\
        \           \n\
        \            }\n\
        \       {-   [Failed]: Endpoint could not be created, updated, or re-scaled. Use the \
         [FailureReason] value returned by \
         {{:https://docs.aws.amazon.com/sagemaker/latest/APIReference/API_DescribeEndpoint.html}DescribeEndpoint} \
         for information about the failure. \
         {{:https://docs.aws.amazon.com/sagemaker/latest/APIReference/API_DeleteEndpoint.html}DeleteEndpoint} \
         is the only operation that can be performed on a failed endpoint.\n\
        \           \n\
        \            }\n\
        \       {-   [UpdateRollbackFailed]: Both the rolling deployment and auto-rollback failed. \
         Your endpoint is in service with a mix of the old and new endpoint configurations. For \
         information about how to remedy this issue and restore the endpoint's status to \
         [InService], see \
         {{:https://docs.aws.amazon.com/sagemaker/latest/dg/deployment-guardrails-rolling.html}Rolling \
         Deployments}.\n\
        \           \n\
        \            }\n\
        \       }\n\
        \  "]
  data_capture_config : data_capture_config_summary option; [@ocaml.doc ""]
  production_variants : production_variant_summary_list option;
      [@ocaml.doc
        "An array of \
         {{:https://docs.aws.amazon.com/sagemaker/latest/APIReference/API_ProductionVariantSummary.html}ProductionVariantSummary} \
         objects, one for each model hosted behind this endpoint.\n"]
  endpoint_config_name : endpoint_config_name option;
      [@ocaml.doc "The name of the endpoint configuration associated with this endpoint.\n"]
