      [@ocaml.doc "Failure reason of the compute allocation definition.\n"]
  status : scheduler_resource_status; [@ocaml.doc "Status of the compute allocation definition.\n"]
  compute_quota_version : integer; [@ocaml.doc "Version of the compute allocation definition.\n"]
  description : entity_description option;
      [@ocaml.doc "Description of the compute allocation definition.\n"]
  name : entity_name; [@ocaml.doc "Name of the compute allocation definition.\n"]
  compute_quota_id : compute_quota_id; [@ocaml.doc "ID of the compute allocation definition.\n"]
  compute_quota_arn : compute_quota_arn; [@ocaml.doc "ARN of the compute allocation definition.\n"]
}
