type nonrec auto_mls3_data_source = {
  s3_uri : s3_uri;
      [@ocaml.doc
        "The URL to the Amazon S3 data source. The Uri refers to the Amazon S3 prefix or \
         ManifestFile depending on the data type.\n"]
  s3_data_type : auto_mls3_data_type;
      [@ocaml.doc
        "The data type. \n\n\
        \ {ul\n\
        \       {-  If you choose [S3Prefix], [S3Uri] identifies a key name prefix. SageMaker AI \
         uses all objects that match the specified key name prefix for model training.\n\
        \           \n\
        \            The [S3Prefix] should have the following format:\n\
        \            \n\
        \              [s3://DOC-EXAMPLE-BUCKET/DOC-EXAMPLE-FOLDER-OR-FILE] \n\
        \             \n\
        \              }\n\
        \       {-  If you choose [ManifestFile], [S3Uri] identifies an object that is a manifest \
         file containing a list of object keys that you want SageMaker AI to use for model \
         training.\n\
        \           \n\
        \            A [ManifestFile] should have the format shown below:\n\
        \            \n\
        \              [\\[ {\"prefix\": \
         \"s3://DOC-EXAMPLE-BUCKET/DOC-EXAMPLE-FOLDER/DOC-EXAMPLE-PREFIX/\"}, ] \n\
        \             \n\
        \               [\"DOC-EXAMPLE-RELATIVE-PATH/DOC-EXAMPLE-FOLDER/DATA-1\",] \n\
        \              \n\
        \                [\"DOC-EXAMPLE-RELATIVE-PATH/DOC-EXAMPLE-FOLDER/DATA-2\",] \n\
        \               \n\
        \                 [... \"DOC-EXAMPLE-RELATIVE-PATH/DOC-EXAMPLE-FOLDER/DATA-N\" \\]] \n\
        \                \n\
        \                 }\n\
        \       {-  If you choose [AugmentedManifestFile], [S3Uri] identifies an object that is an \
         augmented manifest file in JSON lines format. This file contains the data you want to use \
         for model training. [AugmentedManifestFile] is available for V2 API jobs only (for \
         example, for jobs created by calling [CreateAutoMLJobV2]).\n\
        \           \n\
        \            Here is a minimal, single-record example of an [AugmentedManifestFile]:\n\
        \            \n\
        \              [{\"source-ref\": \
         \"s3://DOC-EXAMPLE-BUCKET/DOC-EXAMPLE-FOLDER/cats/cat.jpg\",] \n\
        \             \n\
        \               [\"label-metadata\": {\"class-name\": \"cat\"] \\}\n\
        \              \n\
        \               For more information on [AugmentedManifestFile], see \
         {{:https://docs.aws.amazon.com/sagemaker/latest/dg/augmented-manifest.html}Provide \
         Dataset Metadata to Training Jobs with an Augmented Manifest File}.\n\
        \               \n\
        \                }\n\
