type nonrec auto_ml_job_channel = {
  data_source : auto_ml_data_source option;
      [@ocaml.doc "The data source for an AutoML channel (Required).\n"]
  compression_type : compression_type option;
      [@ocaml.doc
        "The allowed compression types depend on the input format and problem type. We allow the \
         compression type [Gzip] for [S3Prefix] inputs on tabular data only. For all other inputs, \
         the compression type should be [None]. If no compression type is provided, we default to \
         [None].\n"]
  content_type : content_type option;
      [@ocaml.doc
        "The content type of the data from the input source. The following are the allowed content \
         types for different problems:\n\n\
        \ {ul\n\
        \       {-  For tabular problem types: [text/csv;header=present] or \
         [x-application/vnd.amazon+parquet]. The default value is [text/csv;header=present].\n\
        \           \n\
        \            }\n\
        \       {-  For image classification: [image/png], [image/jpeg], or [image/*]. The default \
         value is [image/*].\n\
        \           \n\
        \            }\n\
        \       {-  For text classification: [text/csv;header=present] or \
         [x-application/vnd.amazon+parquet]. The default value is [text/csv;header=present].\n\
        \           \n\
        \            }\n\
        \       {-  For time-series forecasting: [text/csv;header=present] or \
         [x-application/vnd.amazon+parquet]. The default value is [text/csv;header=present].\n\
        \           \n\
        \            }\n\
        \       {-  For text generation (LLMs fine-tuning): [text/csv;header=present] or \
         [x-application/vnd.amazon+parquet]. The default value is [text/csv;header=present].\n\
        \           \n\
        \            }\n\
        \       }\n\
        \  "]
  channel_type : auto_ml_channel_type option;
      [@ocaml.doc
        "The type of channel. Defines whether the data are used for training or validation. The \
         default value is [training]. Channels for [training] and [validation] must share the same \
         [ContentType] \n\n\
        \  The type of channel defaults to [training] for the time-series forecasting problem type.\n\
        \  \n\
        \   "]
}
[@@ocaml.doc
  "A channel is a named input source that training algorithms can consume. This channel is used \
   for AutoML jobs V2 (jobs created by calling \
   {{:https://docs.aws.amazon.com/sagemaker/latest/APIReference/API_CreateAutoMLJobV2.html}CreateAutoMLJobV2}).\n"]

