type nonrec auto_ml_job_objective = {
  metric_name : auto_ml_metric_enum;
      [@ocaml.doc
        "The name of the objective metric used to measure the predictive quality of a machine \
         learning system. During training, the model's parameters are updated iteratively to \
         optimize its performance based on the feedback provided by the objective metric when \
         evaluating the model on the validation dataset.\n\n\
        \ The list of available metrics supported by Autopilot and the default metric applied when \
         you do not specify a metric name explicitly depend on the problem type.\n\
        \ \n\
        \  {ul\n\
        \        {-  For tabular problem types:\n\
        \            \n\
        \             {ul\n\
        \                   {-  List of available metrics: \n\
        \                       \n\
        \                        {ul\n\
        \                              {-   Regression: [MAE], [MSE], [R2], [RMSE] \n\
        \                                  \n\
        \                                   }\n\
        \                              {-   Binary classification: [Accuracy], [AUC], \
         [BalancedAccuracy], [F1], [Precision], [Recall] \n\
        \                                  \n\
        \                                   }\n\
        \                              {-   Multiclass classification: [Accuracy], \
         [BalancedAccuracy], [F1macro], [PrecisionMacro], [RecallMacro] \n\
        \                                  \n\
        \                                   }\n\
        \                              \n\
        \                    }\n\
        \                     For a description of each metric, see \
         {{:https://docs.aws.amazon.com/sagemaker/latest/dg/autopilot-metrics-validation.html#autopilot-metrics}Autopilot \
         metrics for classification and regression}.\n\
        \                     \n\
        \                      }\n\
        \                   {-  Default objective metrics:\n\
        \                       \n\
        \                        {ul\n\
        \                              {-  Regression: [MSE].\n\
        \                                  \n\
        \                                   }\n\
        \                              {-  Binary classification: [F1].\n\
        \                                  \n\
        \                                   }\n\
        \                              {-  Multiclass classification: [Accuracy].\n\
        \                                  \n\
        \                                   }\n\
        \                              \n\
        \                    }\n\
        \                     }\n\
        \                   \n\
        \         }\n\
        \          }\n\
        \        {-  For image or text classification problem types:\n\
        \            \n\
        \             {ul\n\
        \                   {-  List of available metrics: [Accuracy] \n\
        \                       \n\
        \                        For a description of each metric, see \
         {{:https://docs.aws.amazon.com/sagemaker/latest/dg/text-classification-data-format-and-metric.html}Autopilot \
         metrics for text and image classification}.\n\
        \                        \n\
        \                         }\n\
        \                   {-  Default objective metrics: [Accuracy] \n\
        \                       \n\
        \                        }\n\
        \                   \n\
        \         }\n\
        \          }\n\
        \        {-  For time-series forecasting problem types:\n\
        \            \n\
        \             {ul\n\
        \                   {-  List of available metrics: [RMSE], [wQL], [Average wQL], [MASE], \
         [MAPE], [WAPE] \n\
        \                       \n\
        \                        For a description of each metric, see \
         {{:https://docs.aws.amazon.com/sagemaker/latest/dg/timeseries-objective-metric.html}Autopilot \
         metrics for time-series forecasting}.\n\
        \                        \n\
        \                         }\n\
        \                   {-  Default objective metrics: [AverageWeightedQuantileLoss] \n\
        \                       \n\
        \                        }\n\
        \                   \n\
        \         }\n\
        \          }\n\
        \        {-  For text generation problem types (LLMs fine-tuning): Fine-tuning language \
         models in Autopilot does not require setting the [AutoMLJobObjective] field. Autopilot \
         fine-tunes LLMs without requiring multiple candidates to be trained and evaluated. \
         Instead, using your dataset, Autopilot directly fine-tunes your target model to enhance a \
         default objective metric, the cross-entropy loss. After fine-tuning a language model, you \
         can evaluate the quality of its generated text using different metrics. For a list of the \
         available metrics, see \
         {{:https://docs.aws.amazon.com/sagemaker/latest/dg/autopilot-llms-finetuning-metrics.html}Metrics \
         for fine-tuning LLMs in Autopilot}.\n\
        \            \n\
        \             }\n\
        \        }\n\
        \  "]
}
[@@ocaml.doc "Specifies a metric to minimize or maximize as the objective of an AutoML job.\n"]

