type nonrec auto_ml_compute_config = {
  emr_serverless_compute_config : emr_serverless_compute_config option;
      [@ocaml.doc
        "The configuration for using \
         {{:https://docs.aws.amazon.com/emr/latest/EMR-Serverless-UserGuide/emr-serverless.html} \
         EMR Serverless} to run the AutoML job V2.\n\n\
        \ To allow your AutoML job V2 to automatically initiate a remote job on EMR Serverless \
         when additional compute resources are needed to process large datasets, you need to \
         provide an [EmrServerlessComputeConfig] object, which includes an [ExecutionRoleARN] \
         attribute, to the [AutoMLComputeConfig] of the AutoML job V2 input request.\n\
        \ \n\
        \  By seamlessly transitioning to EMR Serverless when required, the AutoML job can handle \
         datasets that would otherwise exceed the initially provisioned resources, without any \
         manual intervention from you. \n\
        \  \n\
        \   EMR Serverless is available for the tabular and time series problem types. We \
         recommend setting up this option for tabular datasets larger than 5 GB and time series \
         datasets larger than 30 GB.\n\
        \   "]
}
