type nonrec auto_ml_channel = {
  sample_weight_attribute_name : sample_weight_attribute_name option;
      [@ocaml.doc
        "If specified, this column name indicates which column of the dataset should be treated as \
         sample weights for use by the objective metric during the training, evaluation, and the \
         selection of the best model. This column is not considered as a predictive feature. For \
         more information on Autopilot metrics, see \
         {{:https://docs.aws.amazon.com/sagemaker/latest/dg/autopilot-metrics-validation.html}Metrics \
         and validation}.\n\n\
        \ Sample weights should be numeric, non-negative, with larger values indicating which rows \
         are more important than others. Data points that have invalid or no weight value are \
         excluded.\n\
        \ \n\
        \  Support for sample weights is available in \
         {{:https://docs.aws.amazon.com/sagemaker/latest/APIReference/API_AutoMLAlgorithmConfig.html}Ensembling} \
         mode only.\n\
        \  "]
  channel_type : auto_ml_channel_type option;
      [@ocaml.doc
        "The channel type (optional) is an [enum] string. The default value is [training]. \
         Channels for training and validation must share the same [ContentType] and \
         [TargetAttributeName]. For information on specifying training and validation channel \
         types, see \
         {{:https://docs.aws.amazon.com/sagemaker/latest/dg/autopilot-datasets-problem-types.html#autopilot-data-sources-training-or-validation}How \
         to specify training and validation datasets}.\n"]
  content_type : content_type option;
      [@ocaml.doc
        "The content type of the data from the input source. You can use [text/csv;header=present] \
         or [x-application/vnd.amazon+parquet]. The default value is [text/csv;header=present].\n"]
  target_attribute_name : target_attribute_name;
      [@ocaml.doc
        "The name of the target variable in supervised learning, usually represented by 'y'.\n"]
  compression_type : compression_type option;
      [@ocaml.doc "You can use [Gzip] or [None]. The default value is [None].\n"]
  data_source : auto_ml_data_source option; [@ocaml.doc "The data source for an AutoML channel.\n"]
}
[@@ocaml.doc
  "A channel is a named input source that training algorithms can consume. The validation dataset \
   size is limited to less than 2 GB. The training dataset size must be less than 100 GB. For more \
   information, see {{:https://docs.aws.amazon.com/sagemaker/latest/APIReference/API_Channel.html} \
   Channel}.\n\n\
  \  A validation dataset must contain the same headers as the training dataset.\n\
  \  \n\
  \    \n\
  \    "]

