type nonrec create_transform_job_request = {
  experiment_config : experiment_config option; [@ocaml.doc ""]
  tags : tag_list option;
      [@ocaml.doc
        "(Optional) An array of key-value pairs. For more information, see \
         {{:https://docs.aws.amazon.com/awsaccountbilling/latest/aboutv2/cost-alloc-tags.html#allocation-what}Using \
         Cost Allocation Tags} in the {i Amazon Web Services Billing and Cost Management User \
         Guide}.\n"]
  data_processing : data_processing option;
      [@ocaml.doc
        "The data structure used to specify the data to be used for inference in a batch transform \
         job and to associate the data that is relevant to the prediction results in the output. \
         The input filter provided allows you to exclude input data that is not needed for \
         inference in a batch transform job. The output filter provided allows you to include \
         input data relevant to interpreting the predictions in the output from the job. For more \
         information, see \
         {{:https://docs.aws.amazon.com/sagemaker/latest/dg/batch-transform-data-processing.html}Associate \
         Prediction Results with their Corresponding Input Records}.\n"]
  transform_resources : transform_resources;
      [@ocaml.doc
        "Describes the resources, including ML instance types and ML instance count, to use for \
         the transform job.\n"]
  data_capture_config : batch_data_capture_config option;
      [@ocaml.doc "Configuration to control how SageMaker captures inference data.\n"]
  transform_output : transform_output; [@ocaml.doc "Describes the results of the transform job.\n"]
  transform_input : transform_input;
      [@ocaml.doc "Describes the input source and the way the transform job consumes it.\n"]
  environment : transform_environment_map option;
      [@ocaml.doc
        "The environment variables to set in the Docker container. Don't include any sensitive \
         data in your environment variables. We support up to 16 key and values entries in the map.\n"]
  batch_strategy : batch_strategy option;
      [@ocaml.doc
        "Specifies the number of records to include in a mini-batch for an HTTP inference request. \
         A {i record} {i  is a single unit of input data that inference can be made on. For \
         example, a single line in a CSV file is a record. }\n\n\
         {i  To enable the batch strategy, you must set the [SplitType] property to [Line], \
         [RecordIO], or [TFRecord].\n\
        \    \n\
        \     To use only one record when making an HTTP invocation request to a container, set \
         [BatchStrategy] to [SingleRecord] and [SplitType] to [Line].\n\
        \     \n\
        \      To fit as many records in a mini-batch as can fit within the [MaxPayloadInMB] \
         limit, set [BatchStrategy] to [MultiRecord] and [SplitType] to [Line].\n\
        \      }"]
  max_payload_in_m_b : max_payload_in_m_b option;
      [@ocaml.doc
        "The maximum allowed size of the payload, in MB. A {i payload} is the data portion of a \
         record (without metadata). The value in [MaxPayloadInMB] must be greater than, or equal \
         to, the size of a single record. To estimate the size of a record in MB, divide the size \
         of your dataset by the number of records. To ensure that the records fit within the \
         maximum payload size, we recommend using a slightly larger value. The default value is \
         [6] MB. \n\n\
        \ The value of [MaxPayloadInMB] cannot be greater than 100 MB. If you specify the \
         [MaxConcurrentTransforms] parameter, the value of [(MaxConcurrentTransforms * \
         MaxPayloadInMB)] also cannot exceed 100 MB.\n\
        \ \n\
        \  For cases where the payload might be arbitrarily large and is transmitted using HTTP \
         chunked encoding, set the value to [0]. This feature works only in supported algorithms. \
         Currently, Amazon SageMaker built-in algorithms do not support HTTP chunked encoding.\n\
        \  "]
  model_client_config : model_client_config option;
      [@ocaml.doc
        "Configures the timeout and maximum number of retries for processing a transform job \
         invocation.\n"]
  max_concurrent_transforms : max_concurrent_transforms option;
      [@ocaml.doc
        "The maximum number of parallel requests that can be sent to each instance in a transform \
         job. If [MaxConcurrentTransforms] is set to [0] or left unset, Amazon SageMaker checks \
         the optional execution-parameters to determine the settings for your chosen algorithm. If \
         the execution-parameters endpoint is not enabled, the default value is [1]. For more \
         information on execution-parameters, see \
         {{:https://docs.aws.amazon.com/sagemaker/latest/dg/your-algorithms-batch-code.html#your-algorithms-batch-code-how-containe-serves-requests}How \
         Containers Serve Requests}. For built-in algorithms, you don't need to set a value for \
         [MaxConcurrentTransforms].\n"]
  model_name : model_name;
      [@ocaml.doc
        "The name of the model that you want to use for the transform job. [ModelName] must be the \
         name of an existing Amazon SageMaker model within an Amazon Web Services Region in an \
         Amazon Web Services account.\n"]
  transform_job_name : transform_job_name;
      [@ocaml.doc
        "The name of the transform job. The name must be unique within an Amazon Web Services \
         Region in an Amazon Web Services account. \n"]
}
[@@ocaml.doc ""]

