type nonrec create_training_job_request = {
  model_package_config : model_package_config option;
      [@ocaml.doc " The configuration for the model package. \n"]
  mlflow_config : mlflow_config option;
      [@ocaml.doc " The MLflow configuration using SageMaker managed MLflow. \n"]
  serverless_job_config : serverless_job_config option;
      [@ocaml.doc " The configuration for serverless training jobs. \n"]
  session_chaining_config : session_chaining_config option;
      [@ocaml.doc
        "Contains information about attribute-based access control (ABAC) for the training job.\n"]
  infra_check_config : infra_check_config option;
      [@ocaml.doc
        "Contains information about the infrastructure health check configuration for the training \
         job.\n"]
  remote_debug_config : remote_debug_config option;
      [@ocaml.doc
        "Configuration for remote debugging. To learn more about the remote debugging \
         functionality of SageMaker, see \
         {{:https://docs.aws.amazon.com/sagemaker/latest/dg/train-remote-debugging.html}Access a \
         training container through Amazon Web Services Systems Manager (SSM) for remote \
         debugging}.\n"]
  retry_strategy : retry_strategy option;
      [@ocaml.doc
        "The number of times to retry the job when the job fails due to an [InternalServerError].\n"]
  environment : training_environment_map option;
      [@ocaml.doc
        "The environment variables to set in the Docker container.\n\n\
        \  Do not include any security-sensitive information including account access IDs, \
         secrets, or tokens in any environment fields. As part of the shared responsibility model, \
         you are responsible for any potential exposure, unauthorized access, or compromise of \
         your sensitive data if caused by security-sensitive information included in the request \
         environment variable or plain text fields.\n\
        \  \n\
        \   "]
  profiler_rule_configurations : profiler_rule_configurations option;
      [@ocaml.doc
        "Configuration information for Amazon SageMaker Debugger rules for profiling system and \
         framework metrics.\n"]
  profiler_config : profiler_config option; [@ocaml.doc ""]
  experiment_config : experiment_config option; [@ocaml.doc ""]
  tensor_board_output_config : tensor_board_output_config option; [@ocaml.doc ""]
  debug_rule_configurations : debug_rule_configurations option;
      [@ocaml.doc
        "Configuration information for Amazon SageMaker Debugger rules for debugging output tensors.\n"]
  debug_hook_config : debug_hook_config option; [@ocaml.doc ""]
  checkpoint_config : checkpoint_config option;
      [@ocaml.doc
        "Contains information about the output location for managed spot training checkpoint data.\n"]
  enable_managed_spot_training : boolean_ option;
      [@ocaml.doc
        "To train models using managed spot training, choose [True]. Managed spot training \
         provides a fully managed and scalable infrastructure for training machine learning \
         models. this option is useful when training jobs can be interrupted and when there is \
         flexibility when the training job is run. \n\n\
        \ The complete and intermediate results of jobs are stored in an Amazon S3 bucket, and can \
         be used as a starting point to train models incrementally. Amazon SageMaker provides \
         metrics and logs in CloudWatch. They can be used to see when managed spot training jobs \
         are running, interrupted, resumed, or completed. \n\
        \ "]
  enable_inter_container_traffic_encryption : boolean_ option;
      [@ocaml.doc
        "To encrypt all communications between ML compute instances in distributed training, \
         choose [True]. Encryption provides greater security for distributed training, but \
         training might take longer. How long it takes depends on the amount of communication \
         between compute instances, especially if you use a deep learning algorithm in distributed \
         training. For more information, see \
         {{:https://docs.aws.amazon.com/sagemaker/latest/dg/train-encrypt.html}Protect \
         Communications Between ML Compute Instances in a Distributed Training Job}.\n"]
  enable_network_isolation : boolean_ option;
      [@ocaml.doc
        "Isolates the training container. No inbound or outbound network calls can be made, except \
         for calls between peers within a training cluster for distributed training. If you enable \
         network isolation for training jobs that are configured to use a VPC, SageMaker downloads \
         and uploads customer data and model artifacts through the specified VPC, but the training \
         container does not have network access.\n"]
  tags : tag_list option;
      [@ocaml.doc
        "An array of key-value pairs. You can use tags to categorize your Amazon Web Services \
         resources in different ways, for example, by purpose, owner, or environment. For more \
         information, see \
         {{:https://docs.aws.amazon.com/general/latest/gr/aws_tagging.html}Tagging Amazon Web \
         Services Resources}.\n\n\
        \  Do not include any security-sensitive information including account access IDs, \
         secrets, or tokens in any tags. As part of the shared responsibility model, you are \
         responsible for any potential exposure, unauthorized access, or compromise of your \
         sensitive data if caused by any security-sensitive information included in the request \
         tag variable or plain text fields.\n\
        \  \n\
        \   "]
  stopping_condition : stopping_condition option;
      [@ocaml.doc
        "Specifies a limit to how long a model training job can run. It also specifies how long a \
         managed Spot training job has to complete. When the job reaches the time limit, SageMaker \
         ends the training job. Use this API to cap model training costs.\n\n\
        \ To stop a job, SageMaker sends the algorithm the [SIGTERM] signal, which delays job \
         termination for 120 seconds. Algorithms can use this 120-second window to save the model \
         artifacts, so the results of training are not lost. \n\
        \ "]
  vpc_config : vpc_config option;
      [@ocaml.doc
        "A \
         {{:https://docs.aws.amazon.com/sagemaker/latest/APIReference/API_VpcConfig.html}VpcConfig} \
         object that specifies the VPC that you want your training job to connect to. Control \
         access to and from your training container by configuring the VPC. For more information, \
         see {{:https://docs.aws.amazon.com/sagemaker/latest/dg/train-vpc.html}Protect Training \
         Jobs by Using an Amazon Virtual Private Cloud}.\n"]
  resource_config : resource_config option;
      [@ocaml.doc
        "The resources, including the ML compute instances and ML storage volumes, to use for \
         model training. \n\n\
        \ ML storage volumes store model artifacts and incremental states. Training algorithms \
         might also use ML storage volumes for scratch space. If you want SageMaker to use the ML \
         storage volume to store the training data, choose [File] as the [TrainingInputMode] in \
         the algorithm specification. For distributed training algorithms, specify an instance \
         count greater than 1.\n\
        \ "]
  output_data_config : output_data_config;
      [@ocaml.doc
        "Specifies the path to the S3 location where you want to store model artifacts. SageMaker \
         creates subfolders for the artifacts. \n"]
  input_data_config : input_data_config option;
      [@ocaml.doc
        "An array of [Channel] objects. Each channel is a named input source. [InputDataConfig] \
         describes the input data and its location. \n\n\
        \ Algorithms can accept input data from one or more channels. For example, an algorithm \
         might have two channels of input data, [training_data] and [validation_data]. The \
         configuration for each channel provides the S3, EFS, or FSx location where the input data \
         is stored. It also provides information about the stored data: the MIME type, compression \
         method, and whether the data is wrapped in RecordIO format. \n\
        \ \n\
        \  Depending on the input mode that the algorithm supports, SageMaker either copies input \
         data files from an S3 bucket to a local directory in the Docker container, or makes it \
         available as input streams. For example, if you specify an EFS location, input data files \
         are available as input streams. They do not need to be downloaded.\n\
        \  \n\
        \   Your input must be in the same Amazon Web Services region as your training job.\n\
        \   "]
  role_arn : role_arn;
      [@ocaml.doc
        "The Amazon Resource Name (ARN) of an IAM role that SageMaker can assume to perform tasks \
         on your behalf. \n\n\
        \ During model training, SageMaker needs your permission to read input data from an S3 \
         bucket, download a Docker image that contains training code, write model artifacts to an \
         S3 bucket, write logs to Amazon CloudWatch Logs, and publish metrics to Amazon \
         CloudWatch. You grant permissions for all of these tasks to an IAM role. For more \
         information, see \
         {{:https://docs.aws.amazon.com/sagemaker/latest/dg/sagemaker-roles.html}SageMaker Roles}. \n\
        \ \n\
        \   To be able to pass this role to SageMaker, the caller of this API must have the \
         [iam:PassRole] permission.\n\
        \   \n\
        \    "]
  algorithm_specification : algorithm_specification option;
      [@ocaml.doc
        "The registry path of the Docker image that contains the training algorithm and \
         algorithm-specific metadata, including the input mode. For more information about \
         algorithms provided by SageMaker, see \
         {{:https://docs.aws.amazon.com/sagemaker/latest/dg/algos.html}Algorithms}. For \
         information about providing your own algorithms, see \
         {{:https://docs.aws.amazon.com/sagemaker/latest/dg/your-algorithms.html}Using Your Own \
         Algorithms with Amazon SageMaker}. \n"]
  hyper_parameters : hyper_parameters option;
      [@ocaml.doc
        "Algorithm-specific parameters that influence the quality of the model. You set \
         hyperparameters before you start the learning process. For a list of hyperparameters for \
         each training algorithm provided by SageMaker, see \
         {{:https://docs.aws.amazon.com/sagemaker/latest/dg/algos.html}Algorithms}. \n\n\
        \ You can specify a maximum of 100 hyperparameters. Each hyperparameter is a key-value \
         pair. Each key and value is limited to 256 characters, as specified by the [Length \
         Constraint]. \n\
        \ \n\
        \   Do not include any security-sensitive information including account access IDs, \
         secrets, or tokens in any hyperparameter fields. As part of the shared responsibility \
         model, you are responsible for any potential exposure, unauthorized access, or compromise \
         of your sensitive data if caused by any security-sensitive information included in the \
         request hyperparameter variable or plain text fields.\n\
        \   \n\
        \    "]
  training_job_name : training_job_name;
      [@ocaml.doc
        "The name of the training job. The name must be unique within an Amazon Web Services \
         Region in an Amazon Web Services account. \n"]
}
