        "The ID of the subnet in a VPC to which you would like to have a connectivity from your ML \
         compute instance. \n"]
  instance_type : instance_type;
      [@ocaml.doc "The type of ML compute instance to launch for the notebook instance.\n"]
  notebook_instance_name : notebook_instance_name;
      [@ocaml.doc "The name of the new notebook instance.\n"]
}
