      [@ocaml.doc " A structure describing the current state of the model in its life cycle. \n"]
  model_card : model_package_model_card option;
      [@ocaml.doc
        "The model card associated with the model package. Since [ModelPackageModelCard] is tied \
         to a model package, it is a specific usage of a model card and its schema is simplified \
         compared to the schema of [ModelCard]. The [ModelPackageModelCard] schema does not \
         include [model_package_details], and [model_overview] is composed of the [model_creator] \
         and [model_artifact] properties. For more information about the model package model card \
         schema, see \
         {{:https://docs.aws.amazon.com/sagemaker/latest/dg/model-registry-details.html#model-card-schema}Model \
         package model card schema}. For more information about the model card associated with the \
         model package, see \
         {{:https://docs.aws.amazon.com/sagemaker/latest/dg/model-registry-details.html}View the \
         Details of a Model Version}.\n"]
  security_config : model_package_security_config option;
      [@ocaml.doc "The KMS Key ID ([KMSKeyId]) used for encryption of model package information.\n"]
  source_uri : model_package_source_uri option;
      [@ocaml.doc
        "The URI of the source for the model package. If you want to clone a model package, set it \
         to the model package Amazon Resource Name (ARN). If you want to register a model, set it \
         to the model ARN.\n"]
  skip_model_validation : skip_model_validation option;
      [@ocaml.doc "Indicates if you want to skip model validation.\n"]
  additional_inference_specifications : additional_inference_specifications option;
      [@ocaml.doc
        "An array of additional Inference Specification objects. Each additional Inference \
         Specification specifies artifacts based on this model package that can be used on \
         inference endpoints. Generally used with SageMaker Neo to store the compiled artifacts. \n"]
  drift_check_baselines : drift_check_baselines option;
      [@ocaml.doc
        "Represents the drift check baselines that can be used when the model monitor is set using \
         the model package. For more information, see the topic on \
         {{:https://docs.aws.amazon.com/sagemaker/latest/dg/pipelines-quality-clarify-baseline-lifecycle.html#pipelines-quality-clarify-baseline-drift-detection}Drift \
         Detection against Previous Baselines in SageMaker Pipelines} in the {i Amazon SageMaker \
         Developer Guide}. \n"]
  customer_metadata_properties : customer_metadata_map option;
      [@ocaml.doc "The metadata properties associated with the model package versions.\n"]
  sample_payload_url : s3_uri option;
      [@ocaml.doc
        "The Amazon Simple Storage Service (Amazon S3) path where the sample payload is stored. \
         This path must point to a single gzip compressed tar archive (.tar.gz suffix). This \
         archive can hold multiple files that are all equally used in the load test. Each file in \
         the archive must satisfy the size constraints of the \
         {{:https://docs.aws.amazon.com/sagemaker/latest/APIReference/API_runtime_InvokeEndpoint.html#API_runtime_InvokeEndpoint_RequestSyntax}InvokeEndpoint} \
         call.\n"]
  task : string_ option;
      [@ocaml.doc
        "The machine learning task your model package accomplishes. Common machine learning tasks \
         include object detection and image classification. The following tasks are supported by \
         Inference Recommender: [\"IMAGE_CLASSIFICATION\"] | [\"OBJECT_DETECTION\"] | \
         [\"TEXT_GENERATION\"] |[\"IMAGE_SEGMENTATION\"] | [\"FILL_MASK\"] | [\"CLASSIFICATION\"] \
         | [\"REGRESSION\"] | [\"OTHER\"].\n\n\
        \ Specify \"OTHER\" if none of the tasks listed fit your use case.\n\
        \ "]
  domain : string_ option;
      [@ocaml.doc
        "The machine learning domain of your model package and its components. Common machine \
         learning domains include computer vision and natural language processing.\n"]
  client_token : client_token option;
      [@ocaml.doc "A unique token that guarantees that the call to this API is idempotent.\n"]
  model_metrics : model_metrics option;
      [@ocaml.doc "A structure that contains model metrics reports.\n"]
  metadata_properties : metadata_properties option; [@ocaml.doc ""]
  model_approval_status : model_approval_status option;
      [@ocaml.doc
        "Whether the model is approved for deployment.\n\n\
        \ This parameter is optional for versioned models, and does not apply to unversioned models.\n\
        \ \n\
        \  For versioned models, the value of this parameter must be set to [Approved] to deploy \
         the model.\n\
        \  "]
  tags : tag_list option;
      [@ocaml.doc
        "A list of key value pairs associated with the model. For more information, see \
         {{:https://docs.aws.amazon.com/general/latest/gr/aws_tagging.html}Tagging Amazon Web \
         Services resources} in the {i Amazon Web Services General Reference Guide}.\n\n\
        \ If you supply [ModelPackageGroupName], your model package belongs to the model group you \
         specify and uses the tags associated with the model group. In this case, you cannot \
         supply a [tag] argument. \n\
        \ "]
  certify_for_marketplace : certify_for_marketplace option;
      [@ocaml.doc
        "Whether to certify the model package for listing on Amazon Web Services Marketplace.\n\n\
        \ This parameter is optional for unversioned models, and does not apply to versioned models.\n\
        \ "]
  source_algorithm_specification : source_algorithm_specification option;
      [@ocaml.doc "Details about the algorithm that was used to create the model package.\n"]
  validation_specification : model_package_validation_specification option;
      [@ocaml.doc
        "Specifies configurations for one or more transform jobs that SageMaker runs to test the \
         model package.\n"]
  inference_specification : inference_specification option;
      [@ocaml.doc
        "Specifies details about inference jobs that you can run with models based on this model \
         package, including the following information:\n\n\
        \ {ul\n\
        \       {-  The Amazon ECR paths of containers that contain the inference code and model \
         artifacts.\n\
        \           \n\
        \            }\n\
        \       {-  The instance types that the model package supports for transform jobs and \
         real-time endpoints used for inference.\n\
        \           \n\
        \            }\n\
        \       {-  The input and output content formats that the model package supports for \
         inference.\n\
        \           \n\
        \            }\n\
        \       }\n\
        \  "]
  model_package_registration_type : model_package_registration_type option;
      [@ocaml.doc " The package registration type of the model package input. \n"]
  model_package_description : entity_description option;
      [@ocaml.doc "A description of the model package.\n"]
  model_package_group_name : arn_or_name option;
      [@ocaml.doc
        "The name or Amazon Resource Name (ARN) of the model package group that this model version \
         belongs to.\n\n\
        \ This parameter is required for versioned models, and does not apply to unversioned models.\n\
        \ "]
  model_package_name : entity_name option;
      [@ocaml.doc
        "The name of the model package. The name must have 1 to 63 characters. Valid characters \
         are a-z, A-Z, 0-9, and - (hyphen).\n\n\
        \ This parameter is required for unversioned models. It is not applicable to versioned \
         models.\n\
        \ "]
}
