type nonrec create_mlflow_tracking_server_request = {
  s3_bucket_owner_verification : boolean_ option;
      [@ocaml.doc
        "Enable Amazon S3 Ownership checks when interacting with Amazon S3 buckets from a \
         SageMaker Managed MLflow Tracking Server. Defaults to [True] if not provided. \n"]
  s3_bucket_owner_account_id : account_id option;
      [@ocaml.doc
        "Expected Amazon Web Services account ID that owns the Amazon S3 bucket for artifact \
         storage. Defaults to caller's account ID if not provided.\n"]
