        "Tags consisting of key-value pairs used to manage metadata for the tracking server.\n"]
  weekly_maintenance_window_start : weekly_maintenance_window_start option;
      [@ocaml.doc
        "The day and time of the week in Coordinated Universal Time (UTC) 24-hour standard time \
         that weekly maintenance updates are scheduled. For example: TUE:03:30.\n"]
  automatic_model_registration : boolean_ option;
      [@ocaml.doc
        "Whether to enable or disable automatic registration of new MLflow models to the SageMaker \
         Model Registry. To enable automatic model registration, set this value to [True]. To \
         disable automatic model registration, set this value to [False]. If not specified, \
         [AutomaticModelRegistration] defaults to [False].\n"]
  role_arn : role_arn;
      [@ocaml.doc
        "The Amazon Resource Name (ARN) for an IAM role in your account that the MLflow Tracking \
         Server uses to access the artifact store in Amazon S3. The role should have \
         [AmazonS3FullAccess] permissions. For more information on IAM permissions for tracking \
         server creation, see \
         {{:https://docs.aws.amazon.com/sagemaker/latest/dg/mlflow-create-tracking-server-iam.html}Set \
         up IAM permissions for MLflow}.\n"]
  mlflow_version : mlflow_version option;
      [@ocaml.doc
        "The version of MLflow that the tracking server uses. To see which MLflow versions are \
         available to use, see \
         {{:https://docs.aws.amazon.com/sagemaker/latest/dg/mlflow.html#mlflow-create-tracking-server-how-it-works}How \
         it works}.\n"]
  tracking_server_size : tracking_server_size option;
      [@ocaml.doc
        "The size of the tracking server you want to create. You can choose between [\"Small\"], \
         [\"Medium\"], and [\"Large\"]. The default MLflow Tracking Server configuration size is \
         [\"Small\"]. You can choose a size depending on the projected use of the tracking server \
         such as the volume of data logged, number of users, and frequency of use. \n\n\
        \ We recommend using a small tracking server for teams of up to 25 users, a medium \
         tracking server for teams of up to 50 users, and a large tracking server for teams of up \
         to 100 users. \n\
        \ "]
  artifact_store_uri : s3_uri;
      [@ocaml.doc
        "The S3 URI for a general purpose bucket to use as the MLflow Tracking Server artifact \
         store.\n"]
  tracking_server_name : tracking_server_name;
      [@ocaml.doc
        "A unique string identifying the tracking server name. This string is part of the tracking \
         server ARN.\n"]
}
