type nonrec create_labeling_job_request = {
  tags : tag_list option;
      [@ocaml.doc
        "An array of key/value pairs. For more information, see \
         {{:https://docs.aws.amazon.com/awsaccountbilling/latest/aboutv2/cost-alloc-tags.html#allocation-what}Using \
         Cost Allocation Tags} in the {i Amazon Web Services Billing and Cost Management User \
         Guide}.\n"]
  human_task_config : human_task_config;
      [@ocaml.doc
        "Configures the labeling task and how it is presented to workers; including, but not \
         limited to price, keywords, and batch size (task count).\n"]
  labeling_job_algorithms_config : labeling_job_algorithms_config option;
      [@ocaml.doc "Configures the information required to perform automated data labeling.\n"]
  stopping_conditions : labeling_job_stopping_conditions option;
      [@ocaml.doc
        "A set of conditions for stopping the labeling job. If any of the conditions are met, the \
         job is automatically stopped. You can use these conditions to control the cost of data \
         labeling.\n"]
  label_category_config_s3_uri : s3_uri option;
      [@ocaml.doc
        "The S3 URI of the file, referred to as a {i label category configuration file}, that \
         defines the categories used to label the data objects.\n\n\
        \ For 3D point cloud and video frame task types, you can add label category attributes and \
         frame attributes to your label category configuration file. To learn how, see \
         {{:https://docs.aws.amazon.com/sagemaker/latest/dg/sms-point-cloud-label-category-config.html}Create \
         a Labeling Category Configuration File for 3D Point Cloud Labeling Jobs}. \n\
        \ \n\
        \  For named entity recognition jobs, in addition to [\"labels\"], you must provide worker \
         instructions in the label category configuration file using the [\"instructions\"] \
         parameter: [\"instructions\": {\"shortInstruction\":\"<h1>Add header</h1><p>Add \
         Instructions</p>\", \"fullInstruction\":\"<p>Add additional instructions.</p>\"}]. For \
         details and an example, see \
         {{:https://docs.aws.amazon.com/sagemaker/latest/dg/sms-named-entity-recg.html#sms-creating-ner-api}Create \
         a Named Entity Recognition Labeling Job (API) }.\n\
        \  \n\
        \   For all other \
         {{:https://docs.aws.amazon.com/sagemaker/latest/dg/sms-task-types.html}built-in task \
         types} and \
         {{:https://docs.aws.amazon.com/sagemaker/latest/dg/sms-custom-templates.html}custom \
         tasks}, your label category configuration file must be a JSON file in the following \
         format. Identify the labels you want to use by replacing [label_1], \
         [label_2],[...],[label_n] with your label categories.\n\
        \   \n\
        \     [{ ] \n\
        \    \n\
        \      [\"document-version\": \"2018-11-28\",] \n\
        \     \n\
        \       [\"labels\": \\[{\"label\": \"label_1\"},{\"label\": \"label_2\"},...{\"label\": \
         \"label_n\"}\\]] \n\
        \      \n\
        \        [}] \n\
        \       \n\
        \        Note the following about the label category configuration file:\n\
        \        \n\
        \         {ul\n\
        \               {-  For image classification and text classification (single and \
         multi-label) you must specify at least two label categories. For all other task types, \
         the minimum number of label categories required is one. \n\
        \                   \n\
        \                    }\n\
        \               {-  Each label category must be unique, you cannot specify duplicate label \
         categories.\n\
        \                   \n\
        \                    }\n\
        \               {-  If you create a 3D point cloud or video frame adjustment or \
         verification labeling job, you must include [auditLabelAttributeName] in the label \
         category configuration. Use this parameter to enter the \
         {{:https://docs.aws.amazon.com/sagemaker/latest/APIReference/API_CreateLabelingJob.html#sagemaker-CreateLabelingJob-request-LabelAttributeName} \
         [LabelAttributeName] } of the labeling job you want to adjust or verify annotations of.\n\
        \                   \n\
        \                    }\n\
        \               }\n\
        \  "]
  role_arn : role_arn;
      [@ocaml.doc
        "The Amazon Resource Number (ARN) that Amazon SageMaker assumes to perform tasks on your \
         behalf during data labeling. You must grant this role the necessary permissions so that \
         Amazon SageMaker can successfully complete data labeling.\n"]
  output_config : labeling_job_output_config;
      [@ocaml.doc
        "The location of the output data and the Amazon Web Services Key Management Service key ID \
         for the key used to encrypt the output data, if any.\n"]
  input_config : labeling_job_input_config;
      [@ocaml.doc
        "Input data for the labeling job, such as the Amazon S3 location of the data objects and \
         the location of the manifest file that describes the data objects.\n\n\
        \ You must specify at least one of the following: [S3DataSource] or [SnsDataSource]. \n\
        \ \n\
        \  {ul\n\
        \        {-  Use [SnsDataSource] to specify an SNS input topic for a streaming labeling \
         job. If you do not specify and SNS input topic ARN, Ground Truth will create a one-time \
         labeling job that stops after all data objects in the input manifest file have been \
         labeled.\n\
        \            \n\
        \             }\n\
        \        {-  Use [S3DataSource] to specify an input manifest file for both streaming and \
         one-time labeling jobs. Adding an [S3DataSource] is optional if you use [SnsDataSource] \
         to create a streaming labeling job.\n\
        \            \n\
        \             }\n\
        \        }\n\
        \   If you use the Amazon Mechanical Turk workforce, your input data should not include \
         confidential information, personal information or protected health information. Use \
         [ContentClassifiers] to specify that your data is free of personally identifiable \
         information and adult content.\n\
        \   "]
  label_attribute_name : label_attribute_name;
      [@ocaml.doc
        "The attribute name to use for the label in the output manifest file. This is the key for \
         the key/value pair formed with the label that a worker assigns to the object. The \
         [LabelAttributeName] must meet the following requirements.\n\n\
        \ {ul\n\
        \       {-  The name can't end with \"-metadata\". \n\
        \           \n\
        \            }\n\
        \       {-  If you are using one of the \
         {{:https://docs.aws.amazon.com/sagemaker/latest/dg/sms-task-types.html}built-in task \
         types} or one of the following, the attribute name {i must} end with \"-ref\".\n\
        \           \n\
        \            {ul\n\
        \                  {-  Image semantic segmentation ([SemanticSegmentation)] and adjustment \
         ([AdjustmentSemanticSegmentation]) labeling jobs for this task type. One exception is \
         that verification ([VerificationSemanticSegmentation]) {i must not} end with -\"ref\".\n\
        \                      \n\
        \                       }\n\
        \                  {-  Video frame object detection ([VideoObjectDetection]), and \
         adjustment and verification ([AdjustmentVideoObjectDetection]) labeling jobs for this \
         task type.\n\
        \                      \n\
        \                       }\n\
        \                  {-  Video frame object tracking ([VideoObjectTracking]), and adjustment \
         and verification ([AdjustmentVideoObjectTracking]) labeling jobs for this task type.\n\
        \                      \n\
        \                       }\n\
        \                  {-  3D point cloud semantic segmentation \
         ([3DPointCloudSemanticSegmentation]), and adjustment and verification \
         ([Adjustment3DPointCloudSemanticSegmentation]) labeling jobs for this task type. \n\
        \                      \n\
        \                       }\n\
        \                  {-  3D point cloud object tracking ([3DPointCloudObjectTracking]), and \
         adjustment and verification ([Adjustment3DPointCloudObjectTracking]) labeling jobs for \
         this task type. \n\
        \                      \n\
        \                       }\n\
        \                  \n\
        \        }\n\
        \         }\n\
        \       }\n\
        \     \n\
        \   \n\
        \   If you are creating an adjustment or verification labeling job, you must use a {i \
         different} [LabelAttributeName] than the one used in the original labeling job. The \
         original labeling job is the Ground Truth labeling job that produced the labels that you \
         want verified or adjusted. To learn more about adjustment and verification labeling jobs, \
         see {{:https://docs.aws.amazon.com/sagemaker/latest/dg/sms-verification-data.html}Verify \
         and Adjust Labels}.\n\
        \   \n\
        \    "]
  labeling_job_name : labeling_job_name;
      [@ocaml.doc
        "The name of the labeling job. This name is used to identify the job in a list of labeling \
         jobs. Labeling job names must be unique within an Amazon Web Services account and region. \
         [LabelingJobName] is not case sensitive. For example, Example-job and example-job are \
         considered the same labeling job name by Ground Truth.\n"]
}
