type nonrec recommendation_job_output_config = {
  compiled_output_config : recommendation_job_compiled_output_config option;
      [@ocaml.doc "Provides information about the output configuration for the compiled model.\n"]
  kms_key_id : kms_key_id option;
      [@ocaml.doc
        "The Amazon Resource Name (ARN) of a Amazon Web Services Key Management Service (Amazon \
         Web Services KMS) key that Amazon SageMaker uses to encrypt your output artifacts with \
         Amazon S3 server-side encryption. The SageMaker execution role must have \
         [kms:GenerateDataKey] permission.\n\n\
        \ The [KmsKeyId] can be any of the following formats:\n\
        \ \n\
        \  {ul\n\
        \        {-  // KMS Key ID\n\
        \            \n\
        \              [\"1234abcd-12ab-34cd-56ef-1234567890ab\"] \n\
        \             \n\
        \              }\n\
        \        {-  // Amazon Resource Name (ARN) of a KMS Key\n\
        \            \n\
        \              \
         [\"arn:aws:kms:<region>:<account>:key/<key-id-12ab-34cd-56ef-1234567890ab>\"] \n\
        \             \n\
        \              }\n\
        \        {-  // KMS Key Alias\n\
        \            \n\
        \              [\"alias/ExampleAlias\"] \n\
        \             \n\
        \              }\n\
        \        {-  // Amazon Resource Name (ARN) of a KMS Key Alias\n\
        \            \n\
        \              [\"arn:aws:kms:<region>:<account>:alias/<ExampleAlias>\"] \n\
        \             \n\
        \              }\n\
        \        }\n\
        \   For more information about key identifiers, see \
         {{:https://docs.aws.amazon.com/kms/latest/developerguide/concepts.html#key-id-key-id}Key \
         identifiers (KeyID)} in the Amazon Web Services Key Management Service (Amazon Web \
         Services KMS) documentation.\n\
        \   "]
}
[@@ocaml.doc "Provides information about the output configuration for the compiled model.\n"]

type nonrec create_inference_recommendations_job_request = {
  tags : tag_list option;
      [@ocaml.doc
        "The metadata that you apply to Amazon Web Services resources to help you categorize and \
         organize them. Each tag consists of a key and a value, both of which you define. For more \
         information, see \
         {{:https://docs.aws.amazon.com/general/latest/gr/aws_tagging.html}Tagging Amazon Web \
         Services Resources} in the Amazon Web Services General Reference.\n"]
  output_config : recommendation_job_output_config option;
      [@ocaml.doc
        "Provides information about the output artifacts and the KMS key to use for Amazon S3 \
         server-side encryption.\n"]
  stopping_conditions : recommendation_job_stopping_conditions option;
      [@ocaml.doc
        "A set of conditions for stopping a recommendation job. If any of the conditions are met, \
         the job is automatically stopped.\n"]
  job_description : recommendation_job_description option;
      [@ocaml.doc "Description of the recommendation job.\n"]
  input_config : recommendation_job_input_config;
      [@ocaml.doc
        "Provides information about the versioned model package Amazon Resource Name (ARN), the \
         traffic pattern, and endpoint configurations.\n"]
  role_arn : role_arn;
      [@ocaml.doc
        "The Amazon Resource Name (ARN) of an IAM role that enables Amazon SageMaker to perform \
         tasks on your behalf.\n"]
  job_type : recommendation_job_type;
      [@ocaml.doc
        "Defines the type of recommendation job. Specify [Default] to initiate an instance \
         recommendation and [Advanced] to initiate a load test. If left unspecified, Amazon \
         SageMaker Inference Recommender will run an instance recommendation ([DEFAULT]) job.\n"]
  job_name : recommendation_job_name;
      [@ocaml.doc
        "A name for the recommendation job. The name must be unique within the Amazon Web Services \
         Region and within your Amazon Web Services account. The job name is passed down to the \
         resources created by the recommendation job. The names of resources (such as the model, \
         endpoint configuration, endpoint, and compilation) that are prefixed with the job name \
         are truncated at 40 characters.\n"]
}
