type nonrec create_inference_experiment_request = {
  tags : tag_list option;
      [@ocaml.doc
        " Array of key-value pairs. You can use tags to categorize your Amazon Web Services \
         resources in different ways, for example, by purpose, owner, or environment. For more \
         information, see {{:https://docs.aws.amazon.com/ARG/latest/userguide/tagging.html}Tagging \
         your Amazon Web Services Resources}. \n"]
  kms_key : kms_key_id option;
      [@ocaml.doc
        " The Amazon Web Services Key Management Service (Amazon Web Services KMS) key that Amazon \
         SageMaker uses to encrypt data on the storage volume attached to the ML compute instance \
         that hosts the endpoint. The [KmsKey] can be any of the following formats: \n\n\
        \ {ul\n\
        \       {-  KMS key ID\n\
        \           \n\
        \             [\"1234abcd-12ab-34cd-56ef-1234567890ab\"] \n\
        \            \n\
        \             }\n\
        \       {-  Amazon Resource Name (ARN) of a KMS key\n\
        \           \n\
        \             \
         [\"arn:aws:kms:us-west-2:111122223333:key/1234abcd-12ab-34cd-56ef-1234567890ab\"] \n\
        \            \n\
        \             }\n\
        \       {-  KMS key Alias\n\
        \           \n\
        \             [\"alias/ExampleAlias\"] \n\
        \            \n\
        \             }\n\
        \       {-  Amazon Resource Name (ARN) of a KMS key Alias\n\
        \           \n\
        \             [\"arn:aws:kms:us-west-2:111122223333:alias/ExampleAlias\"] \n\
        \            \n\
        \             }\n\
        \       }\n\
        \    If you use a KMS key ID or an alias of your KMS key, the Amazon SageMaker execution \
         role must include permissions to call [kms:Encrypt]. If you don't provide a KMS key ID, \
         Amazon SageMaker uses the default KMS key for Amazon S3 for your role's account. Amazon \
         SageMaker uses server-side encryption with KMS managed keys for [OutputDataConfig]. If \
         you use a bucket policy with an [s3:PutObject] permission that only allows objects with \
         server-side encryption, set the condition key of [s3:x-amz-server-side-encryption] to \
         [\"aws:kms\"]. For more information, see \
         {{:https://docs.aws.amazon.com/AmazonS3/latest/dev/UsingKMSEncryption.html}KMS managed \
         Encryption Keys} in the {i Amazon Simple Storage Service Developer Guide.} \n\
        \   \n\
        \     The KMS key policy must grant permission to the IAM role that you specify in your \
         [CreateEndpoint] and [UpdateEndpoint] requests. For more information, see \
         {{:https://docs.aws.amazon.com/kms/latest/developerguide/key-policies.html}Using Key \
         Policies in Amazon Web Services KMS} in the {i Amazon Web Services Key Management Service \
         Developer Guide}. \n\
        \    "]
  shadow_mode_config : shadow_mode_config;
      [@ocaml.doc
        " The configuration of [ShadowMode] inference experiment type. Use this field to specify a \
         production variant which takes all the inference requests, and a shadow variant to which \
         Amazon SageMaker replicates a percentage of the inference requests. For the shadow \
         variant also specify the percentage of requests that Amazon SageMaker replicates. \n"]
  data_storage_config : inference_experiment_data_storage_config option;
      [@ocaml.doc
        " The Amazon S3 location and configuration for storing inference request and response \
         data. \n\n\
        \  This is an optional parameter that you can use for data capture. For more information, \
         see \
         {{:https://docs.aws.amazon.com/sagemaker/latest/dg/model-monitor-data-capture.html}Capture \
         data}. \n\
        \ "]
  model_variants : model_variant_config_list;
      [@ocaml.doc
        " An array of [ModelVariantConfig] objects. There is one for each variant in the inference \
         experiment. Each [ModelVariantConfig] object in the array describes the infrastructure \
         configuration for the corresponding variant. \n"]
  endpoint_name : endpoint_name;
      [@ocaml.doc
        " The name of the Amazon SageMaker endpoint on which you want to run the inference \
         experiment. \n"]
  role_arn : role_arn;
      [@ocaml.doc
