  role_arn : role_arn option;
      [@ocaml.doc
        "The Amazon Resource Name (ARN) of the IAM execution role used to persist data into the \
         [OfflineStore] if an [OfflineStoreConfig] is provided.\n"]
  throughput_config : throughput_config option; [@ocaml.doc ""]
  offline_store_config : offline_store_config option;
      [@ocaml.doc
        "Use this to configure an [OfflineFeatureStore]. This parameter allows you to specify:\n\n\
        \ {ul\n\
        \       {-  The Amazon Simple Storage Service (Amazon S3) location of an [OfflineStore].\n\
        \           \n\
        \            }\n\
        \       {-  A configuration for an Amazon Web Services Glue or Amazon Web Services Hive \
         data catalog. \n\
        \           \n\
        \            }\n\
        \       {-  An KMS encryption key to encrypt the Amazon S3 location used for \
         [OfflineStore]. If KMS encryption key is not specified, by default we encrypt all data at \
         rest using Amazon Web Services KMS key. By defining your \
         {{:https://docs.aws.amazon.com/AmazonS3/latest/userguide/bucket-key.html}bucket-level \
         key} for SSE, you can reduce Amazon Web Services KMS requests costs by up to 99 percent.\n\
        \           \n\
        \            }\n\
        \       {-  Format for the offline store table. Supported formats are Glue (Default) and \
         {{:https://iceberg.apache.org/}Apache Iceberg}.\n\
        \           \n\
        \            }\n\
        \       }\n\
        \   To learn more about this parameter, see \
         {{:https://docs.aws.amazon.com/sagemaker/latest/APIReference/API_OfflineStoreConfig.html}OfflineStoreConfig}.\n\
        \   "]
  online_store_config : online_store_config option;
      [@ocaml.doc
        "You can turn the [OnlineStore] on or off by specifying [True] for the [EnableOnlineStore] \
         flag in [OnlineStoreConfig].\n\n\
        \ You can also include an Amazon Web Services KMS key ID ([KMSKeyId]) for at-rest \
         encryption of the [OnlineStore].\n\
        \ \n\
        \  The default value is [False].\n\
        \  "]
  feature_definitions : feature_definitions;
      [@ocaml.doc
        "A list of [Feature] names and types. [Name] and [Type] is compulsory per [Feature]. \n\n\
        \ Valid feature [FeatureType]s are [Integral], [Fractional] and [String].\n\
        \ \n\
        \   [FeatureName]s cannot be any of the following: [is_deleted], [write_time], \
         [api_invocation_time] \n\
        \  \n\
        \   You can create up to 2,500 [FeatureDefinition]s per [FeatureGroup].\n\
        \   "]
  event_time_feature_name : feature_name;
      [@ocaml.doc
        "The name of the feature that stores the [EventTime] of a [Record] in a [FeatureGroup].\n\n\
        \ An [EventTime] is a point in time when a new event occurs that corresponds to the \
         creation or update of a [Record] in a [FeatureGroup]. All [Records] in the [FeatureGroup] \
         must have a corresponding [EventTime].\n\
        \ \n\
        \  An [EventTime] can be a [String] or [Fractional]. \n\
        \  \n\
        \   {ul\n\
        \         {-   [Fractional]: [EventTime] feature values must be a Unix timestamp in seconds.\n\
        \             \n\
        \              }\n\
        \         {-   [String]: [EventTime] feature values must be an ISO-8601 string in the \
         format. The following formats are supported [yyyy-MM-dd'T'HH:mm:ssZ] and \
         [yyyy-MM-dd'T'HH:mm:ss.SSSZ] where [yyyy], [MM], and [dd] represent the year, month, and \
         day respectively and [HH], [mm], [ss], and if applicable, [SSS] represent the hour, \
         month, second and milliseconds respsectively. ['T'] and [Z] are constants.\n\
        \             \n\
        \              }\n\
        \         }\n\
        \  "]
  record_identifier_feature_name : feature_name;
      [@ocaml.doc
        "The name of the [Feature] whose value uniquely identifies a [Record] defined in the \
         [FeatureStore]. Only the latest record per identifier value will be stored in the \
         [OnlineStore]. [RecordIdentifierFeatureName] must be one of feature definitions' names.\n\n\
        \ You use the [RecordIdentifierFeatureName] to access data in a [FeatureStore].\n\
        \ \n\
        \  This name:\n\
        \  \n\
        \   {ul\n\
        \         {-  Must start with an alphanumeric character.\n\
        \             \n\
        \              }\n\
        \         {-  Can only contains alphanumeric characters, hyphens, underscores. Spaces are \
         not allowed. \n\
        \             \n\
        \              }\n\
        \         }\n\
        \  "]
  feature_group_name : feature_group_name;
      [@ocaml.doc
        "The name of the [FeatureGroup]. The name must be unique within an Amazon Web Services \
         Region in an Amazon Web Services account.\n\n\
        \ The name:\n\
        \ \n\
        \  {ul\n\
        \        {-  Must start with an alphanumeric character.\n\
        \            \n\
        \             }\n\
        \        {-  Can only include alphanumeric characters, underscores, and hyphens. Spaces \
         are not allowed.\n\
