      [@ocaml.doc
        "Specifies configuration for how an endpoint performs asynchronous inference. This is a \
         required field in order for your Endpoint to be invoked using \
         {{:https://docs.aws.amazon.com/sagemaker/latest/APIReference/API_runtime_InvokeEndpointAsync.html}InvokeEndpointAsync}.\n"]
  kms_key_id : kms_key_id option;
      [@ocaml.doc
        "The Amazon Resource Name (ARN) of a Amazon Web Services Key Management Service key that \
         SageMaker uses to encrypt data on the storage volume attached to the ML compute instance \
         that hosts the endpoint.\n\n\
        \ The KmsKeyId can be any of the following formats: \n\
        \ \n\
        \  {ul\n\
        \        {-  Key ID: [1234abcd-12ab-34cd-56ef-1234567890ab] \n\
        \            \n\
        \             }\n\
        \        {-  Key ARN: \
         [arn:aws:kms:us-west-2:111122223333:key/1234abcd-12ab-34cd-56ef-1234567890ab] \n\
        \            \n\
        \             }\n\
        \        {-  Alias name: [alias/ExampleAlias] \n\
        \            \n\
        \             }\n\
        \        {-  Alias name ARN: [arn:aws:kms:us-west-2:111122223333:alias/ExampleAlias] \n\
        \            \n\
        \             }\n\
        \        }\n\
        \   The KMS key policy must grant permission to the IAM role that you specify in your \
         [CreateEndpoint], [UpdateEndpoint] requests. For more information, refer to the Amazon \
         Web Services Key Management Service \
         section{{:https://docs.aws.amazon.com/kms/latest/developerguide/key-policies.html} Using \
         Key Policies in Amazon Web Services KMS } \n\
        \   \n\
        \     Certain Nitro-based instances include local storage, dependent on the instance type. \
         Local storage volumes are encrypted using a hardware module on the instance. If any of \
         the models that you specify in the [ProductionVariants] parameter use nitro-based \
         instances with local storage, the [KmsKeyId] parameter does not encrypt instance local \
         storage.\n\
        \     \n\
        \      For a list of instance types that support local instance storage, see \
         {{:https://docs.aws.amazon.com/AWSEC2/latest/UserGuide/InstanceStorage.html#instance-store-volumes}Instance \
         Store Volumes}.\n\
        \      \n\
        \       For more information about local instance storage encryption, see \
         {{:https://docs.aws.amazon.com/AWSEC2/latest/UserGuide/ssd-instance-store.html}SSD \
         Instance Store Volumes}.\n\
        \       \n\
        \        "]
