type nonrec create_auto_ml_job_v2_request = {
  auto_ml_compute_config : auto_ml_compute_config option;
      [@ocaml.doc "Specifies the compute configuration for the AutoML job V2.\n"]
  data_split_config : auto_ml_data_split_config option;
      [@ocaml.doc
        "This structure specifies how to split the data into train and validation datasets.\n\n\
        \ The validation and training datasets must contain the same headers. For jobs created by \
         calling [CreateAutoMLJob], the validation dataset must be less than 2 GB in size.\n\
        \ \n\
        \   This attribute must not be set for the time-series forecasting problem type, as \
         Autopilot automatically splits the input dataset into training and validation sets.\n\
        \   \n\
        \    "]
  model_deploy_config : model_deploy_config option;
      [@ocaml.doc
        "Specifies how to generate the endpoint name for an automatic one-click Autopilot model \
         deployment.\n"]
  auto_ml_job_objective : auto_ml_job_objective option;
      [@ocaml.doc
        "Specifies a metric to minimize or maximize as the objective of a job. If not specified, \
         the default objective metric depends on the problem type. For the list of default values \
         per problem type, see \
         {{:https://docs.aws.amazon.com/sagemaker/latest/APIReference/API_AutoMLJobObjective.html}AutoMLJobObjective}.\n\n\
        \  {ul\n\
        \        {-  For tabular problem types: You must either provide both the \
         [AutoMLJobObjective] and indicate the type of supervised learning problem in \
         [AutoMLProblemTypeConfig] ([TabularJobConfig.ProblemType]), or none at all.\n\
        \            \n\
        \             }\n\
        \        {-  For text generation problem types (LLMs fine-tuning): Fine-tuning language \
         models in Autopilot does not require setting the [AutoMLJobObjective] field. Autopilot \
         fine-tunes LLMs without requiring multiple candidates to be trained and evaluated. \
         Instead, using your dataset, Autopilot directly fine-tunes your target model to enhance a \
         default objective metric, the cross-entropy loss. After fine-tuning a language model, you \
         can evaluate the quality of its generated text using different metrics. For a list of the \
         available metrics, see \
         {{:https://docs.aws.amazon.com/sagemaker/latest/dg/autopilot-llms-finetuning-metrics.html}Metrics \
         for fine-tuning LLMs in Autopilot}.\n\
        \            \n\
        \             }\n\
        \        }\n\
        \   "]
  security_config : auto_ml_security_config option;
      [@ocaml.doc "The security configuration for traffic encryption or Amazon VPC settings.\n"]
  tags : tag_list option;
      [@ocaml.doc
        "An array of key-value pairs. You can use tags to categorize your Amazon Web Services \
         resources in different ways, such as by purpose, owner, or environment. For more \
         information, see \
         {{:https://docs.aws.amazon.com/general/latest/gr/aws_tagging.html}Tagging Amazon Web \
         ServicesResources}. Tag keys must be unique per resource.\n"]
  role_arn : role_arn; [@ocaml.doc "The ARN of the role that is used to access the data.\n"]
  auto_ml_problem_type_config : auto_ml_problem_type_config;
      [@ocaml.doc "Defines the configuration settings of one of the supported problem types.\n"]
  output_data_config : auto_ml_output_data_config;
      [@ocaml.doc
        "Provides information about encryption and the Amazon S3 output path needed to store \
         artifacts from an AutoML job.\n"]
  auto_ml_job_input_data_config : auto_ml_job_input_data_config;
      [@ocaml.doc
        "An array of channel objects describing the input data and their location. Each channel is \
         a named input source. Similar to the \
         {{:https://docs.aws.amazon.com/sagemaker/latest/APIReference/API_CreateAutoMLJob.html#sagemaker-CreateAutoMLJob-request-InputDataConfig}InputDataConfig} \
         attribute in the [CreateAutoMLJob] input parameters. The supported formats depend on the \
         problem type:\n\n\
        \ {ul\n\
        \       {-  For tabular problem types: [S3Prefix], [ManifestFile].\n\
        \           \n\
        \            }\n\
        \       {-  For image classification: [S3Prefix], [ManifestFile], [AugmentedManifestFile].\n\
        \           \n\
        \            }\n\
        \       {-  For text classification: [S3Prefix].\n\
        \           \n\
        \            }\n\
        \       {-  For time-series forecasting: [S3Prefix].\n\
        \           \n\
        \            }\n\
        \       {-  For text generation (LLMs fine-tuning): [S3Prefix].\n\
        \           \n\
        \            }\n\
        \       }\n\
        \  "]
  auto_ml_job_name : auto_ml_job_name;
      [@ocaml.doc
        "Identifies an Autopilot job. The name must be unique to your account and is case \
         insensitive.\n"]
}
[@@ocaml.doc ""]

