type nonrec add_association_request = {
  association_type : association_edge_type option;
      [@ocaml.doc
        "The type of association. The following are suggested uses for each type. Amazon SageMaker \
         places no restrictions on their use.\n\n\
        \ {ul\n\
        \       {-  ContributedTo - The source contributed to the destination or had a part in \
         enabling the destination. For example, the training data contributed to the training job.\n\
        \           \n\
        \            }\n\
        \       {-  AssociatedWith - The source is connected to the destination. For example, an \
         approval workflow is associated with a model deployment.\n\
        \           \n\
        \            }\n\
        \       {-  DerivedFrom - The destination is a modification of the source. For example, a \
         digest output of a channel input for a processing job is derived from the original inputs.\n\
        \           \n\
        \            }\n\
        \       {-  Produced - The source generated the destination. For example, a training job \
         produced a model artifact.\n\
        \           \n\
        \            }\n\
        \       }\n\
        \  "]
  destination_arn : association_entity_arn;
      [@ocaml.doc "The Amazon Resource Name (ARN) of the destination.\n"]
  source_arn : association_entity_arn; [@ocaml.doc "The ARN of the source.\n"]
}
